function restoreSession() {
  const s = localStorage.getItem('dnd-session');
  if (!s) return false;
  try {
    const data = JSON.parse(s);
    state.roomPin = data.roomPin;
    state.playerId = data.playerId;
    state.playerName = data.playerName;
    state.isDM = data.isDM;
    state.isSpectator = data.isSpectator || false;
    state.playerPin = data.playerPin || null;
    return true;
  } catch { return false; }
}

function saveSession() {
  localStorage.setItem('dnd-session', JSON.stringify({
    roomPin: state.roomPin,
    playerId: state.playerId,
    playerName: state.playerName,
    isDM: state.isDM,
    isSpectator: state.isSpectator || false,
    playerPin: state.playerPin || null
  }));
}

function clearSession() {
  localStorage.removeItem('dnd-session');
  state.roomPin = null;
  state.playerId = null;
  state.playerName = null;
  state.isDM = false;
  state.isSpectator = false;
}

async function createRoom() {
  const name = $('#dm-name').value.trim();
  if (!name) return showError('Enter your name');
  try {
    const data = await api('/rooms', { method:'POST', body:{ dmName: name } });
    state.roomPin = data.pin;
    state.playerId = data.dmId;
    state.playerName = data.dmName;
    state.isDM = true;
    state.managedPlayers = [];
    saveSession();
    // Show room-created panel with DM PIN
    showRoomCreatedPanel(data.pin);
  } catch (e) { showError(e.message); }
}

function showRoomCreatedPanel(dmPin) {
  $$('.login-panel').forEach(p => p.classList.remove('active'));
  $('#room-created-panel').classList.add('active');
  $('#created-dm-pin').textContent = dmPin;
  state.managedPlayers = [];
  renderManagedPlayerList();
}

async function loginWithPin(pin) {
  if (!pin) return showError('Enter a PIN');
  pin = pin.trim();
  try {
    if (pin.length === 6) {
      // DM login
      const data = await api('/auth/dm', { method:'POST', body:{ pin } });
      state.roomPin = data.roomPin;
      state.playerId = data.dmId;
      state.playerName = data.dmName;
      state.isDM = true;
      state.managedPlayers = data.players || [];
      saveSession();
      enterApp();
    } else if (pin.length === 4) {
      // Player login
      const data = await api('/auth/player', { method:'POST', body:{ pin } });
      state.roomPin = data.roomPin;
      state.playerId = data.playerId;
      state.playerName = data.playerName;
      state.isDM = false;
      state.playerPin = pin;
      saveSession();
      enterApp();
    } else {
      showError('PIN must be 4 digits (player) or 6 digits (DM)');
    }
  } catch (e) { showError(e.message); }
}

// --- Manage Players (DM only) ---

async function addPlayer(name, context) {
  if (!name) return;
  try {
    const player = await api(`/rooms/${state.roomPin}/players`, { method:'POST', body:{ name } });
    if (context === 'login') {
      state.managedPlayers.push(player);
      renderManagedPlayerList();
    } else {
      await loadManagedPlayers();
      renderManagePlayersTab();
    }
    // Notify via WebSocket
    sendWS({ type: 'player-added', data: player });
  } catch (e) { showError(e.message); }
}

async function removePlayer(playerId, context) {
  try {
    await api(`/rooms/${state.roomPin}/players/${playerId}`, { method:'DELETE' });
    if (context === 'login') {
      state.managedPlayers = state.managedPlayers.filter(p => p.id !== playerId);
      renderManagedPlayerList();
    } else {
      await loadManagedPlayers();
      renderManagePlayersTab();
    }
    sendWS({ type: 'player-removed', data: { playerId } });
  } catch (e) { showError(e.message); }
}

async function regenPin(playerId, context) {
  try {
    const updated = await api(`/rooms/${state.roomPin}/players/${playerId}/regen-pin`, { method:'POST' });
    if (context === 'login') {
      const idx = state.managedPlayers.findIndex(p => p.id === playerId);
      if (idx >= 0) state.managedPlayers[idx] = updated;
      renderManagedPlayerList();
    } else {
      await loadManagedPlayers();
      renderManagePlayersTab();
    }
  } catch (e) { showError(e.message); }
}

async function loadManagedPlayers() {
  try {
    state.managedPlayers = await api(`/rooms/${state.roomPin}/players`);
  } catch (e) {
    console.error('Failed to load players:', e);
  }
}

function renderManagedPlayerList() {
  // Used by room-created-panel (login screen)
  const list = $('#player-list');
  const noMsg = $('#no-players-msg');
  const copyAllBtn = $('#copy-all-pins-btn');
  if (!list) return;
  list.innerHTML = '';
  const players = state.managedPlayers || [];
  if (players.length === 0) {
    list.innerHTML = '<p class="muted" id="no-players-msg">No players added yet.</p>';
    if (copyAllBtn) hide(copyAllBtn);
    return;
  }
  if (copyAllBtn) show(copyAllBtn);
  players.forEach(p => {
    const row = document.createElement('div');
    row.className = 'player-row';
    row.innerHTML = `
      <span class="player-row-name">${escapeHtml(p.name)}</span>
      <span class="player-row-pin">${p.pin}</span>
      <button class="btn-copy-sm" title="Copy PIN" data-pin="${p.pin}">📋</button>
      <button class="btn-regen-sm" title="Regenerate PIN" data-id="${p.id}">🔄</button>
      <button class="btn-remove-sm" title="Remove Player" data-id="${p.id}">❌</button>
    `;
    row.querySelector('.btn-copy-sm').addEventListener('click', () => {
      navigator.clipboard.writeText(p.pin).then(() => showToast('PIN copied!')).catch(() => {});
    });
    row.querySelector('.btn-regen-sm').addEventListener('click', () => regenPin(p.id, 'login'));
    row.querySelector('.btn-remove-sm').addEventListener('click', () => removePlayer(p.id, 'login'));
    list.appendChild(row);
  });
}

