function copyAllPins() {
  const players = state.managedPlayers || [];
  if (players.length === 0) return;
  let text = `🐉 D&D Room — DM PIN: ${state.roomPin}\n\nPlayer PINs:\n`;
  players.forEach(p => {
    text += `• ${p.name}: ${p.pin}\n`;
  });
  navigator.clipboard.writeText(text).then(() => showToast('All PINs copied!')).catch(() => showError('Failed to copy'));
}

