// WEBSOCKET
// ============================================================

function connectWS() {
  if (state.ws && state.ws.readyState === WebSocket.OPEN) return;
  if (state.wsReconnectTimer) { clearTimeout(state.wsReconnectTimer); state.wsReconnectTimer = null; }

  const ws = new WebSocket(WS_URL);
  state.ws = ws;

  ws.onopen = () => {
    ws.send(JSON.stringify({
      type: 'join-room',
      roomPin: state.roomPin,
      userId: state.playerId,
      userName: state.playerName,
      isDM: state.isDM,
      isSpectator: state.isSpectator || false
    }));
  };

  ws.onmessage = (evt) => {
    let msg;
    try { msg = JSON.parse(evt.data); } catch { return; }
    handleWSMessage(msg);
  };

  ws.onclose = () => {
    state.wsReconnectTimer = setTimeout(connectWS, 3000);
  };

  ws.onerror = () => { /* onclose will fire */ };
}

function handleWSMessage(msg) {
  switch (msg.type) {
    case 'user-joined': {
      addOnlinePlayer(msg);
      break;
    }
    case 'user-left': {
      removeOnlinePlayer(msg.userId);
      break;
    }
    case 'dice-roll': {
      addRollToHistory(msg.data);
      break;
    }
    case 'initiative-update': {
      state.initiative = msg.data;
      renderInitiative();
      break;
    }
    case 'character_update': {
      // When a player updates their character, DM refreshes party overview
      if (state.isDM) {
        loadPartyOverview();
      }
      break;
    }
    case 'player-added': {
      if (state.isDM) {
        loadManagedPlayers().then(() => renderManagePlayersTab());
      }
      break;
    }
    case 'player-removed': {
      if (state.isDM) {
        loadManagedPlayers().then(() => renderManagePlayersTab());
      }
      break;
    }
    case 'map_update': {
      BattleMap.handleWSMapUpdate(msg.data);
      break;
    }
    case 'token_move': {
      BattleMap.handleWSTokenMove(msg.data);
      break;
    }
    case 'fog_reveal': {
      BattleMap.handleWSFogReveal(msg.data);
      break;
    }
    case 'achievement-unlocked': {
      // Show achievement toast for other players
      if (msg.data && msg.data.playerId !== state.playerId) {
        showAchievementToast(msg.data.achievement, msg.data.playerName);
      }
      break;
    }
    case 'loot-shared': {
      // Show loot notification to players
      if (!state.isDM && msg.data) {
        showLootSharedNotification(msg.data);
      }
      break;
    }
    case 'chat_message': {
      InGameChat.receiveMessage(msg.data);
      break;
    }
    case 'spectator-count': {
      const cEl = $('#spectator-count-val');
      if (cEl) cEl.textContent = msg.count || 0;
      const sEl = $('#sidebar-spectators');
      if (sEl) { if ((msg.count || 0) > 0) show(sEl); else hide(sEl); }
      break;
    }
  }
}

function sendWS(data) {
  if (state.ws && state.ws.readyState === WebSocket.OPEN) {
    state.ws.send(JSON.stringify(data));
  }
}

// ============================================================
// ONLINE PLAYERS
// ============================================================

function addOnlinePlayer(p) {
  if (!state.onlinePlayers.find(x => x.userId === p.userId)) {
    state.onlinePlayers.push(p);
  }
  renderOnlinePlayers();
}

function removeOnlinePlayer(userId) {
  state.onlinePlayers = state.onlinePlayers.filter(p => p.userId !== userId);
  renderOnlinePlayers();
}

function renderOnlinePlayers() {
  const ul = $('#online-players');
  ul.innerHTML = '';
  // Always show self
  const all = [...state.onlinePlayers];
  if (!all.find(p => p.userId === state.playerId)) {
    all.unshift({ userId: state.playerId, userName: state.playerName, isDM: state.isDM });
  }
  all.forEach(p => {
    const li = document.createElement('li');
    li.innerHTML = `<span class="player-dot ${p.isDM?'dm':'player'}"></span> ${escapeHtml(p.userName)} ${p.isDM ? '<span class="role-badge dm">DM</span>' : ''}`;
    ul.appendChild(li);
  });
}

function escapeHtml(s) {
  const div = document.createElement('div');
  div.textContent = s;
  return div.innerHTML;
}

