// ROOM DATA
// ============================================================

async function loadRoomData() {
  try {
    const room = await api(`/rooms/${state.roomPin}`);
    // Populate online players from room
    state.onlinePlayers = (room.players || []).map(p => ({
      userId: p.id, userName: p.name, isDM: p.isDM
    }));
    renderOnlinePlayers();

    // Load initiative
    if (room.initiative) {
      state.initiative = room.initiative;
      renderInitiative();
    }

    // Load roll history
    state.rollHistory = room.rollHistory || [];
    renderRollHistory();

    // Load notes
    if (room.sessionNotes) {
      $('#session-notes').value = room.sessionNotes;
    }
    if (room.summaries && room.summaries.length) {
      renderSummaries(room.summaries);
    }
  } catch (e) {
    console.error('Failed to load room data:', e);
  }
}

