};

let _previousTab = null;

function switchTab(tab) {
  // Deactivate previous tab
  if (_previousTab === 'map') BattleMap.deactivate();

  // Update nav buttons
  $$('.nav-btn').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.tab === tab);
  });
  // Update content panels
  $$('.tab-content').forEach(panel => {
    panel.classList.toggle('active', panel.id === `tab-${tab}`);
  });
  // Update mobile header title
  const titleEl = $('#mobile-page-title');
  if (titleEl) titleEl.textContent = TAB_TITLES[tab] || 'Paul Simulator';
  localStorage.setItem('dnd-lastTab', tab);

  // Activate new tab
  if (tab === 'map') BattleMap.activate();

  _previousTab = tab;
}

