function renderPartyGrid(chars) {
  const grid = $('#party-grid');
  if (!chars || chars.length === 0) {
    grid.innerHTML = '<div class="party-empty">No players have created characters yet. Share the PIN and wait for your party!</div>';
    return;
  }

  grid.innerHTML = '';
  chars.forEach(c => {
    const cls = CLASSES.find(cl => cl.name === c.className);
    const species = SPECIES.find(s => s.name === c.species);

    // Calculate derived stats
    const level = c.level || 1;
    const pb = profBonus(level);
    const conScore = c.abilityScores?.CON || 10;
    const dexScore = c.abilityScores?.DEX || 10;
    const conMod = mod(conScore);
    const dexMod = mod(dexScore);

    let maxHP = 10;
    if (cls) {
      const hitDieMax = parseInt(cls.hitDie.replace('d', ''));
      maxHP = hitDieMax + conMod;
      if (level > 1) {
        maxHP += (level - 1) * (Math.floor(hitDieMax / 2) + 1 + conMod);
      }
      if (c.species === 'Dwarf') maxHP += level;
    }
    if (maxHP < 1) maxHP = 1;

    const currentHP = c.currentHP !== undefined ? c.currentHP : maxHP;
    const ac = 10 + dexMod;
    const hpPct = Math.max(0, Math.min(100, (currentHP / maxHP) * 100));
    const hpColor = hpPct > 50 ? '#4caf50' : hpPct > 25 ? '#ff9800' : '#f44336';

    const card = document.createElement('div');
    card.className = 'party-card';
    const avatarHtml = c.avatar
      ? `<div class="party-avatar"><img src="${c.avatar}" alt="Avatar"></div>`
      : `<div class="party-avatar"><span class="avatar-placeholder">🧙</span></div>`;
    card.innerHTML = `
      <div class="party-card-header">
        ${avatarHtml}
        <div style="flex:1">
          <span class="party-char-name">${escapeHtml(c.name || 'Unnamed')}</span>
          <span class="party-player-name">${escapeHtml(c.playerName || 'Unknown')}</span>
        </div>
      </div>
      <div class="party-card-info">
        <span class="party-info-tag">${escapeHtml(c.species || '?')}</span>
        <span class="party-info-tag">${escapeHtml(c.className || '?')}</span>
        <span class="party-info-tag">Lv.${level}</span>
      </div>
      <div class="party-card-stats">
        <div class="party-stat">
          <span class="party-stat-label">HP</span>
          <div class="party-hp-bar-wrap">
            <div class="party-hp-bar" style="width:${hpPct}%; background:${hpColor}"></div>
          </div>
          <span class="party-stat-value">${currentHP}/${maxHP}</span>
        </div>
        <div class="party-stat-row">
          <div class="party-stat-box"><span class="party-stat-label">AC</span><span class="party-stat-value">${ac}</span></div>
          <div class="party-stat-box"><span class="party-stat-label">STR</span><span class="party-stat-value">${c.abilityScores?.STR || 10}</span></div>
          <div class="party-stat-box"><span class="party-stat-label">DEX</span><span class="party-stat-value">${c.abilityScores?.DEX || 10}</span></div>
          <div class="party-stat-box"><span class="party-stat-label">CON</span><span class="party-stat-value">${c.abilityScores?.CON || 10}</span></div>
          <div class="party-stat-box"><span class="party-stat-label">INT</span><span class="party-stat-value">${c.abilityScores?.INT || 10}</span></div>
          <div class="party-stat-box"><span class="party-stat-label">WIS</span><span class="party-stat-value">${c.abilityScores?.WIS || 10}</span></div>
          <div class="party-stat-box"><span class="party-stat-label">CHA</span><span class="party-stat-value">${c.abilityScores?.CHA || 10}</span></div>
        </div>
      </div>
      <button class="btn-sm party-view-btn" data-id="${c.id}">📋 View Details</button>
    `;
    grid.appendChild(card);
  });

  // Attach click handlers for "View Details" buttons
  grid.querySelectorAll('.party-view-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      showPartyCharacterDetail(btn.dataset.id);
    });
  });
}

async function showPartyCharacterDetail(charId) {
  try {
    const c = await api(`/characters/${charId}`);
    const cls = CLASSES.find(cl => cl.name === c.className);
    const species = SPECIES.find(s => s.name === c.species);
    const bg = BACKGROUNDS.find(b => b.name === c.background);
    const level = c.level || 1;
    const pb = profBonus(level);

    // Calculate derived stats
    const totals = {};
    ABILITIES.forEach(ab => {
      totals[ab] = c.abilityScores?.[ab] || 10;
    });
    const conMod = mod(totals.CON);
    const dexMod = mod(totals.DEX);

    let maxHP = 10;
    if (cls) {
      const hitDieMax = parseInt(cls.hitDie.replace('d', ''));
      maxHP = hitDieMax + conMod;
      if (level > 1) maxHP += (level - 1) * (Math.floor(hitDieMax / 2) + 1 + conMod);
      if (c.species === 'Dwarf') maxHP += level;
    }
    if (maxHP < 1) maxHP = 1;
    const currentHP = c.currentHP !== undefined ? c.currentHP : maxHP;
    const ac = 10 + dexMod;

    let html = `
      <div class="detail-section">
        <div class="detail-basic">
          <h2>${escapeHtml(c.name)}</h2>
          <p>Level ${level} ${escapeHtml(c.species || '?')} ${escapeHtml(c.className || '?')} — ${escapeHtml(c.background || 'No background')}</p>
          <p class="muted">Player: ${escapeHtml(c.playerName || 'Unknown')}</p>
        </div>
      </div>
      <div class="detail-section">
        <h3>Combat Stats</h3>
        <div class="detail-combat-stats">
          <div class="detail-stat-box"><span class="label">HP</span><span class="value">${currentHP}/${maxHP}</span></div>
          <div class="detail-stat-box"><span class="label">AC</span><span class="value">${ac}</span></div>
          <div class="detail-stat-box"><span class="label">Hit Die</span><span class="value">${cls?.hitDie || '—'}</span></div>
          <div class="detail-stat-box"><span class="label">Prof</span><span class="value">+${pb}</span></div>
          <div class="detail-stat-box"><span class="label">Init</span><span class="value">${modStr(totals.DEX)}</span></div>
          <div class="detail-stat-box"><span class="label">Speed</span><span class="value">${species?.speed || 30}</span></div>
        </div>
      </div>
      <div class="detail-section">
        <h3>Ability Scores</h3>
        <div class="detail-abilities">
    `;
    ABILITIES.forEach(ab => {
      html += `<div class="detail-ability"><span class="ab-name">${ab}</span><span class="ab-score">${totals[ab]}</span><span class="ab-mod">${modStr(totals[ab])}</span></div>`;
    });
    html += `</div></div>`;

    // Saving throws
    const profSaves = new Set(c.proficientSaves || []);
    html += `<div class="detail-section"><h3>Saving Throws</h3><div class="detail-saves">`;
    ABILITIES.forEach(ab => {
      const m = mod(totals[ab]);
      const prof = profSaves.has(ab) ? pb : 0;
      const total = m + prof;
      const check = profSaves.has(ab) ? '✓' : '';
      html += `<span class="detail-save">${check} ${ab}: ${total >= 0 ? '+' : ''}${total}</span>`;
    });
    html += `</div></div>`;

    // Skills
    const profSkills = new Set(c.proficientSkills || []);
    html += `<div class="detail-section"><h3>Skills</h3><div class="detail-skills">`;
    SKILLS.forEach(sk => {
      const m = mod(totals[sk.ability]);
      const prof = profSkills.has(sk.name) ? pb : 0;
      const total = m + prof;
      if (profSkills.has(sk.name)) {
        html += `<span class="detail-skill prof">✓ ${sk.name}: ${total >= 0 ? '+' : ''}${total}</span>`;
      }
    });
    // If no proficient skills
    if (profSkills.size === 0) html += `<span class="muted">No proficiencies</span>`;
    html += `</div></div>`;

    // Prepared spells
    if (c.preparedSpells && c.preparedSpells.length > 0) {
      html += `<div class="detail-section"><h3>Prepared Spells</h3><div class="detail-spells">`;
      c.preparedSpells.forEach(sp => {
        html += `<span class="detail-spell-tag">${escapeHtml(sp)}</span>`;
      });
      html += `</div></div>`;
    }

    // Notes
    if (c.notes) {
      html += `<div class="detail-section"><h3>Notes</h3><div class="detail-notes">${escapeHtml(c.notes).replace(/\n/g, '<br>')}</div></div>`;
    }

    $('#party-detail-title').textContent = `${c.name} — Character Details`;
    $('#party-detail-content').innerHTML = html;
    show('#party-detail-modal');
  } catch (e) {
    console.error('Load character detail failed:', e);
  }
}

