function initLoginTabs() {
  // PIN input — auto-detect player vs DM
  const pinInput = $('#login-pin');
  const pinHint = $('#pin-hint');
  if (pinInput) {
    pinInput.addEventListener('input', () => {
      const val = pinInput.value.replace(/\D/g, '');
      pinInput.value = val;
      if (val.length === 4) {
        pinHint.textContent = '🎮 Player login';
        pinHint.style.color = '#4caf50';
      } else if (val.length === 6) {
        pinHint.textContent = '🏰 DM login';
        pinHint.style.color = '#d4af37';
      } else if (val.length > 0) {
        pinHint.textContent = `${val.length} digit${val.length>1?'s':''} — need 4 (player) or 6 (DM)`;
        pinHint.style.color = '#888';
      } else {
        pinHint.textContent = '';
      }
    });
    pinInput.addEventListener('keydown', e => {
      if (e.key === 'Enter') loginWithPin(pinInput.value);
    });
  }

  // Enter game button
  $('#enter-game-btn')?.addEventListener('click', () => loginWithPin($('#login-pin').value));

  // Show create panel
  $('#show-create-btn')?.addEventListener('click', () => {
    $$('.login-panel').forEach(p => p.classList.remove('active'));
    $('#create-panel').classList.add('active');
  });

  // Back to login
  $('#back-to-login-btn')?.addEventListener('click', () => {
    $$('.login-panel').forEach(p => p.classList.remove('active'));
    $('#pin-login-panel').classList.add('active');
  });

  // Create room
  $('#create-room-btn')?.addEventListener('click', createRoom);
  $('#dm-name')?.addEventListener('keydown', e => { if (e.key === 'Enter') createRoom(); });

  // Copy DM PIN (room-created panel)
  $('#copy-dm-pin-btn')?.addEventListener('click', () => {
    const pin = $('#created-dm-pin').textContent;
    navigator.clipboard.writeText(pin).then(() => showToast('DM PIN copied!')).catch(() => {});
  });

  // Add player (room-created panel)
  $('#add-player-btn')?.addEventListener('click', () => {
    const name = $('#new-player-name').value.trim();
    if (!name) return;
    addPlayer(name, 'login');
    $('#new-player-name').value = '';
  });
  $('#new-player-name')?.addEventListener('keydown', e => {
    if (e.key === 'Enter') {
      const name = $('#new-player-name').value.trim();
      if (!name) return;
      addPlayer(name, 'login');
      $('#new-player-name').value = '';
    }
  });

  // Copy all PINs (room-created panel)
  $('#copy-all-pins-btn')?.addEventListener('click', copyAllPins);

  // Enter as DM button (room-created panel → main app)
  $('#enter-as-dm-btn')?.addEventListener('click', () => enterApp());

  // Leave room
  $('#leave-room-btn')?.addEventListener('click', leaveRoom);
}

