// For CR 11-20, scale from CR 10
function getNPCPreset(cr) {
  if (NPC_CR_PRESETS[cr]) return { ...NPC_CR_PRESETS[cr], actions: NPC_CR_PRESETS[cr].actions.map(a=>({...a})) };
  const n = parseInt(cr);
  if (n >= 11 && n <= 20) {
    const base = NPC_CR_PRESETS['10'];
    const scale = 1 + (n - 10) * 0.12;
    return {
      hp: Math.round(base.hp * scale), ac: Math.min(20, base.ac + Math.floor((n-10)/3)),
      str: Math.min(24, base.str + Math.floor((n-10)/2)), dex: Math.min(20, base.dex + Math.floor((n-10)/3)),
      con: Math.min(22, base.con + Math.floor((n-10)/2)), int: Math.min(20, base.int + Math.floor((n-10)/4)),
      wis: Math.min(20, base.wis + Math.floor((n-10)/3)), cha: Math.min(20, base.cha + Math.floor((n-10)/3)),
      speed: '30 ft',
      actions: base.actions.map(a=>({...a}))
    };
  }
  return NPC_CR_PRESETS['1'];
}

async function loadNPCs() {
