function renderNPCList() {
  const search = ($('#npc-search')?.value || '').toLowerCase();
  const tagFilter = ($('#npc-tag-filter')?.value || '').toLowerCase().trim();
  const list = $('#npc-list');

  let filtered = (state.npcs || []).filter(n => !n.isMonster);
  if (search) filtered = filtered.filter(n => (n.name || '').toLowerCase().includes(search) || (n.title || '').toLowerCase().includes(search));
  if (tagFilter) filtered = filtered.filter(n => (n.tags || []).some(t => t.toLowerCase().includes(tagFilter)));

  if (!filtered.length) {
    list.innerHTML = '<div class="npc-empty">No NPCs found. Use Quick Create or AI Generate to get started!</div>';
    return;
  }

  list.innerHTML = '';
  filtered.forEach(npc => {
    const card = document.createElement('div');
    card.className = 'npc-card';
    card.innerHTML = `
      <div class="npc-card-header">
        <span class="npc-card-name">${escapeHtml(npc.name)}</span>
        <span class="npc-card-cr">CR ${escapeHtml(String(npc.cr || '?'))}</span>
      </div>
      <div class="npc-card-title">${escapeHtml(npc.title || npc.race || '')}</div>
      <div class="npc-card-stats">
        <span class="npc-stat">❤️ ${npc.hp || '?'}</span>
        <span class="npc-stat">🛡️ ${npc.ac || '?'}</span>
        <span class="npc-stat">${escapeHtml(npc.alignment || '')}</span>
      </div>
      ${(npc.tags && npc.tags.length) ? `<div class="npc-card-tags">${npc.tags.map(t => `<span class="npc-tag">${escapeHtml(t)}</span>`).join('')}</div>` : ''}
      <button class="btn-sm btn-gold npc-combat-btn" data-id="${npc.id}">⚔️ Add to Combat</button>
    `;
    card.addEventListener('click', (e) => {
      if (e.target.classList.contains('npc-combat-btn') || e.target.closest('.npc-combat-btn')) return;
      showNPCDetail(npc);
    });
    card.querySelector('.npc-combat-btn').addEventListener('click', (e) => {
      e.stopPropagation();
      addCreatureToCombat(npc);
    });
    list.appendChild(card);
  });
}

function showNPCDetail(npc) {
