function buildStatBlock(creature, type) {
  const isNPC = type === 'npc';
  const accentClass = isNPC ? 'stat-block-npc' : 'stat-block-monster';
  let html = `<div class="stat-block ${accentClass}">`;
  html += `<div class="stat-block-header">
    <h2>${escapeHtml(creature.name)}</h2>
    <p class="stat-block-subtitle">${escapeHtml(creature.size || 'Medium')} ${escapeHtml(creature.type || creature.race || '')}${creature.alignment ? ', ' + escapeHtml(creature.alignment) : ''}</p>
  </div>`;
  html += `<div class="stat-block-divider"></div>`;
  html += `<div class="stat-block-props">
    <p><strong>Armor Class</strong> ${creature.ac || 10}</p>
    <p><strong>Hit Points</strong> ${creature.hp || creature.maxHp || 10}</p>
    <p><strong>Speed</strong> ${escapeHtml(creature.speed || '30 ft')}</p>
  </div>`;
  html += `<div class="stat-block-divider"></div>`;
  html += `<div class="stat-block-abilities">`;
  ['str','dex','con','int','wis','cha'].forEach(ab => {
    const val = creature[ab] || 10;
    const m = Math.floor((val - 10) / 2);
    const ms = m >= 0 ? `+${m}` : `${m}`;
    html += `<div class="stat-block-ability"><span class="ab-label">${ab.toUpperCase()}</span><span class="ab-val">${val} (${ms})</span></div>`;
  });
  html += `</div>`;
  html += `<div class="stat-block-divider"></div>`;

  if (creature.skills && creature.skills.length) {
    html += `<p><strong>Skills</strong> ${creature.skills.map(s => escapeHtml(s)).join(', ')}</p>`;
  }
  if (creature.cr) html += `<p><strong>Challenge</strong> ${escapeHtml(String(creature.cr))}</p>`;

  // Special abilities
  if (creature.specialAbilities && creature.specialAbilities.length) {
    html += `<div class="stat-block-divider"></div>`;
    creature.specialAbilities.forEach(a => {
      html += `<p><strong><em>${escapeHtml(a.name)}.</em></strong> ${escapeHtml(a.desc)}</p>`;
    });
  }

  // Actions
  if (creature.actions && creature.actions.length) {
    html += `<div class="stat-block-divider"></div>`;
    html += `<h3 class="stat-block-section-title">Actions</h3>`;
    creature.actions.forEach(a => {
      html += `<p><strong><em>${escapeHtml(a.name)}.</em></strong> ${escapeHtml(a.desc)}</p>`;
    });
  }

  // NPC-specific roleplay fields
  if (isNPC) {
    const rpFields = [
      { key: 'personality', label: '🎭 Personality' },
      { key: 'motivation', label: '🎯 Motivation' },
      { key: 'backstory', label: '📖 Backstory' },
      { key: 'appearance', label: '👁️ Appearance' },
      { key: 'voiceNotes', label: '🗣️ Voice Notes' },
      { key: 'quirk', label: '✨ Quirk' }
    ];
    const hasRP = rpFields.some(f => creature[f.key]);
    if (hasRP) {
      html += `<div class="stat-block-divider"></div>`;
      html += `<h3 class="stat-block-section-title">Roleplay</h3>`;
      rpFields.forEach(f => {
        if (creature[f.key]) {
          html += `<p><strong>${f.label}:</strong> ${escapeHtml(creature[f.key])}</p>`;
        }
      });
    }
  }

  html += `</div>`;
  return html;
}

