function crToNumber(cr) {
  if (cr === '1/8') return 0.125;
  if (cr === '1/4') return 0.25;
  if (cr === '1/2') return 0.5;
  return parseFloat(cr) || 0;
}

function renderMonsterList() {
  const search = ($('#monster-search')?.value || '').toLowerCase();
  const typeFilter = $('#monster-type-filter')?.value || '';
  const crFilter = $('#monster-cr-filter')?.value || '';
  const sizeFilter = $('#monster-size-filter')?.value || '';
  const sortBy = $('#monster-sort')?.value || 'name';

  const allMonsters = [...state.bestiary, ...state.customMonsters];
  let filtered = allMonsters;

  if (search) filtered = filtered.filter(m => m.name.toLowerCase().includes(search));
  if (typeFilter) filtered = filtered.filter(m => (m.type || '').toLowerCase() === typeFilter.toLowerCase());
  if (sizeFilter) filtered = filtered.filter(m => (m.size || '') === sizeFilter);
  if (crFilter) {
    filtered = filtered.filter(m => {
      const n = crToNumber(m.cr);
      switch (crFilter) {
        case '0-1': return n <= 1;
        case '2-4': return n >= 2 && n <= 4;
        case '5-10': return n >= 5 && n <= 10;
        case '11-16': return n >= 11 && n <= 16;
        case '17+': return n >= 17;
        default: return true;
      }
    });
  }

  // Sort
  filtered.sort((a, b) => {
    if (sortBy === 'cr') return crToNumber(a.cr) - crToNumber(b.cr);
    if (sortBy === 'hp') return (b.hp || 0) - (a.hp || 0);
    return a.name.localeCompare(b.name);
  });

  const list = $('#monster-list');
  if (!filtered.length) {
    list.innerHTML = '<div class="monster-empty">No monsters match your filters.</div>';
    return;
  }

  list.innerHTML = '';
  filtered.forEach(m => {
    const card = document.createElement('div');
    card.className = 'monster-card';
    if (m.isCustom) card.classList.add('monster-custom');
    card.innerHTML = `
      <div class="monster-card-header">
        <span class="monster-card-name">${escapeHtml(m.name)}</span>
        <span class="monster-card-cr">CR ${escapeHtml(String(m.cr))}</span>
      </div>
      <div class="monster-card-meta">
        <span class="monster-type-badge">${escapeHtml(m.type || '?')}</span>
        <span class="monster-size-badge">${escapeHtml(m.size || '?')}</span>
      </div>
      <div class="monster-card-stats">
        <span class="monster-stat">❤️ ${m.hp}</span>
        <span class="monster-stat">🛡️ ${m.ac}</span>
        <span class="monster-stat">🏃 ${escapeHtml(String(m.speed || '30 ft').split(',')[0])}</span>
      </div>
      <button class="btn-sm btn-gold monster-combat-btn" data-name="${escapeHtml(m.name)}">⚔️ Add to Combat</button>
    `;
    card.addEventListener('click', (e) => {
      if (e.target.classList.contains('monster-combat-btn') || e.target.closest('.monster-combat-btn')) return;
      showMonsterDetail(m);
    });
    card.querySelector('.monster-combat-btn').addEventListener('click', (e) => {
      e.stopPropagation();
      addCreatureToCombat(m);
    });
    list.appendChild(card);
  });
}

