function addCreatureToCombat(creature) {
  const dexMod = Math.floor(((creature.dex || 10) - 10) / 2);
  const initRoll = rollDie(20) + dexMod;

  // Auto-name duplicates
  const baseName = creature.name;
  const existing = state.initiative.combatants.filter(c => c.name.startsWith(baseName));
  let displayName = baseName;
  if (existing.length > 0) {
    displayName = `${baseName} #${existing.length + 1}`;
    // Rename first one if needed
    if (existing.length === 1 && existing[0].name === baseName) {
      existing[0].name = `${baseName} #1`;
    }
  }

  const combatant = {
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    name: displayName,
    initiative: initRoll,
    maxHP: creature.hp || creature.maxHp || 10,
    currentHP: creature.hp || creature.maxHp || 10,
    ac: creature.ac || 10,
    type: creature.isMonster !== false ? 'monster' : 'monster', // NPCs show as monster type in initiative
    conditions: [],
    active: false,
    // Store reference for stat block popup
    creatureData: creature
  };

  state.initiative.combatants.push(combatant);
  sortInitiative();
  broadcastInitiative();
  showToast(`⚔️ ${displayName} added (Init: ${initRoll}, HP: ${combatant.maxHP})`);
}

