const AI_CHAR_PRESETS = {
  'random': 'Create a completely random and unique character with a surprising combination of species, class, and backstory. Be creative!',
  'warrior': 'Create a brave warrior character — a fighter, barbarian, or paladin built for melee combat with a heroic backstory',
  'mage': 'Create a powerful spellcaster — a wizard, sorcerer, or warlock with high intelligence or charisma and a mystical backstory',
  'rogue': 'Create a cunning character — a rogue, ranger, or bard who relies on stealth, skill, and charm',
  'tank': 'Create a heavily armored defender — high AC and HP, built to protect the party. Fighter, paladin, or barbarian with focus on Constitution and defensive abilities',
  'healer': 'Create a divine healer — a cleric or druid focused on keeping the party alive, with high Wisdom and supportive abilities'
};

function initAICharGenerator() {
  // Open modal
  $('#ai-gen-char-btn')?.addEventListener('click', () => {
    show('#ai-char-modal');
    $('#ai-char-prompt').focus();
  });

  // Close modal
  $('#ai-char-close-btn')?.addEventListener('click', () => {
    hide('#ai-char-modal');
    resetAICharModal();
  });
  $('#ai-char-cancel-btn')?.addEventListener('click', () => {
    hide('#ai-char-modal');
    resetAICharModal();
  });

  // Generate button
  $('#ai-char-gen-btn')?.addEventListener('click', generateAICharacter);

  // Presets
  $$('.ai-preset-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const presetKey = btn.dataset.preset;
      const presetText = AI_CHAR_PRESETS[presetKey];
      if (presetText) {
        $('#ai-char-prompt').value = presetText;
        // Auto-generate immediately on preset click
        generateAICharacter();
      }
    });
  });

  // Enter key in prompt triggers generate
  $('#ai-char-prompt')?.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      generateAICharacter();
    }
  });

  // Close on backdrop click
  $('#ai-char-modal')?.addEventListener('click', (e) => {
    if (e.target.id === 'ai-char-modal') {
      hide('#ai-char-modal');
      resetAICharModal();
    }
  });
}

function resetAICharModal() {
  const status = $('#ai-char-status');
  if (status) {
    hide(status);
    status.textContent = '';
    status.className = 'ai-status hidden';
  }
  const btn = $('#ai-char-gen-btn');
  if (btn) {
    btn.disabled = false;
    btn.textContent = '✨ Generate Character!';
  }
}

async function generateAICharacter() {
  const prompt = ($('#ai-char-prompt')?.value || '').trim();
  if (!prompt) {
    showToast('Describe your character or pick a preset!', 'error');
    return;
  }

  const level = $('#ai-char-level')?.value || '1';
  const className = $('#ai-char-class')?.value || 'Any';
  const species = $('#ai-char-species')?.value || 'Any';

  const btn = $('#ai-char-gen-btn');
  const status = $('#ai-char-status');

  // Show loading state
  btn.disabled = true;
  btn.textContent = '⏳ Summoning...';
  status.className = 'ai-status';
  status.innerHTML = `
    <div class="ai-char-loading">
      <div class="sparkle-anim">✨</div>
      <div class="loading-text">Summoning your character from the void<span class="loading-dots"></span></div>
    </div>
  `;
  show(status);

  try {
    const result = await api('/characters/generate', {
      method: 'POST',
      body: { prompt, level: parseInt(level), className, species }
    });

    // Close modal
    hide('#ai-char-modal');
    resetAICharModal();

    // Apply generated data to the character sheet
    applyAICharacterToForm(result);

    showToast(`✨ ${result.name} has been summoned! Review and save when ready.`, 'success');
  } catch (e) {
    status.className = 'ai-status ai-error';
    status.innerHTML = `❌ Generation failed: ${e.message}. Try again!`;
    btn.disabled = false;
    btn.textContent = '✨ Generate Character!';
  }
}

function applyAICharacterToForm(data) {
  // First, create a new character (reset the form)
  newCharacter();

  // Small delay to let the form reset, then fill fields
  setTimeout(() => {
    // Name
    const nameEl = $('#char-name');
    if (nameEl) {
      nameEl.value = data.name || '';
      addGlowEffect(nameEl);
    }

    // Level
    const levelEl = $('#char-level');
    if (levelEl) {
      levelEl.value = data.level || 1;
      addGlowEffect(levelEl);
    }

    // Species
    const speciesEl = $('#char-species');
    if (speciesEl) {
      // Try to match the species from AI to our dropdown options
      const speciesName = matchDropdownValue(speciesEl, data.species);
      if (speciesName) {
        speciesEl.value = speciesName;
        addGlowEffect(speciesEl);
      }
    }

    // Class
    const classEl = $('#char-class');
    if (classEl) {
      const classNameVal = matchDropdownValue(classEl, data.className);
      if (classNameVal) {
        classEl.value = classNameVal;
        addGlowEffect(classEl);
      }
    }

    // Background
    const bgEl = $('#char-background');
    if (bgEl) {
      const bgVal = matchDropdownValue(bgEl, data.background);
      if (bgVal) {
        bgEl.value = bgVal;
        addGlowEffect(bgEl);
      }
    }

    // Switch to manual ability entry so we can set exact values
    const methodEl = $('#ability-method');
    if (methodEl) {
      methodEl.value = 'manual';
      onAbilityMethodChange();
    }

    // Ability Scores
    const abilityMap = { str: 'STR', dex: 'DEX', con: 'CON', int: 'INT', wis: 'WIS', cha: 'CHA' };
    Object.entries(abilityMap).forEach(([key, ab]) => {
      const scoreEl = $(`#score-${ab}`);
      if (scoreEl && data[key]) {
        scoreEl.value = data[key];
        state.abilityScores[ab] = data[key];
        addGlowEffect(scoreEl);
      }
    });

    // Proficient Skills
    if (data.proficientSkills && data.proficientSkills.length > 0) {
      state.proficientSkills = new Set(data.proficientSkills);
      $$('.skill-prof').forEach(cb => {
        cb.checked = state.proficientSkills.has(cb.dataset.skill);
        if (cb.checked) {
          addGlowEffect(cb.closest('.skill-row'));
        }
      });
    }

    // Set saving throws based on class (the onClassChange handler does this too, but we
    // want to make sure it happens after we set the class)
    const className = classEl?.value;
    const cls = CLASSES.find(c => c.name === className);
    if (cls) {
      state.proficientSaves.clear();
      cls.saves.forEach(s => state.proficientSaves.add(s));
      $$('.save-prof').forEach(cb => {
        cb.checked = state.proficientSaves.has(cb.dataset.ability);
      });
    }

    // Build notes from backstory, appearance, equipment, features, personality
    let notes = '';
    if (data.appearance) notes += `🎨 APPEARANCE\n${data.appearance}\n\n`;
    if (data.personalityTraits) notes += `🎭 PERSONALITY\n${data.personalityTraits}\n\n`;
    if (data.ideals) notes += `⭐ IDEALS\n${data.ideals}\n\n`;
    if (data.bonds) notes += `🤝 BONDS\n${data.bonds}\n\n`;
    if (data.flaws) notes += `💔 FLAWS\n${data.flaws}\n\n`;
    if (data.backstory) notes += `📖 BACKSTORY\n${data.backstory}\n\n`;
    if (data.equipment) notes += `🎒 EQUIPMENT\n${data.equipment}\n\n`;
    if (data.features && data.features.length > 0) {
      notes += `⚡ FEATURES\n`;
      data.features.forEach(f => {
        notes += `• ${f.name}: ${f.desc}\n`;
      });
      notes += '\n';
    }
    if (data.alignment) notes += `⚖️ ALIGNMENT: ${data.alignment}\n`;

    const notesEl = $('#char-notes');
    if (notesEl) {
      notesEl.value = notes.trim();
      addGlowEffect(notesEl);
    }

    // Current HP
    const hpEl = $('#current-hp');
    if (hpEl) {
      hpEl.dataset.userSet = 'true';
    }

    // Recalculate everything
    recalcAll();

    // Scroll to top of character sheet
    const charSheet = $('#char-sheet');
    if (charSheet) charSheet.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }, 100);
}

function matchDropdownValue(selectEl, value) {
  if (!value || !selectEl) return '';
  // Exact match
  for (const opt of selectEl.options) {
    if (opt.value.toLowerCase() === value.toLowerCase()) return opt.value;
  }
  // Partial match
  for (const opt of selectEl.options) {
    if (opt.value.toLowerCase().includes(value.toLowerCase()) ||
        value.toLowerCase().includes(opt.value.toLowerCase())) {
      return opt.value;
    }
  }
  return '';
}

function addGlowEffect(el) {
  if (!el) return;
  el.classList.add('ai-filled-glow');
  setTimeout(() => el.classList.remove('ai-filled-glow'), 1500);
}

