const WIKI_CATEGORIES = {
  location: { icon: '📍', label: 'Locations', color: '#3B82F6' },
  npc:      { icon: '👤', label: 'NPCs',      color: '#F59E0B' },
  faction:  { icon: '⚔️', label: 'Factions',  color: '#EF4444' },
  item:     { icon: '🗡️', label: 'Items',     color: '#10B981' },
  lore:     { icon: '📜', label: 'Lore',      color: '#8B5CF6' },
  quest:    { icon: '❓', label: 'Quests',    color: '#F97316' },
  other:    { icon: '📄', label: 'Other',     color: '#9CA3AF' }
};

async function loadWikiPages() {
  if (!state.roomPin) return;
  try {
    state.wikiPages = await api(`/rooms/${state.roomPin}/wiki?isDM=${state.isDM}`);
    renderWikiPageList();
    // Show/hide DM actions
    if (state.isDM) {
      const dmActions = $('#wiki-dm-actions');
      if (dmActions) dmActions.style.display = 'flex';
      const viewerDmActions = $('#wiki-viewer-dm-actions');
      if (viewerDmActions) viewerDmActions.style.display = 'flex';
    }
    // Re-select the current page if still in list
    if (state.selectedWikiPageId) {
      const page = state.wikiPages.find(p => p.id === state.selectedWikiPageId);
      if (page) showWikiPage(page);
      else {
        state.selectedWikiPageId = null;
        hideWikiViewer();
      }
    }
  } catch (e) {
    console.error('Load wiki pages failed:', e);
  }
}

function renderWikiPageList() {
  const search = ($('#wiki-search')?.value || '').toLowerCase();
  const catFilter = $('#wiki-category-filter')?.value || '';
  const list = $('#wiki-page-list');

  let filtered = state.wikiPages || [];
  if (search) {
    filtered = filtered.filter(p =>
      p.title.toLowerCase().includes(search) ||
      p.content.toLowerCase().includes(search) ||
      (p.tags || []).some(t => t.toLowerCase().includes(search))
    );
  }
  if (catFilter) {
    filtered = filtered.filter(p => p.category === catFilter);
  }

  if (!filtered.length) {
    list.innerHTML = '<div class="wiki-empty">No wiki pages found.</div>';
    return;
  }

  // Group by category
  const grouped = {};
  const categoryOrder = ['location', 'npc', 'faction', 'item', 'lore', 'quest', 'other'];
  filtered.forEach(p => {
    const cat = p.category || 'other';
    if (!grouped[cat]) grouped[cat] = [];
    grouped[cat].push(p);
  });

  list.innerHTML = '';
  categoryOrder.forEach(cat => {
    if (!grouped[cat]) return;
    const catInfo = WIKI_CATEGORIES[cat] || WIKI_CATEGORIES.other;
    const section = document.createElement('div');
    section.className = 'wiki-category-section';

    // Category header (skip if filtering by category)
    if (!catFilter) {
      const header = document.createElement('div');
      header.className = `wiki-category-header cat-${cat}`;
      header.textContent = `${catInfo.icon} ${catInfo.label}`;
      section.appendChild(header);
    }

    grouped[cat].forEach(page => {
      const item = document.createElement('div');
      item.className = `wiki-page-item${state.selectedWikiPageId === page.id ? ' active' : ''}`;
      const preview = stripMarkdown(page.content).slice(0, 60);
      item.innerHTML = `
        <span class="wiki-page-icon">${catInfo.icon}</span>
        <div class="wiki-page-info">
          <div class="wiki-page-title">${escapeHtml(page.title)}</div>
          <div class="wiki-page-preview">${escapeHtml(preview)}</div>
        </div>
        ${!page.published ? '<span class="wiki-page-draft">DRAFT</span>' : ''}
      `;
      item.addEventListener('click', () => showWikiPage(page));
      section.appendChild(item);
    });

    list.appendChild(section);
  });
}

function stripMarkdown(md) {
  if (!md) return '';
  return md
    .replace(/#{1,6}\s*/g, '')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .replace(/^[-*]\s+/gm, '')
    .replace(/\n+/g, ' ')
    .trim();
}

function renderMarkdown(md) {
  if (!md) return '';
  let html = escapeHtml(md);

  // Headers (must be before other replacements)
  html = html.replace(/^#### (.+)$/gm, '<h4>$1</h4>');
  html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
  html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');

  // Bold and italic
  html = html.replace(/\*\*\*([^*]+)\*\*\*/g, '<strong><em>$1</em></strong>');
  html = html.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
  html = html.replace(/\*([^*]+)\*/g, '<em>$1</em>');

  // Inline code
  html = html.replace(/`([^`]+)`/g, '<code>$1</code>');

  // Blockquotes
  html = html.replace(/^&gt; (.+)$/gm, '<blockquote>$1</blockquote>');

  // Horizontal rules
  html = html.replace(/^---$/gm, '<hr>');

  // Unordered lists
  html = html.replace(/^[-*] (.+)$/gm, '<li>$1</li>');
  html = html.replace(/(<li>.*<\/li>\n?)+/g, (match) => `<ul>${match}</ul>`);

  // Ordered lists
  html = html.replace(/^\d+\. (.+)$/gm, '<li>$1</li>');

  // Paragraphs — wrap standalone text lines
  html = html.replace(/^(?!<[hublop]|<li|<hr|<blockquote)(.+)$/gm, '<p>$1</p>');

  // Clean up empty paragraphs
  html = html.replace(/<p><\/p>/g, '');

  return html;
}

function showWikiPage(page) {
  state.selectedWikiPageId = page.id;

  // Update list selection
  $$('#wiki-page-list .wiki-page-item').forEach(item => {
    item.classList.remove('active');
  });
  // Find and activate the clicked item
  const items = $$('#wiki-page-list .wiki-page-item');
  items.forEach(item => {
    if (item.querySelector('.wiki-page-title')?.textContent === page.title) {
      item.classList.add('active');
    }
  });

  // Show content
  hide('#wiki-viewer-empty');
  show('#wiki-viewer-content');

  const catInfo = WIKI_CATEGORIES[page.category] || WIKI_CATEGORIES.other;

  $('#wiki-view-title').textContent = page.title;

  const catBadge = $('#wiki-view-category');
  catBadge.textContent = `${catInfo.icon} ${page.category}`;
  catBadge.className = `wiki-category-badge cat-${page.category}`;

  const tagsEl = $('#wiki-view-tags');
  tagsEl.innerHTML = (page.tags || []).map(t => `<span class="wiki-tag">${escapeHtml(t)}</span>`).join('');

  // Render markdown content
  const body = $('#wiki-view-body');
  body.innerHTML = renderMarkdown(page.content);

  // Linked pages
  const linkedSection = $('#wiki-linked-pages');
  if (page.linkedPages && page.linkedPages.length > 0) {
    const linkedPagesData = page.linkedPages
      .map(id => state.wikiPages.find(p => p.id === id))
      .filter(Boolean);

    if (linkedPagesData.length > 0) {
      linkedSection.innerHTML = `
        <h3>📎 Linked Pages</h3>
        <div class="wiki-linked-list">
          ${linkedPagesData.map(lp => {
            const lpCat = WIKI_CATEGORIES[lp.category] || WIKI_CATEGORIES.other;
            return `<div class="wiki-linked-item" data-id="${lp.id}"><span class="wiki-linked-icon">${lpCat.icon}</span>${escapeHtml(lp.title)}</div>`;
          }).join('')}
        </div>
      `;
      linkedSection.querySelectorAll('.wiki-linked-item').forEach(el => {
        el.addEventListener('click', () => {
          const linkedPage = state.wikiPages.find(p => p.id === el.dataset.id);
          if (linkedPage) showWikiPage(linkedPage);
        });
      });
      show(linkedSection);
    } else {
      linkedSection.innerHTML = '';
      hide(linkedSection);
    }
  } else {
    linkedSection.innerHTML = '';
    hide(linkedSection);
  }

  // Show DM actions
  if (state.isDM) {
    const viewerDmActions = $('#wiki-viewer-dm-actions');
    if (viewerDmActions) viewerDmActions.style.display = 'flex';
  }
}

function hideWikiViewer() {
  show('#wiki-viewer-empty');
  hide('#wiki-viewer-content');
}

function openWikiCreateModal() {
  state.editingWikiPageId = null;
  $('#wiki-modal-title').textContent = 'Create Wiki Page';
  $('#wiki-edit-title').value = '';
  $('#wiki-edit-category').value = 'location';
  $('#wiki-edit-content').value = '';
  $('#wiki-edit-tags').value = '';
  $('#wiki-edit-published').value = 'true';
  populateWikiLinksDropdown();
  show('#wiki-edit-modal');
}

function openWikiEditModal() {
  const page = state.wikiPages.find(p => p.id === state.selectedWikiPageId);
  if (!page) return;

  state.editingWikiPageId = page.id;
  $('#wiki-modal-title').textContent = 'Edit Wiki Page';
  $('#wiki-edit-title').value = page.title;
  $('#wiki-edit-category').value = page.category || 'other';
  $('#wiki-edit-content').value = page.content || '';
  $('#wiki-edit-tags').value = (page.tags || []).join(', ');
  $('#wiki-edit-published').value = page.published ? 'true' : 'false';
  populateWikiLinksDropdown(page.linkedPages || []);
  show('#wiki-edit-modal');
}

function populateWikiLinksDropdown(selectedIds) {
  const sel = $('#wiki-edit-links');
  sel.innerHTML = '';
  (state.wikiPages || []).forEach(p => {
    if (p.id === state.editingWikiPageId) return; // Don't link to self
    const catInfo = WIKI_CATEGORIES[p.category] || WIKI_CATEGORIES.other;
    const opt = document.createElement('option');
    opt.value = p.id;
    opt.textContent = `${catInfo.icon} ${p.title}`;
    opt.selected = selectedIds && selectedIds.includes(p.id);
    sel.appendChild(opt);
  });
}

async function saveWikiPage() {
  const title = $('#wiki-edit-title').value.trim();
  if (!title) return alert('Enter a page title');

  const category = $('#wiki-edit-category').value;
  const content = $('#wiki-edit-content').value;
  const tags = $('#wiki-edit-tags').value.split(',').map(t => t.trim()).filter(Boolean);
  const published = $('#wiki-edit-published').value === 'true';
  const linkedPages = Array.from($('#wiki-edit-links').selectedOptions).map(o => o.value);

  const pageData = { title, category, content, tags, published, linkedPages, createdBy: 'DM' };

  try {
    let savedPage;
    if (state.editingWikiPageId) {
      // Update
      savedPage = await api(`/rooms/${state.roomPin}/wiki/${state.editingWikiPageId}`, { method: 'PUT', body: pageData });
    } else {
      // Create
      savedPage = await api(`/rooms/${state.roomPin}/wiki`, { method: 'POST', body: pageData });
    }

    hide('#wiki-edit-modal');
    await loadWikiPages();
    showWikiPage(savedPage);
    showToast(`📖 Wiki page "${savedPage.title}" saved!`);
  } catch (e) {
    showToast('❌ Failed: ' + e.message, 'error');
  }
}

async function deleteWikiPage() {
  if (!state.selectedWikiPageId) return;
  const page = state.wikiPages.find(p => p.id === state.selectedWikiPageId);
  if (!page) return;
  if (!confirm(`Delete wiki page "${page.title}"? This cannot be undone.`)) return;

  try {
    await api(`/rooms/${state.roomPin}/wiki/${state.selectedWikiPageId}`, { method: 'DELETE' });
    state.selectedWikiPageId = null;
    hideWikiViewer();
    await loadWikiPages();
    showToast('🗑️ Wiki page deleted');
  } catch (e) {
    showToast('❌ Failed: ' + e.message, 'error');
  }
}

async function aiGenerateWikiPage() {
  const description = $('#wiki-ai-prompt').value.trim();
  if (!description) return alert('Describe what you want to generate');

  const btn = $('#wiki-ai-gen-btn');
  const status = $('#wiki-ai-status');
  btn.disabled = true;
  btn.textContent = '⏳ Generating...';
  status.textContent = '🔮 AI is crafting your wiki page...';
  status.className = 'ai-status';
  show(status);

  try {
    const result = await api('/wiki/generate', { method: 'POST', body: { description, roomPin: state.roomPin } });

    // Close AI modal
    hide('#wiki-ai-modal');
    hide(status);
    btn.disabled = false;
    btn.textContent = '✨ Generate Page';
    $('#wiki-ai-prompt').value = '';

    // Open edit modal with generated content
    state.editingWikiPageId = null;
    $('#wiki-modal-title').textContent = 'Create Wiki Page';
    $('#wiki-edit-title').value = result.title || '';
    $('#wiki-edit-category').value = result.category || 'other';
    $('#wiki-edit-content').value = result.content || '';
    $('#wiki-edit-tags').value = (result.tags || []).join(', ');
    $('#wiki-edit-published').value = 'true';
    populateWikiLinksDropdown();
    show('#wiki-edit-modal');

    showToast('✨ Wiki page generated! Review and save.');
  } catch (e) {
    status.textContent = '❌ ' + e.message;
    status.className = 'ai-status ai-error';
    btn.disabled = false;
    btn.textContent = '✨ Generate Page';
  }
}

function initWiki() {
  // Search & filter
  $('#wiki-search')?.addEventListener('input', renderWikiPageList);
  $('#wiki-category-filter')?.addEventListener('change', renderWikiPageList);

  // DM actions
  $('#wiki-create-btn')?.addEventListener('click', openWikiCreateModal);
  $('#wiki-ai-generate-btn')?.addEventListener('click', () => show('#wiki-ai-modal'));
  $('#wiki-edit-btn')?.addEventListener('click', openWikiEditModal);
  $('#wiki-delete-btn')?.addEventListener('click', deleteWikiPage);

  // Modal controls
  $('#wiki-modal-close-btn')?.addEventListener('click', () => hide('#wiki-edit-modal'));
  $('#wiki-modal-cancel-btn')?.addEventListener('click', () => hide('#wiki-edit-modal'));
  $('#wiki-save-btn')?.addEventListener('click', saveWikiPage);

  // AI modal
  $('#wiki-ai-close-btn')?.addEventListener('click', () => { hide('#wiki-ai-modal'); hide('#wiki-ai-status'); });
  $('#wiki-ai-cancel-btn')?.addEventListener('click', () => { hide('#wiki-ai-modal'); hide('#wiki-ai-status'); });
  $('#wiki-ai-gen-btn')?.addEventListener('click', aiGenerateWikiPage);

  // Close modals on backdrop click
  $('#wiki-edit-modal')?.addEventListener('click', (e) => {
    if (e.target.id === 'wiki-edit-modal') hide('#wiki-edit-modal');
  });
  $('#wiki-ai-modal')?.addEventListener('click', (e) => {
    if (e.target.id === 'wiki-ai-modal') hide('#wiki-ai-modal');
  });
}

