const AiDM = (() => {
  const dmState = {
    characterData: null,
    conversationHistory: [], // {role: 'player'|'dm'|'system', text, roll}
    genre: null,
    location: 'Unknown Location',
    pendingRoll: null, // {type, skill, modifier, dc, description}
    loading: false,
    adventureActive: false
  };

  const MAX_MESSAGES = 50;

  function init() {
    // Solo adventure button on login screen
    $('#solo-adventure-btn')?.addEventListener('click', startSoloMode);

    // New adventure
    $('#ai-dm-new-adventure-btn')?.addEventListener('click', resetAdventure);
