    switchTab('ai-dm');
    loadCharactersForAiDM();
  }

  function activate() {
    show('#nav-ai-dm-btn');
    loadCharactersForAiDM();

    // Check for saved adventure
    const saved = localStorage.getItem('dnd-ai-dm-adventure');
