          // Show load option
          $('#ai-dm-load-btn')?.classList.add('has-save');
        }
      } catch {}
    }
  }

  async function loadCharactersForAiDM() {
    const sel = $('#ai-dm-character-dropdown');
    if (!sel) return;
    sel.innerHTML = '<option value="">— Select Character —</option>';

    try {
      let chars;
      if (state.roomPin === 'SOLO') {
        // Try loading all characters from localStorage or use a generic approach
        chars = [];
        // Try from all rooms
        try {
          const allChars = await api('/characters');
          chars = allChars;
        } catch { chars = []; }
      } else {
        chars = await api(`/characters?roomPin=${state.roomPin}&ownerId=${state.playerId}`);
      }

      chars.forEach(c => {
        const opt = document.createElement('option');
        opt.value = c.id;
        opt.textContent = `${c.name} (Lv.${c.level} ${c.className || '?'})`;
        opt.dataset.charData = JSON.stringify(c);
        sel.appendChild(opt);
      });
    } catch (e) {
      console.error('Failed to load characters for AI DM:', e);
    }
  }

  function onCharacterSelect() {
    const sel = $('#ai-dm-character-dropdown');
    const opt = sel.options[sel.selectedIndex];
    const preview = $('#ai-dm-char-preview');

    if (!opt || !opt.dataset.charData) {
      hide(preview);
      dmState.characterData = null;
      hide('#ai-dm-genre-select');
      return;
    }

    try {
      const c = JSON.parse(opt.dataset.charData);
      dmState.characterData = buildCharDataForAI(c);
      preview.innerHTML = `
        <div class="ai-dm-char-card">
          <strong>${escapeHtml(c.name)}</strong>
          <span>Lv.${c.level} ${escapeHtml(c.species || '?')} ${escapeHtml(c.className || '?')}</span>
          <span>HP: ${c.currentHP || '?'} | AC: ${10 + Math.floor(((c.abilityScores?.DEX || 10) - 10) / 2)}</span>
        </div>
      `;
      show(preview);
      show('#ai-dm-genre-select');
    } catch {
      hide(preview);
    }
  }

  function buildCharDataForAI(c) {
    const cls = CLASSES.find(cl => cl.name === c.className);
    const conScore = c.abilityScores?.CON || 10;
    const dexScore = c.abilityScores?.DEX || 10;
    const conMod = Math.floor((conScore - 10) / 2);
    const dexMod = Math.floor((dexScore - 10) / 2);
    let maxHP = 10;
    if (cls) {
      const hitDieMax = parseInt(cls.hitDie.replace('d', ''));
      maxHP = hitDieMax + conMod;
      if ((c.level || 1) > 1) {
        maxHP += ((c.level || 1) - 1) * (Math.floor(hitDieMax / 2) + 1 + conMod);
      }
    }

    return {
      name: c.name,
      species: c.species,
      className: c.className,
      level: c.level || 1,
      currentHP: c.currentHP || maxHP,
      maxHP: maxHP,
      ac: 10 + dexMod,
      str: c.abilityScores?.STR || 10,
      dex: c.abilityScores?.DEX || 10,
      con: c.abilityScores?.CON || 10,
      int: c.abilityScores?.INT || 10,
      wis: c.abilityScores?.WIS || 10,
      cha: c.abilityScores?.CHA || 10,
      notes: c.notes || ''
    };
  }

  async function startAdventure() {
    if (!dmState.characterData) return;

    dmState.conversationHistory = [];
    dmState.adventureActive = true;
    dmState.pendingRoll = null;

    // Hide setup, show chat
    hide('#ai-dm-char-select');
    hide('#ai-dm-genre-select');
    show('#ai-dm-chat');

    // Clear messages
    $('#ai-dm-messages').innerHTML = '';
    updateMessageCount();

    // Request opening scene from AI
    await sendToAI(null);
  }

  async function sendAction() {
    const input = $('#ai-dm-input');
    const text = input?.value.trim();
    if (!text || dmState.loading) return;

    input.value = '';
    addMessage('player', text);
    hide('#ai-dm-suggestions');

    await sendToAI(text);
  }

  async function sendToAI(playerAction) {
    if (dmState.loading) return;
    dmState.loading = true;

    // Show typing indicator
    const typingEl = addTypingIndicator();

    try {
      // Summarize old messages if over limit
      let history = dmState.conversationHistory;
      if (history.length > MAX_MESSAGES) {
        // Keep first 5 and last 25, summarize the rest
        const old = history.slice(0, history.length - 25);
        const recent = history.slice(-25);
        const summaryText = `[Summary of earlier events: ${old.map(m => m.text).join(' ').slice(0, 500)}...]`;
        history = [{ role: 'system', text: summaryText }, ...recent];
        dmState.conversationHistory = history;
      }

      const response = await api('/ai-dm/chat', {
        method: 'POST',
        body: {
          characterData: dmState.characterData,
          conversationHistory: history,
          playerAction,
          genre: dmState.genre
        }
      });

      // Remove typing indicator
      typingEl?.remove();

      // Add DM message
      const narrative = response.narrative || 'The story continues...';
      addMessage('dm', narrative);

      // Update location
      if (response.location) {
        dmState.location = response.location;
        const locEl = $('#ai-dm-location');
        if (locEl) locEl.textContent = '📍 ' + response.location;
      }

      // Handle roll request
      if (response.rollRequired) {
        dmState.pendingRoll = response.rollRequired;
        showRollPrompt(response.rollRequired);
      } else {
        hide('#ai-dm-roll-prompt');
      }

      // Show suggestions
      if (response.suggestions && response.suggestions.length > 0) {
        showSuggestions(response.suggestions);
      }

      // Auto-save
      autoSaveAdventure();

    } catch (e) {
      typingEl?.remove();
      addMessage('system', `⚠️ AI DM error: ${e.message}. Try again!`);
    } finally {
      dmState.loading = false;
    }
  }

  function addMessage(role, text, rollResult) {
    const container = $('#ai-dm-messages');
    if (!container) return;

    dmState.conversationHistory.push({ role, text, roll: rollResult || null });

    const msgEl = document.createElement('div');
    msgEl.className = `ai-dm-msg ai-dm-msg-${role}`;

    if (role === 'dm') {
      msgEl.innerHTML = `
        <div class="ai-dm-msg-avatar">🐉</div>
        <div class="ai-dm-msg-content ai-dm-narrative">${escapeHtml(text).replace(/\n/g, '<br>')}</div>
      `;
    } else if (role === 'player') {
      msgEl.innerHTML = `
        <div class="ai-dm-msg-content ai-dm-player-msg">${escapeHtml(text)}</div>
        <div class="ai-dm-msg-avatar">⚔️</div>
      `;
    } else if (role === 'system') {
      msgEl.innerHTML = `
        <div class="ai-dm-msg-content ai-dm-system-msg">${escapeHtml(text)}</div>
      `;
    }

    container.appendChild(msgEl);
    container.scrollTop = container.scrollHeight;
    updateMessageCount();
    return msgEl;
  }

  function addTypingIndicator() {
    const container = $('#ai-dm-messages');
    if (!container) return null;

    const el = document.createElement('div');
    el.className = 'ai-dm-msg ai-dm-msg-dm ai-dm-typing';
    el.innerHTML = `
      <div class="ai-dm-msg-avatar">🐉</div>
      <div class="ai-dm-msg-content ai-dm-narrative">
        <div class="typing-dots"><span></span><span></span><span></span></div>
      </div>
    `;
    container.appendChild(el);
    container.scrollTop = container.scrollHeight;
    return el;
  }

  function showRollPrompt(rollData) {
    const descEl = $('#ai-dm-roll-description');
    const dcEl = $('#ai-dm-roll-dc');

    if (descEl) descEl.textContent = rollData.description || `Roll ${rollData.type || 'd20'} + ${rollData.modifier || rollData.skill || 'modifier'}`;
    if (dcEl) dcEl.textContent = rollData.dc ? `DC ${rollData.dc}` : '';

    show('#ai-dm-roll-prompt');
  }

  function performAiDmRoll() {
    if (!dmState.pendingRoll) return;

    const roll = dmState.pendingRoll;
    const d20 = Math.floor(Math.random() * 20) + 1;

    // Try to get modifier from character
    let modValue = 0;
    const modName = (roll.modifier || roll.skill || '').toLowerCase();
    if (dmState.characterData) {
      const abilityMap = {
        'strength': 'str', 'str': 'str',
        'dexterity': 'dex', 'dex': 'dex',
        'constitution': 'con', 'con': 'con',
        'intelligence': 'int', 'int': 'int',
        'wisdom': 'wis', 'wis': 'wis',
        'charisma': 'cha', 'cha': 'cha'
      };
      const abilityKey = abilityMap[modName];
      if (abilityKey && dmState.characterData[abilityKey]) {
        modValue = Math.floor((dmState.characterData[abilityKey] - 10) / 2);
      }
    }

    const total = d20 + modValue;
    const dc = roll.dc || 0;
    const success = dc > 0 ? total >= dc : null;

    const resultText = `🎲 Rolled d20: ${d20} + ${modValue} = ${total}${dc ? ` (DC ${dc}: ${success ? '✅ Success!' : '❌ Failure!'})` : ''}${d20 === 20 ? ' 🌟 NAT 20!' : ''}${d20 === 1 ? ' 💀 NAT 1!' : ''}`;

    addMessage('system', resultText, { d20, modifier: modValue, total, dc, success });

    // Play dice sound
    DiceSound.play();

    // Hide roll prompt
    hide('#ai-dm-roll-prompt');
    dmState.pendingRoll = null;

    // Send roll result to AI
    sendToAI(`[Roll result: d20=${d20}, modifier=${modValue}, total=${total}${dc ? `, DC ${dc}, ${success ? 'SUCCESS' : 'FAILURE'}` : ''}${d20 === 20 ? ', NATURAL 20' : ''}${d20 === 1 ? ', NATURAL 1' : ''}]`);
  }

  function showSuggestions(suggestions) {
    const container = $('#ai-dm-suggestions');
    if (!container || !suggestions.length) return;

    container.innerHTML = '';
    suggestions.forEach(s => {
      const btn = document.createElement('button');
      btn.className = 'ai-dm-suggestion-btn';
      btn.textContent = s;
      btn.addEventListener('click', () => {
        $('#ai-dm-input').value = s;
        hide(container);
        sendAction();
      });
      container.appendChild(btn);
    });
    show(container);
  }

  function updateMessageCount() {
    const el = $('#ai-dm-message-count');
    if (el) {
      const count = dmState.conversationHistory.length;
      el.textContent = `${count}/${MAX_MESSAGES} messages`;
    }
  }

  function saveAdventure() {
    const data = {
      characterData: dmState.characterData,
      conversationHistory: dmState.conversationHistory,
      genre: dmState.genre,
      location: dmState.location,
      savedAt: Date.now()
    };
    localStorage.setItem('dnd-ai-dm-adventure', JSON.stringify(data));
    showToast('💾 Adventure saved!');
  }

  function autoSaveAdventure() {
    const data = {
      characterData: dmState.characterData,
      conversationHistory: dmState.conversationHistory,
      genre: dmState.genre,
      location: dmState.location,
      savedAt: Date.now()
    };
    localStorage.setItem('dnd-ai-dm-adventure', JSON.stringify(data));
  }

  function loadAdventure() {
    const saved = localStorage.getItem('dnd-ai-dm-adventure');
    if (!saved) {
      showToast('No saved adventure found', 'error');
      return;
    }

    try {
      const data = JSON.parse(saved);
      dmState.characterData = data.characterData;
      dmState.conversationHistory = data.conversationHistory || [];
      dmState.genre = data.genre;
      dmState.location = data.location || 'Unknown Location';
      dmState.adventureActive = true;

      // Hide setup, show chat
      hide('#ai-dm-char-select');
      hide('#ai-dm-genre-select');
      show('#ai-dm-chat');

      // Restore location
      const locEl = $('#ai-dm-location');
      if (locEl) locEl.textContent = '📍 ' + dmState.location;

      // Restore messages
      const container = $('#ai-dm-messages');
      container.innerHTML = '';
      dmState.conversationHistory.forEach(m => {
        const msgEl = document.createElement('div');
        msgEl.className = `ai-dm-msg ai-dm-msg-${m.role}`;
        if (m.role === 'dm') {
          msgEl.innerHTML = `<div class="ai-dm-msg-avatar">🐉</div><div class="ai-dm-msg-content ai-dm-narrative">${escapeHtml(m.text).replace(/\n/g, '<br>')}</div>`;
        } else if (m.role === 'player') {
          msgEl.innerHTML = `<div class="ai-dm-msg-content ai-dm-player-msg">${escapeHtml(m.text)}</div><div class="ai-dm-msg-avatar">⚔️</div>`;
        } else {
          msgEl.innerHTML = `<div class="ai-dm-msg-content ai-dm-system-msg">${escapeHtml(m.text)}</div>`;
        }
        container.appendChild(msgEl);
      });
      container.scrollTop = container.scrollHeight;

      updateMessageCount();
      showToast('📂 Adventure loaded!');
    } catch (e) {
      showToast('Failed to load adventure', 'error');
    }
  }

  function resetAdventure() {
    if (dmState.adventureActive && !confirm('Start a new adventure? Current progress will be lost unless saved.')) return;

    dmState.conversationHistory = [];
    dmState.genre = null;
    dmState.location = 'Unknown Location';
    dmState.pendingRoll = null;
    dmState.adventureActive = false;
    dmState.characterData = null;

    show('#ai-dm-char-select');
    hide('#ai-dm-genre-select');
    hide('#ai-dm-chat');
    hide('#ai-dm-roll-prompt');
    hide('#ai-dm-suggestions');

    const locEl = $('#ai-dm-location');
    if (locEl) locEl.textContent = '📍 Unknown Location';
    $('#ai-dm-messages').innerHTML = '';
    $('#ai-dm-character-dropdown').value = '';
    hide('#ai-dm-char-preview');

    loadCharactersForAiDM();
  }

  return { init, activate, startSoloMode };
})();

// ============================================================
// CONDITION & BUFF TRACKER (Enhanced)
// ============================================================

const ConditionTracker = (() => {
  // Standard D&D conditions with emojis
  const STANDARD_CONDITIONS = {
    'Blinded': { icon: '🙈', color: '#6B7280', description: 'Cannot see. Auto-fail ability checks requiring sight. Attacks have disadvantage, attacks against have advantage.' },
    'Charmed': { icon: '💕', color: '#EC4899', description: 'Cannot attack the charmer. Charmer has advantage on social checks.' },
    'Deafened': { icon: '🔇', color: '#6B7280', description: 'Cannot hear. Auto-fail ability checks requiring hearing.' },
    'Exhaustion': { icon: '😩', color: '#F97316', description: 'Penalties scale with level (1-10). Level 10 = death.' },
    'Frightened': { icon: '😱', color: '#A855F7', description: 'Disadvantage on ability checks and attacks while source is in line of sight. Cannot move closer to source.' },
    'Grappled': { icon: '🤼', color: '#F59E0B', description: 'Speed becomes 0. Ends if grappler is incapacitated or forced away.' },
    'Incapacitated': { icon: '💫', color: '#EF4444', description: 'Cannot take actions or reactions.' },
    'Invisible': { icon: '👻', color: '#8B5CF6', description: 'Cannot be seen without special senses. Attacks have advantage, attacks against have disadvantage.' },
    'Paralyzed': { icon: '⚡', color: '#EF4444', description: 'Incapacitated. Auto-fail STR/DEX saves. Attacks have advantage. Melee crits within 5ft.' },

    'Petrified': { icon: '🪨', color: '#9CA3AF', description: 'Turned to stone. Incapacitated. Resistance to all damage. Immune to poison/disease.' },
    'Poisoned': { icon: '🤢', color: '#10B981', description: 'Disadvantage on attack rolls and ability checks.' },
    'Prone': { icon: '🔽', color: '#3B82F6', description: 'Disadvantage on attacks. Melee attacks against have advantage, ranged have disadvantage.' },
    'Restrained': { icon: '⛓️', color: '#F59E0B', description: 'Speed 0. Attacks have disadvantage. Attacks against have advantage. Disadvantage on DEX saves.' },
    'Stunned': { icon: '⭐', color: '#FBBF24', description: 'Incapacitated. Auto-fail STR/DEX saves. Attacks against have advantage.' },
    'Unconscious': { icon: '💤', color: '#EF4444', description: 'Incapacitated. Drop what held, fall prone. Auto-fail STR/DEX saves. Attacks have advantage. Melee crits within 5ft.' }
  };

  // Common buffs/spells with concentration flag
  const COMMON_BUFFS = {
    'Bless': { icon: '✨', color: '#FBBF24', concentration: true, description: '+1d4 to attack rolls and saving throws.' },
    'Shield of Faith': { icon: '🛡️', color: '#3B82F6', concentration: true, description: '+2 to AC.' },
    'Haste': { icon: '⚡', color: '#F59E0B', concentration: true, description: 'Double speed, +2 AC, advantage on DEX saves, extra action.' },
    'Rage': { icon: '🔥', color: '#EF4444', concentration: false, description: 'Bonus melee damage, resistance to physical damage, advantage on STR checks/saves.' },
    'Bardic Inspiration': { icon: '🎵', color: '#A855F7', concentration: false, description: 'Add inspiration die to ability check, attack, or save.' },
    'Hex': { icon: '🔮', color: '#6B21A8', concentration: true, description: '+1d6 necrotic damage. Disadvantage on chosen ability checks.' },
    "Hunter's Mark": { icon: '🎯', color: '#10B981', concentration: true, description: '+1d6 damage to marked target. Advantage on tracking.' },
    'Mage Armor': { icon: '🧿', color: '#3B82F6', concentration: false, description: 'AC becomes 13 + DEX modifier.' },
    'Mirror Image': { icon: '👤', color: '#8B5CF6', concentration: false, description: 'Three illusory duplicates that can absorb attacks.' },
    'Heroism': { icon: '💪', color: '#F59E0B', concentration: true, description: 'Immune to frightened. Gain temp HP each turn.' },
    'Faerie Fire': { icon: '🌟', color: '#A855F7', concentration: true, description: 'Outlined in light. Attacks against have advantage. No benefit from Invisible.' },
    'Spirit Guardians': { icon: '👼', color: '#FBBF24', concentration: true, description: 'Enemies in range take 3d8 damage and have half speed.' }
  };

  const ALL_EFFECTS = { ...STANDARD_CONDITIONS, ...COMMON_BUFFS };

  function getConditionData(name) {
    return ALL_EFFECTS[name] || { icon: '⚙️', color: '#9CA3AF', concentration: false, description: 'Custom effect.' };
  }

  function addConditionToInitiative(combatantId, conditionName, duration, isConcentration, exhaustionLevel) {
    const combatant = state.initiative.combatants.find(c => c.id === combatantId);
    if (!combatant) return;

    if (!combatant.activeConditions) combatant.activeConditions = [];

    // Check concentration conflict
    const condData = getConditionData(conditionName);
    const isConc = isConcentration || condData.concentration || false;

    if (isConc) {
      const existingConc = combatant.activeConditions.find(c => c.isConcentration);
      if (existingConc) {
        if (!confirm(`${combatant.name} is already concentrating on "${existingConc.name}". Adding "${conditionName}" will end it. Continue?`)) {
          return;
        }
        // Remove existing concentration
        combatant.activeConditions = combatant.activeConditions.filter(c => c !== existingConc);
      }
    }

    // Check duplicate
    const existing = combatant.activeConditions.find(c => c.name === conditionName);
    if (existing && conditionName !== 'Exhaustion') {
      showToast(`${combatant.name} already has ${conditionName}`, 'error');
      return;
    }

    combatant.activeConditions.push({
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 4),
      name: conditionName,
      duration: duration || null, // rounds, or null for indefinite
      durationType: duration === -1 ? 'long-rest' : (isConc ? 'concentration' : (duration ? 'rounds' : 'indefinite')),
      isConcentration: isConc,
      exhaustionLevel: conditionName === 'Exhaustion' ? (exhaustionLevel || 1) : null,
      addedRound: state.initiative.currentTurn
    });

    broadcastInitiative();
    showToast(`${getConditionData(conditionName).icon} ${conditionName} added to ${combatant.name}`);
  }

  function removeConditionFromInitiative(combatantId, conditionId) {
    const combatant = state.initiative.combatants.find(c => c.id === combatantId);
    if (!combatant || !combatant.activeConditions) return;
    combatant.activeConditions = combatant.activeConditions.filter(c => c.id !== conditionId);
    broadcastInitiative();
  }

  function decrementDurations() {
    // Called when "Next Turn" is clicked
    state.initiative.combatants.forEach(combatant => {
      if (!combatant.activeConditions) return;

      const toRemove = [];
      combatant.activeConditions.forEach(cond => {
        if (cond.duration && cond.duration > 0 && cond.durationType === 'rounds') {
          cond.duration--;
          if (cond.duration <= 0) {
            toRemove.push(cond.id);
            showToast(`⏰ ${cond.name} expired on ${combatant.name}`);
          }
        }
      });

      if (toRemove.length > 0) {
        combatant.activeConditions = combatant.activeConditions.filter(c => !toRemove.includes(c.id));
      }
    });
  }

  function renderConditionPills(combatant) {
    if (!combatant.activeConditions || combatant.activeConditions.length === 0) return '';

    return combatant.activeConditions.map(cond => {
      const data = getConditionData(cond.name);
      const isExpiringSoon = cond.duration === 1 && cond.durationType === 'rounds';
      const exhaustLevel = cond.name === 'Exhaustion' && cond.exhaustionLevel ? ` ${cond.exhaustionLevel}` : '';
      const durationText = cond.durationType === 'rounds' && cond.duration ? `${cond.duration}r` :
                           cond.durationType === 'concentration' ? 'C' :
                           cond.durationType === 'long-rest' ? 'LR' : '';

      return `<span class="condition-pill ${isExpiringSoon ? 'condition-expiring' : ''} ${cond.isConcentration ? 'condition-concentration' : ''}"
                    style="--pill-color: ${data.color}"
                    data-combatant-id="${combatant.id}"
                    data-condition-id="${cond.id}"
                    data-condition-name="${escapeHtml(cond.name)}"
                    title="${escapeHtml(cond.name)}: ${escapeHtml(data.description)}">
        ${data.icon} ${escapeHtml(cond.name)}${exhaustLevel}${durationText ? ` (${durationText})` : ''}
      </span>`;
    }).join('');
  }

  function buildConditionDropdown(combatantId) {
    const allNames = [...Object.keys(STANDARD_CONDITIONS), '───', ...Object.keys(COMMON_BUFFS)];
    let html = `<select class="enhanced-condition-select" data-combatant-id="${combatantId}">
      <option value="">+ Add Condition/Buff</option>
      <optgroup label="Conditions">
        ${Object.keys(STANDARD_CONDITIONS).map(n => `<option value="${n}">${STANDARD_CONDITIONS[n].icon} ${n}</option>`).join('')}
      </optgroup>
      <optgroup label="Buffs & Spells">
        ${Object.keys(COMMON_BUFFS).map(n => `<option value="${n}">${COMMON_BUFFS[n].icon} ${n}</option>`).join('')}
      </optgroup>
      <optgroup label="Other">
        <option value="__custom__">⚙️ Custom Effect...</option>
      </optgroup>
    </select>`;
    return html;
  }

  function buildDurationInput(combatantId) {
    return `<div class="condition-duration-input hidden" data-combatant-id="${combatantId}">
      <input type="number" class="duration-rounds-input" placeholder="Rounds" min="1" max="100" value="10" style="width:60px">
      <select class="duration-type-select" style="width:auto">
        <option value="rounds">Rounds</option>
        <option value="concentration">Concentration</option>
        <option value="long-rest">Until Long Rest</option>
        <option value="indefinite">Indefinite</option>
      </select>
      <button class="btn-sm btn-gold condition-add-confirm" data-combatant-id="${combatantId}">✓</button>
    </div>`;
  }

  function attachConditionListeners(listEl) {
    // Condition pills click → show detail/remove
    listEl.querySelectorAll('.condition-pill').forEach(pill => {
      pill.addEventListener('click', (e) => {
        e.stopPropagation();
        const combatantId = pill.dataset.combatantId;
        const conditionId = pill.dataset.conditionId;
        const conditionName = pill.dataset.conditionName;

        // Simple toggle remove on click for now
        if (confirm(`Remove ${conditionName}?`)) {
          removeConditionFromInitiative(combatantId, conditionId);
        }
      });
    });

    // Enhanced condition dropdowns
    listEl.querySelectorAll('.enhanced-condition-select').forEach(sel => {
      sel.addEventListener('change', () => {
        const combatantId = sel.dataset.combatantId;
        const value = sel.value;
        if (!value) return;

        if (value === '__custom__') {
          const customName = prompt('Enter custom effect name:');
          if (!customName) { sel.value = ''; return; }
          const customDuration = parseInt(prompt('Duration in rounds (0 for indefinite):', '0')) || 0;
          addConditionToInitiative(combatantId, customName, customDuration || null, false);
          sel.value = '';
          return;
        }

        // Show duration input
        const durationWrap = listEl.querySelector(`.condition-duration-input[data-combatant-id="${combatantId}"]`);
        if (durationWrap) {
          durationWrap.dataset.selectedCondition = value;
          show(durationWrap);
        } else {
          // Fallback: just add with default
          const condData = getConditionData(value);
          addConditionToInitiative(combatantId, value, condData.concentration ? null : 10, condData.concentration);
        }
        sel.value = '';
      });
    });

    // Duration confirm buttons
    listEl.querySelectorAll('.condition-add-confirm').forEach(btn => {
      btn.addEventListener('click', () => {
        const combatantId = btn.dataset.combatantId;
        const durationWrap = btn.closest('.condition-duration-input');
        const condName = durationWrap?.dataset.selectedCondition;
        if (!condName) return;

        const durationType = durationWrap.querySelector('.duration-type-select')?.value || 'rounds';
        const roundsInput = durationWrap.querySelector('.duration-rounds-input');
        let duration = null;

        if (durationType === 'rounds') {
          duration = parseInt(roundsInput?.value) || 10;
        } else if (durationType === 'long-rest') {
          duration = -1;
        }

        const isConc = durationType === 'concentration' || getConditionData(condName).concentration;

        if (condName === 'Exhaustion') {
          const level = parseInt(prompt('Exhaustion level (1-10):', '1')) || 1;
          addConditionToInitiative(combatantId, condName, duration, false, Math.min(10, Math.max(1, level)));
        } else {
          addConditionToInitiative(combatantId, condName, duration, isConc);
        }

        hide(durationWrap);
      });
    });
  }

  return {
    STANDARD_CONDITIONS,
    COMMON_BUFFS,
    ALL_EFFECTS,
    getConditionData,
    addConditionToInitiative,
    removeConditionFromInitiative,
    decrementDurations,
    renderConditionPills,
    buildConditionDropdown,
    buildDurationInput,
    attachConditionListeners
  };
})();

