// Patch renderInitiative to include enhanced conditions
const _origRenderInit2 = renderInitiative;
renderInitiative = function() {
  const list = $('#initiative-list');
  const combatants = state.initiative.combatants;

  if (!combatants.length) {
    list.innerHTML = '<div class="init-empty">No combatants yet. Add some to begin!</div>';
    return;
  }

  list.innerHTML = '';
  combatants.forEach((c, idx) => {
    const card = document.createElement('div');
    card.className = `init-card ${c.active ? 'active-turn' : ''} ${c.type === 'player' ? 'player-card' : 'monster-card'}`;
    const hpPct = Math.max(0, Math.min(100, (c.currentHP / c.maxHP) * 100));
    const hpColor = hpPct > 50 ? '#4caf50' : hpPct > 25 ? '#ff9800' : '#f44336';

    // Build condition pills HTML
    const conditionPillsHTML = ConditionTracker.renderConditionPills(c);
    const conditionDropdownHTML = state.isDM ? ConditionTracker.buildConditionDropdown(c.id) : '';
    const durationInputHTML = state.isDM ? ConditionTracker.buildDurationInput(c.id) : '';

    card.innerHTML = `
      <div class="init-order">${idx + 1}</div>
      <div class="init-info">
        <div class="init-name">${c.avatar ? `<span class="init-avatar"><img src="${c.avatar}" alt=""></span>` : ''}${escapeHtml(c.name)} ${c.active ? '⚔️' : ''}</div>
        <div class="init-roll">Init: ${c.initiative}</div>
        <div class="init-conditions-enhanced">${conditionPillsHTML}</div>
      </div>
      <div class="init-hp">
        <div class="hp-bar-container">
          <div class="hp-bar" style="width:${hpPct}%; background:${hpColor}"></div>
        </div>
        <div class="hp-text">${c.currentHP}/${c.maxHP}</div>
        ${state.isDM ? `
          <div class="hp-controls">
            <button class="hp-btn hp-dmg" data-id="${c.id}" data-dir="-1">−</button>
            <input type="number" class="hp-adj-input" id="hpadj-${c.id}" value="1" min="1" style="width:40px">
            <button class="hp-btn hp-heal" data-id="${c.id}" data-dir="1">+</button>
          </div>
          <div class="init-actions">
            ${conditionDropdownHTML}
            ${durationInputHTML}
            <button class="remove-combatant" data-id="${c.id}">🗑️</button>
          </div>
        ` : ''}
      </div>
    `;
    list.appendChild(card);
  });

  // Attach all event listeners
  // HP buttons
  list.querySelectorAll('.hp-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const id = btn.dataset.id;
      const dir = parseInt(btn.dataset.dir);
      const input = $(`#hpadj-${id}`);
      const amount = parseInt(input?.value) || 1;
      const c = state.initiative.combatants.find(x => x.id === id);
      if (c) {
        c.currentHP = Math.max(0, Math.min(c.maxHP, c.currentHP + dir * amount));
        broadcastInitiative();
      }
    });
  });

  // Remove combatant buttons
  list.querySelectorAll('.remove-combatant').forEach(btn => {
    btn.addEventListener('click', () => {
      const id = btn.dataset.id;
      state.initiative.combatants = state.initiative.combatants.filter(x => x.id !== id);
      if (state.initiative.currentTurn >= state.initiative.combatants.length) {
        state.initiative.currentTurn = 0;
      }
      broadcastInitiative();
    });
  });

  // Condition tracker listeners
  ConditionTracker.attachConditionListeners(list);

  // Stat block popup on creature name click (DM only)
  if (state.isDM) {
    list.querySelectorAll('.init-name').forEach((el, idx) => {
      const c = state.initiative.combatants[idx];
      if (c && c.creatureData) {
        el.style.cursor = 'pointer';
        el.title = 'Click to view stat block';
        el.addEventListener('click', () => {
          const creature = c.creatureData;
          if (creature.isMonster !== false) {
            showMonsterDetail(creature);
          } else {
            showNPCDetail(creature);
          }
        });
      }
    });
  }
};

