function generateLoot(cr, lootType) {
  const crNum = parseInt(cr);
  let currency = {};
  let items = [];

  if (crNum <= 4) {
    if (lootType === 'individual') {
      currency.copper = Math.floor(Math.random() * 30) + 5;
      currency.silver = Math.floor(Math.random() * 20) + 1;
      if (Math.random() > 0.5) currency.gold = Math.floor(Math.random() * 6) + 1;
      if (Math.random() > 0.7) items.push(randomItem('common'));
    } else {
      currency.copper = Math.floor(Math.random() * 600) + 200;
      currency.silver = Math.floor(Math.random() * 300) + 100;
      currency.gold = Math.floor(Math.random() * 50) + 10;
      items.push(randomItem('common'));
      if (Math.random() > 0.5) items.push(randomItem('common'));
      if (Math.random() > 0.7) items.push(randomItem('uncommon'));
    }
  } else if (crNum <= 10) {
    if (lootType === 'individual') {
      currency.silver = Math.floor(Math.random() * 40) + 10;
      currency.gold = Math.floor(Math.random() * 30) + 10;
      if (Math.random() > 0.6) items.push(randomItem('uncommon'));
    } else {
      currency.gold = Math.floor(Math.random() * 500) + 100;
      currency.silver = Math.floor(Math.random() * 200) + 50;
      items.push(randomItem('uncommon'));
      items.push(randomItem('uncommon'));
      if (Math.random() > 0.5) items.push(randomItem('rare'));
    }
  } else if (crNum <= 16) {
    if (lootType === 'individual') {
      currency.gold = Math.floor(Math.random() * 100) + 50;
      currency.platinum = Math.floor(Math.random() * 10) + 1;
      items.push(randomItem('rare'));
    } else {
      currency.gold = Math.floor(Math.random() * 2000) + 500;
      currency.platinum = Math.floor(Math.random() * 100) + 20;
      items.push(randomItem('rare'));
      items.push(randomItem('rare'));
      if (Math.random() > 0.5) items.push(randomItem('very rare'));
    }
  } else {
    if (lootType === 'individual') {
      currency.gold = Math.floor(Math.random() * 200) + 100;
      currency.platinum = Math.floor(Math.random() * 50) + 10;
      items.push(randomItem('very rare'));
    } else {
      currency.platinum = Math.floor(Math.random() * 500) + 100;
      currency.gold = Math.floor(Math.random() * 5000) + 1000;
      items.push(randomItem('very rare'));
      items.push(randomItem('very rare'));
      if (Math.random() > 0.4) items.push(randomItem('legendary'));
    }
  }

  return { currency, items, cr: crNum, type: lootType };
}

function randomItem(rarity) {
  const pool = MAGIC_ITEMS[rarity] || MAGIC_ITEMS.common;
  const item = pool[Math.floor(Math.random() * pool.length)];
  return { ...item, rarity };
}

