const ACHIEVEMENT_DEFS = [
  { id: 'first-blood', name: 'First Blood', icon: '🩸', desc: 'Dealt damage for the first time' },
  { id: 'natural-born', name: 'Natural Born', icon: '⭐', desc: 'Rolled a Natural 20' },
  { id: 'fumble-king', name: 'Fumble King', icon: '💀', desc: 'Rolled a Natural 1' },
  { id: 'dice-addict', name: 'Dice Addict', icon: '🎲', desc: 'Rolled dice 100 times' },
  { id: 'critical-streak', name: 'Critical Streak', icon: '🔥', desc: 'Rolled 2 Nat 20s in a row' },
  { id: 'survivor', name: 'Survivor', icon: '💚', desc: 'Survived a death save' },
  { id: 'big-hitter', name: 'Big Hitter', icon: '💥', desc: 'Dealt 30+ damage in one roll' },
  { id: 'lucky-seven', name: 'Lucky Seven', icon: '🍀', desc: 'Rolled exactly 7 three times' },
  { id: 'centurion', name: 'Centurion', icon: '⚔️', desc: 'Dealt 100 total damage' },
  { id: 'social-butterfly', name: 'Social Butterfly', icon: '🦋', desc: 'Used 5 different dice types in one session' },
];

const achievementState = {
  loaded: false,
  unlocked: [],
  stats: {
    totalRolls: 0,
    totalDamage: 0,
    nat20Count: 0,
    nat1Count: 0,
    lastRollWasNat20: false,
    sevenCount: 0,
    diceTypesUsed: [],
    dealtDamage: false,
  }
};

async function loadAchievements() {
  if (!state.roomPin || !state.playerId || state.isDM) return;
  try {
    const data = await api(`/rooms/${state.roomPin}/achievements/${state.playerId}`);
    achievementState.unlocked = data.unlocked || [];
    achievementState.stats = data.stats || achievementState.stats;
    achievementState.loaded = true;
    renderAchievementGallery();
  } catch (e) {
    console.error('Load achievements failed:', e);
  }
}

async function saveAchievements() {
  if (!state.roomPin || !state.playerId || state.isDM) return;
  try {
    await api(`/rooms/${state.roomPin}/achievements/${state.playerId}`, {
      method: 'POST',
      body: { unlocked: achievementState.unlocked, stats: achievementState.stats }
    });
  } catch (e) {
    console.error('Save achievements failed:', e);
  }
}

function checkAchievements(rollData) {
  if (state.isDM || !achievementState.loaded) return;

  const stats = achievementState.stats;
  const newUnlocks = [];

  // Track total rolls
  stats.totalRolls = (stats.totalRolls || 0) + 1;

  // Track dice types used this session
  if (rollData.sides) {
    if (!stats.diceTypesUsed) stats.diceTypesUsed = [];
    if (!stats.diceTypesUsed.includes(rollData.sides)) {
      stats.diceTypesUsed.push(rollData.sides);
    }
  }

  // Check for nat 20
  const results = rollData.results || [];
  const hasNat20 = results.includes(20) && (rollData.sides === 20 || (rollData.notation && rollData.notation.includes('d20')));
  const hasNat1 = results.includes(1) && (rollData.sides === 20 || (rollData.notation && rollData.notation.includes('d20')));

  // Natural Born — first Nat 20
  if (hasNat20 && !hasAchievement('natural-born')) {
    newUnlocks.push('natural-born');
  }

  // Fumble King — first Nat 1
  if (hasNat1 && !hasAchievement('fumble-king')) {
    newUnlocks.push('fumble-king');
  }

  // Critical Streak — 2 Nat 20s in a row
  if (hasNat20) {
    if (stats.lastRollWasNat20 && !hasAchievement('critical-streak')) {
      newUnlocks.push('critical-streak');
    }
    stats.lastRollWasNat20 = true;
    stats.nat20Count = (stats.nat20Count || 0) + 1;
  } else {
    stats.lastRollWasNat20 = false;
  }

  if (hasNat1) stats.nat1Count = (stats.nat1Count || 0) + 1;

  // Lucky Seven — rolled exactly 7 three times
  if (rollData.total === 7) {
    stats.sevenCount = (stats.sevenCount || 0) + 1;
    if (stats.sevenCount >= 3 && !hasAchievement('lucky-seven')) {
      newUnlocks.push('lucky-seven');
    }
  }

  // Dice Addict — 100 rolls
  if (stats.totalRolls >= 100 && !hasAchievement('dice-addict')) {
    newUnlocks.push('dice-addict');
  }

  // Social Butterfly — 5 different dice types
  if ((stats.diceTypesUsed || []).length >= 5 && !hasAchievement('social-butterfly')) {
    newUnlocks.push('social-butterfly');
  }

  // Check damage-related achievements from notation
  const isDmgRoll = rollData.notation && !rollData.notation.includes('d20') && rollData.total > 0;
  if (isDmgRoll) {
    // First Blood
    if (!hasAchievement('first-blood')) {
      stats.dealtDamage = true;
      newUnlocks.push('first-blood');
    }

    // Big Hitter — 30+ damage in one roll
    if (rollData.total >= 30 && !hasAchievement('big-hitter')) {
      newUnlocks.push('big-hitter');
    }

    // Centurion — 100 total damage
    stats.totalDamage = (stats.totalDamage || 0) + rollData.total;
    if (stats.totalDamage >= 100 && !hasAchievement('centurion')) {
      newUnlocks.push('centurion');
    }
  }

  // Process unlocks
  if (newUnlocks.length > 0) {
    newUnlocks.forEach(id => {
      if (!hasAchievement(id)) {
        achievementState.unlocked.push({
          id,
          unlockedAt: Date.now()
        });
        const def = ACHIEVEMENT_DEFS.find(a => a.id === id);
        if (def) {
          showAchievementToast(def, state.playerName);
          // Broadcast to other players
          sendWS({
            type: 'achievement-unlocked',
            data: { playerId: state.playerId, playerName: state.playerName, achievement: def }
          });
        }
      }
    });
    saveAchievements();
    renderAchievementGallery();
  } else {
    // Still save stats even if no new unlock
    saveAchievements();
  }
}

function hasAchievement(id) {
  return achievementState.unlocked.some(a => a.id === id);
}

function showAchievementToast(achievement, playerName) {
  const toast = document.createElement('div');
  toast.className = 'achievement-toast';
  toast.innerHTML = `
    <span class="toast-icon">${achievement.icon}</span>
    <div class="toast-text">
      <span class="toast-label">🏆 Achievement Unlocked!</span>
      <span class="toast-name">${escapeHtml(achievement.name)}</span>
      ${playerName ? `<span class="toast-player">${escapeHtml(playerName)}</span>` : ''}
    </div>
  `;
  document.body.appendChild(toast);
  setTimeout(() => toast.classList.add('show'), 50);
  setTimeout(() => {
    toast.classList.remove('show');
    setTimeout(() => toast.remove(), 500);
  }, 5000);
}

function renderAchievementGallery() {
  const gallery = $('#achievement-gallery');
  if (!gallery) return;

  gallery.innerHTML = '';
  ACHIEVEMENT_DEFS.forEach(def => {
    const unlock = achievementState.unlocked.find(a => a.id === def.id);
    const badge = document.createElement('div');
    badge.className = `achievement-badge ${unlock ? '' : 'locked'}`;
    badge.innerHTML = `
      <span class="badge-icon">${def.icon}</span>
      <span class="badge-name">${escapeHtml(def.name)}</span>
      <span class="badge-desc">${escapeHtml(def.desc)}</span>
      ${unlock ? `<span class="badge-date">${new Date(unlock.unlockedAt).toLocaleDateString()}</span>` : ''}
    `;
    gallery.appendChild(badge);
  });
}

