function initAvatarUpload() {
  const uploadBtn = $('#avatar-upload-btn');
  const fileInput = $('#avatar-file-input');
  const removeBtn = $('#avatar-remove-btn');
  const display = $('#char-avatar-display');

  uploadBtn?.addEventListener('click', () => fileInput?.click());
  display?.addEventListener('click', () => fileInput?.click());

  fileInput?.addEventListener('change', async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Validate file size (500KB max)
    if (file.size > 500 * 1024) {
      showToast('Image too large! Max 500KB.', 'error');
      fileInput.value = '';
      return;
    }

    // Validate file type
    if (!['image/jpeg', 'image/png'].includes(file.type)) {
      showToast('Only JPG and PNG images allowed.', 'error');
      fileInput.value = '';
      return;
    }

    try {
      const dataUrl = await resizeImage(file, 200, 200);
      state.avatarDataUrl = dataUrl;
      displayAvatar(dataUrl);
      show(removeBtn);
      debounceSaveCharacter();
    } catch (err) {
      showToast('Failed to process image.', 'error');
    }

    fileInput.value = '';
  });

  removeBtn?.addEventListener('click', () => {
    state.avatarDataUrl = null;
    displayAvatar(null);
    hide(removeBtn);
    debounceSaveCharacter();
  });
}

function resizeImage(file, maxWidth, maxHeight) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let w = img.width;
        let h = img.height;

        // Scale down maintaining aspect ratio
        if (w > maxWidth || h > maxHeight) {
          const ratio = Math.min(maxWidth / w, maxHeight / h);
          w = Math.round(w * ratio);
          h = Math.round(h * ratio);
        }

        canvas.width = w;
        canvas.height = h;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL('image/jpeg', 0.85));
      };
      img.onerror = reject;
      img.src = e.target.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function displayAvatar(dataUrl) {
  const display = $('#char-avatar-display');
  if (!display) return;
  if (dataUrl) {
    display.innerHTML = `<img src="${dataUrl}" alt="Avatar">`;
    show('#avatar-remove-btn');
  } else {
    display.innerHTML = `<span class="avatar-placeholder">🧙</span>`;
    hide('#avatar-remove-btn');
  }
}

