const Journal = (() => {
  function init() {
    $('#journal-write-btn')?.addEventListener('click', showWriteForm);
    $('#journal-cancel-btn')?.addEventListener('click', hideWriteForm);
    $('#journal-save-btn')?.addEventListener('click', saveEntry);
    $('#journal-ai-btn')?.addEventListener('click', aiGenerateEntry);
  }

  function showWriteForm() {
    show('#journal-write-form');
    $('#journal-entry-title').value = '';
    $('#journal-entry-session').value = '';
    $('#journal-entry-content').value = '';
    $('#journal-entry-title').focus();
  }

  function hideWriteForm() { hide('#journal-write-form'); }

  function updateCharInfo() {
    const label = $('#journal-char-name');
    const writeBtn = $('#journal-write-btn');
    const aiBtn = $('#journal-ai-btn');
    if (!state.currentCharId) {
      if (label) label.textContent = 'Select a character first';
      if (writeBtn) writeBtn.disabled = true;
      if (aiBtn) aiBtn.disabled = true;
      return;
    }
    api(`/characters/${state.currentCharId}`).then(c => {
      if (label) label.textContent = '\ud83d\udcd3 ' + (c.name || 'Unknown') + "'s Journal";
      if (writeBtn) writeBtn.disabled = false;
      if (aiBtn) aiBtn.disabled = false;
      loadEntries();
    }).catch(() => {
      if (label) label.textContent = 'Select a character first';
      if (writeBtn) writeBtn.disabled = true;
      if (aiBtn) aiBtn.disabled = true;
    });
  }

  async function loadEntries() {
    if (!state.currentCharId) return;
    try {
      const entries = await api(`/characters/${state.currentCharId}/journal`);
      renderEntries(entries);
    } catch (e) { console.error('Load journal failed:', e); }
  }

  function renderEntries(entries) {
    const list = $('#journal-entries-list');
    if (!entries || entries.length === 0) {
      list.innerHTML = '<div class="journal-empty">No journal entries yet. Write your first entry!</div>';
      return;
    }
    list.innerHTML = '';
    entries.forEach(e => {
      const card = document.createElement('div');
      card.className = 'journal-entry-card';
      const d = new Date(e.date);
      card.innerHTML = '<div class="journal-entry-header"><span class="journal-entry-title">' + escapeHtml(e.title) + '</span><span class="journal-entry-date">' + d.toLocaleDateString() + '</span></div>' +
        (e.sessionNumber ? '<span class="journal-entry-session">Session #' + e.sessionNumber + '</span>' : '') +
        '<div class="journal-entry-content">' + escapeHtml(e.content) + '</div>';
      list.appendChild(card);
    });
  }

  async function saveEntry() {
    if (!state.currentCharId) return;
    const title = $('#journal-entry-title').value.trim();
    const content = $('#journal-entry-content').value.trim();
    const sessionNumber = parseInt($('#journal-entry-session').value) || null;
    if (!title || !content) return alert('Title and content are required');
    try {
      await api('/characters/' + state.currentCharId + '/journal', {
        method: 'POST', body: { title: title, content: content, sessionNumber: sessionNumber }
      });
      hideWriteForm();
      loadEntries();
      showToast('\ud83d\udcd3 Journal entry saved!');
    } catch (e) { showToast('\u274c Failed: ' + e.message, 'error'); }
  }

  async function aiGenerateEntry() {
    if (!state.currentCharId) return;
    const btn = $('#journal-ai-btn');
    const statusEl = $('#journal-ai-status');
    btn.disabled = true;
    btn.textContent = '\u23f3 Writing...';
    statusEl.textContent = '\ud83d\udd2e AI is writing in your character\'s voice...';
    statusEl.className = 'ai-status';
    show(statusEl);
    try {
      const result = await api('/characters/' + state.currentCharId + '/journal/generate', { method: 'POST', body: {} });
      hide(statusEl);
      showWriteForm();
      $('#journal-entry-title').value = 'Reflections on Recent Events';
      $('#journal-entry-content').value = result.content || '';
      showToast('\u2728 AI draft ready \u2014 edit and save!');
    } catch (e) {
      statusEl.textContent = '\u274c ' + e.message;
      statusEl.className = 'ai-status ai-error';
    } finally {
      btn.disabled = false;
      btn.textContent = '\ud83e\udd16 AI Write Entry';
    }
  }

  return { init: init, updateCharInfo: updateCharInfo, loadEntries: loadEntries };
})();

