const EncounterBuilder = (() => {
  const XP_THRESHOLDS = {
    1:{easy:25,medium:50,hard:75,deadly:100},2:{easy:50,medium:100,hard:150,deadly:200},
    3:{easy:75,medium:150,hard:225,deadly:400},4:{easy:125,medium:250,hard:375,deadly:500},
    5:{easy:250,medium:500,hard:750,deadly:1100},6:{easy:300,medium:600,hard:900,deadly:1400},
    7:{easy:350,medium:750,hard:1100,deadly:1700},8:{easy:450,medium:900,hard:1400,deadly:2100},
    9:{easy:550,medium:1100,hard:1600,deadly:2400},10:{easy:600,medium:1200,hard:1900,deadly:2800},
    11:{easy:800,medium:1600,hard:2400,deadly:3600},12:{easy:1000,medium:2000,hard:3000,deadly:4500},
    13:{easy:1100,medium:2200,hard:3400,deadly:5100},14:{easy:1250,medium:2500,hard:3800,deadly:5700},
    15:{easy:1400,medium:2800,hard:4300,deadly:6400},16:{easy:1600,medium:3200,hard:4800,deadly:7200},
    17:{easy:2000,medium:3900,hard:5900,deadly:8800},18:{easy:2100,medium:4200,hard:6300,deadly:9500},
    19:{easy:2400,medium:4900,hard:7300,deadly:10900},20:{easy:2800,medium:5700,hard:8500,deadly:12700}
  };
  const CR_TO_XP = {'0':10,'1/8':25,'1/4':50,'1/2':100,'1':200,'2':450,'3':700,'4':1100,'5':1800,'6':2300,'7':2900,'8':3900,'9':5000,'10':5900,'11':7200,'12':8400,'13':10000,'14':11500,'15':13000,'16':15000,'17':18000,'18':20000,'19':22000,'20':25000,'21':33000,'22':41000,'23':50000,'24':62000,'25':75000};

  let encMonsters = [];
  let encParty = [];
  let currentEncounterId = null;
  let bestiaryCache = [];

  function init() {
    $('#encounter-new-btn')?.addEventListener('click', openBuilder);
    $('#encounter-simulator-btn')?.addEventListener('click', openSimulator);
    $('#enc-toggle-manual-party')?.addEventListener('click', () => $('#encounter-manual-party')?.classList.toggle('hidden'));
    $('#enc-add-manual-monster')?.addEventListener('click', addManualMonster);
    $('#enc-save-btn')?.addEventListener('click', saveEncounter);
    $('#enc-start-combat-btn')?.addEventListener('click', startEncounter);
    $('#enc-ai-analyze-btn')?.addEventListener('click', aiAnalyze);
    $('#sim-calculate-btn')?.addEventListener('click', quickSimulate);
    $('#enc-monster-search')?.addEventListener('input', searchBestiary);
  }

  function openBuilder() { show('#encounter-builder'); hide('#encounter-simulator'); currentEncounterId = null; encMonsters = []; $('#encounter-name').value = ''; renderMonsterList(); loadPartyInfo(); recalcDifficulty(); }
  function openSimulator() { hide('#encounter-builder'); show('#encounter-simulator'); hide('#sim-result'); }

  async function loadPartyInfo() {
    if (!state.roomPin) return;
    try {
      const chars = await api('/rooms/' + state.roomPin + '/characters');
      encParty = chars.map(function(c) {
        var cls = CLASSES.find(function(cl) { return cl.name === c.className; });
        var hitDieMax = cls ? parseInt(cls.hitDie.replace('d','')) : 8;
        var conMod = Math.floor(((c.abilityScores?.CON || 10) - 10) / 2);
        var hp = hitDieMax + conMod; if ((c.level||1)>1) hp += ((c.level||1)-1)*(Math.floor(hitDieMax/2)+1+conMod);
        return { name: c.name, level: c.level||1, hp: Math.max(hp,1), ac: 10+Math.floor(((c.abilityScores?.DEX||10)-10)/2) };
      });
      var el = $('#encounter-party-info');
      if (!encParty.length) { el.innerHTML = '<p class="muted">No players in room yet.</p>'; return; }
      el.innerHTML = encParty.map(function(p) { return '<div class="encounter-party-card"><span class="p-name">'+escapeHtml(p.name)+'</span><span class="p-stats">Lv.'+p.level+' | HP '+p.hp+' | AC '+p.ac+'</span></div>'; }).join('');
    } catch(e) { console.error('Load party failed:', e); }
  }

  function getPartyForCalc() {
    if (encParty.length > 0) return encParty;
    var n = parseInt($('#enc-party-count')?.value) || 4;
    var lv = parseInt($('#enc-party-level')?.value) || 3;
    return Array.from({length:n}, function(){ return {level:lv}; });
  }

  function searchBestiary() {
    var q = ($('#enc-monster-search')?.value||'').toLowerCase().trim();
    var results = $('#enc-monster-results');
    if (!q || q.length < 2) { hide(results); return; }
    if (bestiaryCache.length === 0) { api('/monsters').then(function(data){ bestiaryCache = data; doSearch(q, results); }); }
    else doSearch(q, results);
  }

  function doSearch(q, results) {
    var filtered = bestiaryCache.filter(function(m){ return m.name.toLowerCase().includes(q); }).slice(0,10);
    if (!filtered.length) { hide(results); return; }
    results.innerHTML = '';
    filtered.forEach(function(m) {
      var item = document.createElement('div');
      item.className = 'enc-monster-result-item';
      item.innerHTML = '<span class="em-name">'+escapeHtml(m.name)+'</span><span class="em-cr">CR '+m.cr+'</span>';
      item.addEventListener('click', function(){ addMonster({name:m.name,cr:String(m.cr),hp:m.hp,ac:m.ac,dpr:0}); hide(results); $('#enc-monster-search').value=''; });
      results.appendChild(item);
    });
    show(results);
  }

  function addManualMonster() {
    var name = $('#enc-m-name')?.value.trim(); if (!name) return;
    addMonster({name:name, cr:$('#enc-m-cr')?.value||'1', hp:parseInt($('#enc-m-hp')?.value)||10, ac:parseInt($('#enc-m-ac')?.value)||12, dpr:parseInt($('#enc-m-dpr')?.value)||5});
    $('#enc-m-name').value = '';
  }

  function addMonster(m) {
    var ex = encMonsters.find(function(x){ return x.name===m.name && x.cr===m.cr; });
    if (ex) ex.qty = (ex.qty||1)+1;
    else encMonsters.push(Object.assign({}, m, {qty:1, id:Date.now().toString(36)}));
    renderMonsterList(); recalcDifficulty();
  }

  function renderMonsterList() {
    var el = $('#enc-monster-list');
    if (!encMonsters.length) { el.innerHTML = ''; return; }
    el.innerHTML = '';
    encMonsters.forEach(function(m) {
      var row = document.createElement('div'); row.className = 'enc-monster-row';
      var xp = CR_TO_XP[m.cr]||0;
      row.innerHTML = '<div class="em-info"><span class="em-name">'+escapeHtml(m.name)+'</span><span class="em-stats">CR '+m.cr+' | HP '+m.hp+' | AC '+m.ac+' | '+xp+' XP</span></div><div class="em-qty"><button data-id="'+m.id+'" data-dir="-1">\u2212</button><span>'+m.qty+'</span><button data-id="'+m.id+'" data-dir="1">+</button></div><button class="em-remove" data-id="'+m.id+'">\ud83d\uddd1\ufe0f</button>';
      row.querySelectorAll('.em-qty button').forEach(function(btn) {
        btn.addEventListener('click', function() {
          var mon = encMonsters.find(function(x){return x.id===btn.dataset.id;});
          if (mon) { mon.qty = Math.max(0, mon.qty+parseInt(btn.dataset.dir)); if (mon.qty<=0) encMonsters = encMonsters.filter(function(x){return x.id!==mon.id;}); }
          renderMonsterList(); recalcDifficulty();
        });
      });
      row.querySelector('.em-remove').addEventListener('click', function() { encMonsters = encMonsters.filter(function(x){return x.id!==m.id;}); renderMonsterList(); recalcDifficulty(); });
      el.appendChild(row);
    });
  }

  function recalcDifficulty() {
    var party = getPartyForCalc();
    var numPlayers = party.length;
    var avgLevel = Math.round(party.reduce(function(s,p){return s+(p.level||3);},0)/numPlayers);
    var totalXP = 0;
    encMonsters.forEach(function(m){ totalXP += (CR_TO_XP[m.cr]||0)*(m.qty||1); });
    var thresh = XP_THRESHOLDS[Math.min(avgLevel,20)]||XP_THRESHOLDS[1];
    var bE=thresh.easy*numPlayers, bM=thresh.medium*numPlayers, bH=thresh.hard*numPlayers, bD=thresh.deadly*numPlayers;
    var difficulty='Trivial', diffClass='easy';
    if (totalXP>=bD){difficulty='DEADLY';diffClass='deadly';}
    else if(totalXP>=bH){difficulty='Hard';diffClass='hard';}
    else if(totalXP>=bM){difficulty='Medium';diffClass='medium';}
    else if(totalXP>=bE){difficulty='Easy';diffClass='easy';}
    var bar=$('#enc-diff-bar'); if(bar) bar.style.width=Math.min(100,(totalXP/Math.max(bD,1))*100)+'%';
    var textEl=$('#enc-diff-text');
    if(textEl){textEl.textContent=totalXP>0?'This encounter is '+difficulty+' for your party':'Add monsters to calculate difficulty';textEl.className='enc-diff-text '+diffClass;}
    var xpEl=$('#enc-diff-xp');
    if(xpEl) xpEl.textContent=totalXP>0?'Total XP: '+totalXP+' | Easy:'+bE+' Medium:'+bM+' Hard:'+bH+' Deadly:'+bD:'';
    var sugEl=$('#enc-diff-suggestion');
    if(sugEl&&totalXP>0){
      if(totalXP<bE)sugEl.textContent='\ud83d\udca1 Too easy \u2014 add more monsters.';
      else if(totalXP<bM)sugEl.textContent='\ud83d\udca1 Easy encounter \u2014 good warm-up.';
      else if(totalXP<bH)sugEl.textContent='\ud83d\udca1 Medium \u2014 fair challenge.';
      else if(totalXP<bD)sugEl.textContent='\ud83d\udca1 Hard \u2014 could be lethal if unlucky.';
      else sugEl.textContent='\u26a0\ufe0f DEADLY \u2014 high risk of character death!';
    } else if(sugEl) sugEl.textContent='';
    // Estimated rounds
    if(totalXP>0&&party.length>0){
      var avgDPR=party.length*(avgLevel*3+5);
      var totalHP=encMonsters.reduce(function(s,m){return s+m.hp*(m.qty||1);},0);
      var est=Math.max(1,Math.round(totalHP/avgDPR));
      if(xpEl) xpEl.textContent+=' | ~'+est+' rounds';
    }
  }

  async function saveEncounter() {
    if(!state.roomPin) return;
    var name=$('#encounter-name')?.value.trim()||'Unnamed Encounter';
    try{
      var saved = await api('/rooms/'+state.roomPin+'/encounters',{method:'POST',body:{id:currentEncounterId,name:name,monsters:encMonsters,partyInfo:getPartyForCalc(),totalXP:encMonsters.reduce(function(s,m){return s+(CR_TO_XP[m.cr]||0)*(m.qty||1);},0)}});
      currentEncounterId=saved.id;
      showToast('\ud83d\udcbe Encounter "'+name+'" saved!');
      loadSavedEncounters();

    }catch(e){showToast('\u274c '+e.message,'error');}
  }

  function startEncounter() {
    encMonsters.forEach(function(m){
      for(var i=0;i<(m.qty||1);i++){
        var initRoll=rollDie(20);
        var baseName=m.name;
        var existing=state.initiative.combatants.filter(function(c){return c.name.startsWith(baseName);});
        var displayName=baseName;
        if(existing.length>0||(m.qty||1)>1){displayName=baseName+' #'+(existing.length+1);if(existing.length===1&&existing[0].name===baseName)existing[0].name=baseName+' #1';}
        state.initiative.combatants.push({id:Date.now().toString(36)+Math.random().toString(36).slice(2,6),name:displayName,initiative:initRoll,maxHP:m.hp,currentHP:m.hp,ac:m.ac,type:'monster',conditions:[],active:false});
      }
    });
    sortInitiative(); broadcastInitiative();
    showToast('\u2694\ufe0f Encounter started! Monsters added to initiative.');
    switchTab('initiative');
  }

  async function aiAnalyze() {
    var btn=$('#enc-ai-analyze-btn');var analysisEl=$('#enc-ai-analysis');
    btn.disabled=true;btn.textContent='\u23f3 Analyzing...';show(analysisEl);analysisEl.textContent='\ud83d\udd2e AI analyzing encounter...';
    try{
      var result=await api('/encounters/analyze',{method:'POST',body:{party:getPartyForCalc(),monsters:encMonsters,difficulty:$('#enc-diff-text')?.textContent||''}});
      analysisEl.textContent=result.analysis||'No analysis available.';
    }catch(e){analysisEl.textContent='\u274c '+e.message;}
    finally{btn.disabled=false;btn.textContent='\ud83e\udd16 Analyze Encounter';}
  }

  function quickSimulate() {
    var numPlayers=parseInt($('#sim-party-count')?.value)||4;
    var avgLevel=parseInt($('#sim-party-level')?.value)||3;
    var input=($('#sim-monster-input')?.value||'').trim();
    if(!input)return;
    var totalXP=0;
    if(/^\d+$/.test(input)){totalXP=parseInt(input);}
    else{input.split(',').map(function(s){return s.trim();}).forEach(function(cr){totalXP+=(CR_TO_XP[cr]||0);});}
    var thresh=XP_THRESHOLDS[Math.min(avgLevel,20)]||XP_THRESHOLDS[1];
    var bE=thresh.easy*numPlayers,bM=thresh.medium*numPlayers,bH=thresh.hard*numPlayers,bD=thresh.deadly*numPlayers;
    var diff='Trivial',color='#10B981';
    if(totalXP>=bD){diff='DEADLY';color='#EF4444';}else if(totalXP>=bH){diff='Hard';color='#F97316';}else if(totalXP>=bM){diff='Medium';color='#F59E0B';}else if(totalXP>=bE){diff='Easy';color='#10B981';}
    var result=$('#sim-result');
    var msg=totalXP>=bD?'\u26a0\ufe0f High risk of death!':totalXP>=bH?'\u2694\ufe0f Tough fight.':totalXP>=bM?'\ud83c\udfaf Fair challenge.':totalXP>=bE?'\u2705 Easy warm-up.':'\ud83d\ude34 Add more monsters.';
    result.innerHTML='<h4 style="color:'+color+'">'+diff+' Encounter</h4><p>Total XP: <strong>'+totalXP+'</strong> | Party: '+numPlayers+' at Lv.'+avgLevel+'</p><p>Easy:'+bE+' | Medium:'+bM+' | Hard:'+bH+' | Deadly:'+bD+'</p><p style="margin-top:8px;font-style:italic;color:#c084fc">'+msg+'</p>';
    show(result);
  }

  async function loadSavedEncounters() {
    if(!state.roomPin)return;
    try{var encounters=await api('/rooms/'+state.roomPin+'/encounters');renderSavedEncounters(encounters);}catch(e){console.error('Load encounters failed:',e);}
  }

  function renderSavedEncounters(encounters) {
    var list=$('#enc-saved-list');
    if(!encounters||!encounters.length){list.innerHTML='<p class="muted">No saved encounters yet.</p>';return;}
    list.innerHTML='';
    encounters.forEach(function(enc){
      var card=document.createElement('div');card.className='enc-saved-card';
      var mc=enc.monsters?enc.monsters.reduce(function(s,m){return s+(m.qty||1);},0):0;
      card.innerHTML='<div class="enc-s-name">'+escapeHtml(enc.name)+'</div><div class="enc-s-info">'+mc+' monsters | '+(enc.totalXP||0)+' XP</div><div class="enc-s-actions"><button class="btn-sm btn-gold enc-load-btn" data-id="'+enc.id+'">\ud83d\udcc2 Load</button><button class="btn-sm btn-danger enc-del-btn" data-id="'+enc.id+'">\ud83d\uddd1\ufe0f</button></div>';
      card.querySelector('.enc-load-btn').addEventListener('click',function(e){e.stopPropagation();loadEncounter(enc);});
      card.querySelector('.enc-del-btn').addEventListener('click',async function(e){
        e.stopPropagation();if(!confirm('Delete "'+enc.name+'"?'))return;
        try{await api('/rooms/'+state.roomPin+'/encounters/'+enc.id,{method:'DELETE'});loadSavedEncounters();showToast('\ud83d\uddd1\ufe0f Deleted');}catch(err){showToast('\u274c '+err.message,'error');}
      });
      list.appendChild(card);
    });
  }

  function loadEncounter(enc) {
    show('#encounter-builder');hide('#encounter-simulator');
    currentEncounterId=enc.id;$('#encounter-name').value=enc.name||'';
    encMonsters=enc.monsters||[];renderMonsterList();recalcDifficulty();
    showToast('\ud83d\udcc2 Loaded "'+enc.name+'"');
  }

  return { init:init, loadSavedEncounters:loadSavedEncounters, loadPartyInfo:loadPartyInfo };
})();

