const RelationshipMap = (() => {
  const REL_COLORS = {ally:'#10B981',rival:'#F97316',romantic:'#EC4899',mentor:'#3B82F6',enemy:'#EF4444',family:'#F59E0B',business:'#9CA3AF'};
  let relationships = [];
  let characters = [];
  let npcsList = [];

  function init() {
    $('#rel-add-btn')?.addEventListener('click', openAddModal);
    $('#rel-cancel-btn')?.addEventListener('click', function(){ hide('#rel-add-modal'); });
    $('#rel-save-btn')?.addEventListener('click', saveRelationship);
    $('#rel-add-modal')?.addEventListener('click', function(e){ if(e.target.id==='rel-add-modal') hide('#rel-add-modal'); });
  }

  async function load() {
    if(!state.roomPin) return;
    if(state.isDM){var el=$('#rel-dm-actions');if(el)el.style.display='flex';}
    try{
      var results = await Promise.all([
        api('/rooms/'+state.roomPin+'/relationships'),
        api('/rooms/'+state.roomPin+'/characters'),
        state.isDM ? api('/rooms/'+state.roomPin+'/npcs') : Promise.resolve([])
      ]);
      relationships=results[0]||[];characters=results[1]||[];npcsList=(results[2]||[]).filter(function(n){return !n.isMonster;});
      renderList();renderGraph();
    }catch(e){console.error('Load relationships failed:',e);}
  }

  function renderList() {
    var list=$('#rel-list');
    if(!relationships.length){list.innerHTML='<p class="muted">No relationships defined yet.</p>';return;}
    list.innerHTML='';
    relationships.forEach(function(r){
      var item=document.createElement('div');item.className='rel-item';
      item.innerHTML='<div class="rel-names">'+escapeHtml(r.fromName||'?')+' \u2194 '+escapeHtml(r.toName||'?')+(r.label?' \u2014 <em>'+escapeHtml(r.label)+'</em>':'')+'</div><span class="rel-type-badge rel-type-'+r.type+'">'+r.type+'</span>'+(state.isDM?'<button class="rel-delete" data-id="'+r.id+'">\u2715</button>':'');
      if(state.isDM){item.querySelector('.rel-delete')?.addEventListener('click',async function(){
        try{await api('/rooms/'+state.roomPin+'/relationships/'+r.id,{method:'DELETE'});load();showToast('Relationship removed');}catch(e){showToast('\u274c '+e.message,'error');}
      });}
      list.appendChild(item);
    });
  }

  function renderGraph() {
    var svg=$('#rel-graph-svg');if(!svg)return;
    var wrap=$('#rel-graph-wrap');
    var w=wrap.clientWidth||600,h=wrap.clientHeight||500;
    svg.setAttribute('viewBox','0 0 '+w+' '+h);svg.innerHTML='';
    var nodeMap=new Map();
    var allEntities=[].concat(characters.map(function(c){return{id:c.id,name:c.name,type:'pc'};}),npcsList.map(function(n){return{id:n.id,name:n.name,type:'npc'};}));
    relationships.forEach(function(r){
      if(!nodeMap.has(r.from)){var ent=allEntities.find(function(e){return e.id===r.from;});nodeMap.set(r.from,{id:r.from,name:r.fromName||(ent?ent.name:'?'),type:ent?ent.type:'npc'});}
      if(!nodeMap.has(r.to)){var ent2=allEntities.find(function(e){return e.id===r.to;});nodeMap.set(r.to,{id:r.to,name:r.toName||(ent2?ent2.name:'?'),type:ent2?ent2.type:'npc'});}
    });
    characters.forEach(function(c){if(!nodeMap.has(c.id))nodeMap.set(c.id,{id:c.id,name:c.name,type:'pc'});});
    var nodes=Array.from(nodeMap.values());
    if(nodes.length===0){svg.innerHTML='<text x="50%" y="50%" text-anchor="middle" fill="#666" font-size="14">No characters or relationships to display</text>';return;}
    var cx=w/2,cy=h/2,radius=Math.min(w,h)*0.35;
    nodes.forEach(function(n,i){var angle=(2*Math.PI*i)/nodes.length-Math.PI/2;n.x=cx+radius*Math.cos(angle);n.y=cy+radius*Math.sin(angle);});
    relationships.forEach(function(r){
      var from=nodeMap.get(r.from),to=nodeMap.get(r.to);if(!from||!to)return;
      var color=REL_COLORS[r.type]||'#9CA3AF';
      var line=document.createElementNS('http://www.w3.org/2000/svg','line');
      line.setAttribute('x1',from.x);line.setAttribute('y1',from.y);line.setAttribute('x2',to.x);line.setAttribute('y2',to.y);
      line.setAttribute('stroke',color);line.setAttribute('stroke-width','2.5');line.setAttribute('stroke-opacity','0.7');
      svg.appendChild(line);
      var mx=(from.x+to.x)/2,my=(from.y+to.y)/2;
      var lbl=document.createElementNS('http://www.w3.org/2000/svg','text');
      lbl.setAttribute('x',mx);lbl.setAttribute('y',my-6);lbl.setAttribute('text-anchor','middle');lbl.setAttribute('fill',color);lbl.setAttribute('font-size','10');lbl.setAttribute('font-weight','600');
      lbl.textContent=r.label||r.type;svg.appendChild(lbl);
    });
    nodes.forEach(function(n){
      var g=document.createElementNS('http://www.w3.org/2000/svg','g');g.style.cursor='pointer';
      var circ=document.createElementNS('http://www.w3.org/2000/svg','circle');
      circ.setAttribute('cx',n.x);circ.setAttribute('cy',n.y);circ.setAttribute('r',n.type==='pc'?28:22);
      circ.setAttribute('fill',n.type==='pc'?'#1a2035':'#2a1f35');
      circ.setAttribute('stroke',n.type==='pc'?'#F59E0B':'#8B5CF6');circ.setAttribute('stroke-width','2.5');
      g.appendChild(circ);
      var txt=document.createElementNS('http://www.w3.org/2000/svg','text');
      txt.setAttribute('x',n.x);txt.setAttribute('y',n.y+4);txt.setAttribute('text-anchor','middle');txt.setAttribute('fill','#E5E7EB');txt.setAttribute('font-size','11');txt.setAttribute('font-weight','600');
      txt.textContent=n.name.length>10?n.name.slice(0,9)+'\u2026':n.name;g.appendChild(txt);
      var tl=document.createElementNS('http://www.w3.org/2000/svg','text');
      tl.setAttribute('x',n.x);tl.setAttribute('y',n.y+(n.type==='pc'?44:38));tl.setAttribute('text-anchor','middle');tl.setAttribute('fill','#6B7280');tl.setAttribute('font-size','9');
      tl.textContent=n.type==='pc'?'Player':'NPC';g.appendChild(tl);
      svg.appendChild(g);
    });
  }

  function openAddModal() {
    var fromSel=$('#rel-from-select'),toSel=$('#rel-to-select');
    var allEntities=[].concat(characters.map(function(c){return{id:c.id,name:c.name+' (PC)'};}),npcsList.map(function(n){return{id:n.id,name:n.name+' (NPC)'};}));
    fromSel.innerHTML='';toSel.innerHTML='';
    allEntities.forEach(function(e){fromSel.innerHTML+='<option value="'+e.id+'">'+escapeHtml(e.name)+'</option>';toSel.innerHTML+='<option value="'+e.id+'">'+escapeHtml(e.name)+'</option>';});
    if(allEntities.length>1)toSel.value=allEntities[1].id;
    $('#rel-label-input').value='';show('#rel-add-modal');
  }

  async function saveRelationship() {
    var fromId=$('#rel-from-select')?.value,toId=$('#rel-to-select')?.value;
    if(!fromId||!toId||fromId===toId)return alert('Select two different characters');
    var type=$('#rel-type-select')?.value||'ally';var label=$('#rel-label-input')?.value.trim()||'';
    var allEnt=[].concat(characters,npcsList);
    var fromEnt=allEnt.find(function(e){return e.id===fromId;});var toEnt=allEnt.find(function(e){return e.id===toId;});
    try{
      await api('/rooms/'+state.roomPin+'/relationships',{method:'POST',body:{from:fromId,fromName:fromEnt?.name||'?',to:toId,toName:toEnt?.name||'?',type:type,label:label}});
      hide('#rel-add-modal');load();showToast('\ud83d\udd78\ufe0f Relationship added!');
    }catch(e){showToast('\u274c '+e.message,'error');}
  }

  return { init:init, load:load };
})();

// ============================================================
// PLAYER STATS DASHBOARD
// ============================================================

const PlayerStats = (() => {
  let currentStats = null;

  function init() {
    $('#refresh-stats-btn')?.addEventListener('click', loadAndRender);
  }

  async function loadAndRender() {
    if (!state.currentCharId && !state.isDM) {
      renderEmpty();
      return;
    }
    // For players: show their own stats
    if (!state.isDM && state.currentCharId) {
      try {
        currentStats = await api(`/characters/${state.currentCharId}/stats`);
        renderDashboard(currentStats);
      } catch (e) {
        console.error('Load stats failed:', e);
        renderEmpty();
      }
    } else if (state.isDM) {
      // DM can see all player stats - show a combined view
      try {
        const chars = await api(`/rooms/${state.roomPin}/characters`);
        renderDMStatsOverview(chars);
      } catch (e) {
        console.error('Load DM stats failed:', e);
        renderEmpty();
      }
    }
  }

  function renderEmpty() {
    const el = $('#stats-dashboard');
    if (el) el.innerHTML = '<div class="stats-empty">Select a character to view stats. Stats are tracked from dice rolls and combat.</div>';
  }

  function renderDashboard(stats) {
    const el = $('#stats-dashboard');
    if (!el) return;
    const d = stats.dice || {};
    const c = stats.combat || {};
    const s = stats.session || {};

    let html = '';

    // Dice Stats Section
    html += `<div class="stats-section">
      <h3>🎲 Dice Stats</h3>
      <div class="stats-grid">
        <div class="stat-card gold"><div class="stat-card-value">${d.totalRolled || 0}</div><div class="stat-card-label">Total Rolled</div></div>
        <div class="stat-card gold"><div class="stat-card-value">${d.nat20Count || 0}</div><div class="stat-card-label">Nat 20s</div></div>
        <div class="stat-card damage"><div class="stat-card-value">${d.nat1Count || 0}</div><div class="stat-card-label">Nat 1s</div></div>
        <div class="stat-card"><div class="stat-card-value">${d.luckiest || '—'}</div><div class="stat-card-label">Luckiest Roll</div></div>
        <div class="stat-card"><div class="stat-card-value">${d.unluckiest || '—'}</div><div class="stat-card-label">Unluckiest Roll</div></div>
      </div>
      <h4 style="margin-top:12px;font-size:0.85rem;color:var(--text-dim)">Rolls per Dice Type</h4>
      ${renderBarChart(d.byType || {})}
      <h4 style="margin-top:12px;font-size:0.85rem;color:var(--text-dim)">d20 Distribution</h4>
      ${renderD20Histogram(d.d20Distribution || {})}
    </div>`;

    // Combat Stats Section
    html += `<div class="stats-section">
      <h3>⚔️ Combat Stats</h3>
      <div class="stats-grid">
        <div class="stat-card damage"><div class="stat-card-value">${c.totalDamageDealt || 0}</div><div class="stat-card-label">Total Damage</div></div>
        <div class="stat-card damage"><div class="stat-card-value">${c.highestSingleDamage || 0}</div><div class="stat-card-label">Highest Hit</div></div>
        <div class="stat-card"><div class="stat-card-value">${c.totalAttacks || 0}</div><div class="stat-card-label">Total Attacks</div></div>
        <div class="stat-card healing"><div class="stat-card-value">${c.totalAttacks > 0 ? Math.round((c.hits / c.totalAttacks) * 100) : 0}%</div><div class="stat-card-label">Hit Rate</div></div>
        <div class="stat-card damage"><div class="stat-card-value">${c.kills || 0}</div><div class="stat-card-label">Kills</div></div>
        <div class="stat-card"><div class="stat-card-value">${c.timesDowned || 0}</div><div class="stat-card-label">Times Downed</div></div>
        <div class="stat-card healing"><div class="stat-card-value">${c.deathSaveSuccesses || 0}</div><div class="stat-card-label">Death Save ✓</div></div>
        <div class="stat-card damage"><div class="stat-card-value">${c.deathSaveFailures || 0}</div><div class="stat-card-label">Death Save ✗</div></div>
      </div>
      ${c.totalAttacks > 0 ? `<div style="margin-top:10px"><span style="font-size:0.78rem;color:var(--text-dim)">Hit Rate</span><div class="stats-progress"><div class="stats-progress-fill hit-rate" style="width:${Math.round((c.hits / c.totalAttacks) * 100)}%"></div></div></div>` : ''}
    </div>`;

    // Session Stats Section
    html += `<div class="stats-section">
      <h3>📋 Session Stats</h3>
      <div class="stats-grid">
        <div class="stat-card"><div class="stat-card-value">${s.totalSessions || 0}</div><div class="stat-card-label">Sessions Played</div></div>
        <div class="stat-card"><div class="stat-card-value">${formatDuration(s.totalTimePlayed || 0)}</div><div class="stat-card-label">Time Played</div></div>
        <div class="stat-card"><div class="stat-card-value">${getMostUsed(s.spellUsage) || '—'}</div><div class="stat-card-label">Most Used Spell</div></div>
        <div class="stat-card"><div class="stat-card-value">${getMostUsed(s.actionUsage) || '—'}</div><div class="stat-card-label">Most Used Action</div></div>
      </div>
    </div>`;

    el.innerHTML = html;
  }

  function renderDMStatsOverview(chars) {
    const el = $('#stats-dashboard');
    if (!el) return;
    if (!chars || chars.length === 0) {
      el.innerHTML = '<div class="stats-empty">No characters in this room yet.</div>';
      return;
    }

    let html = '';
    chars.forEach(c => {
      const s = c.stats || { dice: {}, combat: {}, session: {} };
      const d = s.dice || {};
      const cb = s.combat || {};
      html += `<div class="stats-section">
        <h3>📊 ${escapeHtml(c.name || 'Unknown')} <span style="font-size:0.75rem;color:var(--text-dim);font-family:Inter,sans-serif">(${escapeHtml(c.playerName || '?')})</span></h3>
        <div class="stats-grid">
          <div class="stat-card gold"><div class="stat-card-value">${d.totalRolled || 0}</div><div class="stat-card-label">Dice Rolled</div></div>
          <div class="stat-card gold"><div class="stat-card-value">${d.nat20Count || 0}</div><div class="stat-card-label">Nat 20s</div></div>
          <div class="stat-card damage"><div class="stat-card-value">${cb.totalDamageDealt || 0}</div><div class="stat-card-label">Damage Dealt</div></div>
          <div class="stat-card damage"><div class="stat-card-value">${cb.highestSingleDamage || 0}</div><div class="stat-card-label">Highest Hit</div></div>
          <div class="stat-card"><div class="stat-card-value">${cb.kills || 0}</div><div class="stat-card-label">Kills</div></div>
          <div class="stat-card"><div class="stat-card-value">${cb.timesDowned || 0}</div><div class="stat-card-label">Times Downed</div></div>
        </div>
      </div>`;
    });
    el.innerHTML = html;
  }

  function renderBarChart(byType) {
    const entries = Object.entries(byType);
    if (entries.length === 0) return '<p class="muted" style="font-size:0.8rem">No rolls yet.</p>';
    const max = Math.max(...entries.map(([,v]) => v), 1);
    let html = '<div class="stats-bar-chart">';
    const order = ['d4','d6','d8','d10','d12','d20','d100'];
    order.forEach(die => {
      const count = byType[die] || 0;
      if (count === 0) return;
      const pct = (count / max) * 100;
      const avg = byType[die + '_avg'] ? byType[die + '_avg'].toFixed(1) : '';
      html += `<div class="stats-bar-row">
        <span class="stats-bar-label">${die}</span>
        <div class="stats-bar-wrap"><div class="stats-bar-fill bar-${die}" style="width:${pct}%"></div></div>
        <span class="stats-bar-value">${count}${avg ? ' (avg ' + avg + ')' : ''}</span>
      </div>`;
    });
    html += '</div>';
    return html;
  }

  function renderD20Histogram(dist) {
    let hasData = false;
    for (let i = 1; i <= 20; i++) {
      if (dist[i]) { hasData = true; break; }
    }
    if (!hasData) return '<p class="muted" style="font-size:0.8rem">No d20 rolls yet.</p>';
    const max = Math.max(...Array.from({length: 20}, (_, i) => dist[i + 1] || 0), 1);
    let html = '<div class="d20-histogram">';
    for (let i = 1; i <= 20; i++) {
      const count = dist[i] || 0;
      const h = Math.max(2, (count / max) * 100);
      html += `<div class="d20-hist-bar" data-val="${i}" style="height:${h}%" title="${i}: ${count} times"></div>`;
    }
    html += '</div><div class="d20-hist-labels">';
    for (let i = 1; i <= 20; i++) {
      html += `<span>${i}</span>`;
    }
    html += '</div>';
    return html;
  }

  function formatDuration(ms) {
    if (!ms || ms < 60000) return '< 1m';
    const mins = Math.floor(ms / 60000);
    if (mins < 60) return mins + 'm';
    const hrs = Math.floor(mins / 60);
    const remainMins = mins % 60;
    return hrs + 'h ' + remainMins + 'm';
  }

  function getMostUsed(obj) {
    if (!obj) return null;
    const entries = Object.entries(obj);
    if (entries.length === 0) return null;
    entries.sort((a, b) => b[1] - a[1]);
    return entries[0][0];
  }

  // Called whenever a dice roll happens - update player stats
  function trackRoll(rollData) {
    if (state.isDM || !state.currentCharId) return;
    if (!currentStats) {
      currentStats = {
        dice: { totalRolled: 0, byType: {}, d20Distribution: {}, nat20Count: 0, nat1Count: 0, luckiest: null, unluckiest: null },
        combat: { totalDamageDealt: 0, highestSingleDamage: 0, totalAttacks: 0, hits: 0, kills: 0, timesDowned: 0, deathSaveSuccesses: 0, deathSaveFailures: 0 },
        session: { totalSessions: 0, totalTimePlayed: 0, spellUsage: {}, actionUsage: {}, firstActivity: null, lastActivity: null }
      };
    }

    const d = currentStats.dice;
    d.totalRolled = (d.totalRolled || 0) + 1;

    // Track by type
    const dieType = 'd' + (rollData.sides || 20);
    d.byType[dieType] = (d.byType[dieType] || 0) + 1;

    // Track average per type
    const avgKey = dieType + '_avg';
    const countKey = dieType;
    const prevAvg = d.byType[avgKey] || 0;
    const prevCount = d.byType[countKey] || 1;
    if (rollData.total !== undefined) {
      d.byType[avgKey] = ((prevAvg * (prevCount - 1)) + rollData.total) / prevCount;
    }

    // D20 distribution
    if (rollData.sides === 20 && rollData.results) {
      rollData.results.forEach(r => {
        if (!d.d20Distribution) d.d20Distribution = {};
        d.d20Distribution[r] = (d.d20Distribution[r] || 0) + 1;
      });
      // Nat 20 / Nat 1
      if (rollData.results.includes(20)) d.nat20Count = (d.nat20Count || 0) + 1;
      if (rollData.results.includes(1)) d.nat1Count = (d.nat1Count || 0) + 1;
    }

    // Luckiest / unluckiest
    if (rollData.total !== undefined) {
      if (d.luckiest === null || rollData.total > d.luckiest) d.luckiest = rollData.total;
      if (d.unluckiest === null || rollData.total < d.unluckiest) d.unluckiest = rollData.total;
    }

    // Combat tracking (heuristic: d20 = attack, non-d20 = damage)
    if (rollData.sides === 20) {
      currentStats.combat.totalAttacks = (currentStats.combat.totalAttacks || 0) + 1;
    } else if (rollData.sides && rollData.sides !== 20 && rollData.total > 0) {
      currentStats.combat.totalDamageDealt = (currentStats.combat.totalDamageDealt || 0) + rollData.total;
      if (rollData.total > (currentStats.combat.highestSingleDamage || 0)) {
        currentStats.combat.highestSingleDamage = rollData.total;
      }
    }

    // Session tracking
    const now = Date.now();
    if (!currentStats.session.firstActivity) currentStats.session.firstActivity = now;
    currentStats.session.lastActivity = now;
    if (currentStats.session.firstActivity) {
      currentStats.session.totalTimePlayed = now - currentStats.session.firstActivity;
    }

    // Debounce save to backend
    debounceSaveStats();
  }

  let _statsSaveTimer = null;
  function debounceSaveStats() {
    if (_statsSaveTimer) clearTimeout(_statsSaveTimer);
    _statsSaveTimer = setTimeout(saveStats, 5000);
  }

  async function saveStats() {
    if (!state.currentCharId || !currentStats) return;
    try {
      await api(`/characters/${state.currentCharId}/stats`, { method: 'PUT', body: currentStats });
    } catch (e) {
      console.error('Save stats failed:', e);
    }
  }

  return { init, loadAndRender, trackRoll, renderEmpty };
})();

// ============================================================
// SESSION ANALYTICS (DM only)
// ============================================================

const SessionAnalytics = (() => {
  function init() {
    $('#refresh-analytics-btn')?.addEventListener('click', loadAnalytics);
  }

  async function loadAnalytics() {
    if (!state.roomPin || !state.isDM) return;
    try {
      const data = await api(`/rooms/${state.roomPin}/analytics`);
      renderAnalytics(data);
    } catch (e) {
      console.error('Load analytics failed:', e);
    }
  }

  const PART_COLORS = ['#ef4444','#3b82f6','#10b981','#f59e0b','#8b5cf6','#ec4899','#06b6d4','#f97316'];

  function renderAnalytics(data) {
    const el = $('#session-analytics-content');
    if (!el) return;

    const duration = data.sessionDuration || 0;
    const durationStr = duration > 0 ? formatDuration(duration) : '—';

    let html = `
      <div class="analytics-card"><div class="analytics-value">${data.totalRolls || 0}</div><div class="analytics-label">Total Dice Rolls</div></div>
      <div class="analytics-card"><div class="analytics-value" style="color:#ef4444">${data.totalDamage || 0}</div><div class="analytics-label">Total Damage</div></div>
      <div class="analytics-card"><div class="analytics-value">${data.combatRounds || 0}</div><div class="analytics-label">Combat Rounds</div></div>
      <div class="analytics-card"><div class="analytics-value">${durationStr}</div><div class="analytics-label">Session Duration</div></div>
      <div class="analytics-card"><div class="analytics-value" style="font-size:1rem">${escapeHtml(data.mostActivePlayer || '—')}</div><div class="analytics-label">Most Active</div><div class="analytics-detail">${data.mostActiveRolls || 0} rolls</div></div>
      <div class="analytics-card"><div class="analytics-value" style="color:#fbbf24">${data.biggestHit || 0}</div><div class="analytics-label">Biggest Hit</div><div class="analytics-detail">${escapeHtml(data.biggestHitPlayer || '')}</div></div>
    `;

    // Participation chart
    const participation = data.participation || {};
    const names = Object.keys(participation);
    if (names.length > 0) {
      html += `</div><h4 style="margin-top:14px;font-size:0.85rem;color:var(--text-dim)">Player Participation</h4><div class="participation-chart">`;
      names.forEach((name, i) => {
        const pct = participation[name] || 0;
        const color = PART_COLORS[i % PART_COLORS.length];
        html += `<div class="participation-row">
          <div class="participation-color" style="background:${color}"></div>
          <span class="participation-name">${escapeHtml(name)}</span>
          <div class="participation-bar-wrap"><div class="participation-bar" style="width:${pct}%;background:${color}"></div></div>
          <span class="participation-pct">${pct}%</span>
        </div>`;
      });
      html += `</div><div class="analytics-grid" style="display:none">`;
    }

    el.innerHTML = html;
  }

  function formatDuration(ms) {
    if (!ms || ms < 60000) return '< 1m';
    const mins = Math.floor(ms / 60000);
    if (mins < 60) return mins + 'm';
    const hrs = Math.floor(mins / 60);
    const remainMins = mins % 60;
    return hrs + 'h ' + remainMins + 'm';
  }

  return { init, loadAnalytics };
})();

