const SessionReplay = (() => {
  let events = [];
  let playTimer = null;
  let currentIdx = -1;
  let playing = false;

  function init() {
    $('#replay-play-btn')?.addEventListener('click', startPlay);
    $('#replay-pause-btn')?.addEventListener('click', pausePlay);
    $('#replay-clear-btn')?.addEventListener('click', clearLog);
    $('#replay-slider')?.addEventListener('input', onSliderChange);
  }

  async function loadEvents() {
    if (!state.roomPin || !state.isDM) return;
    try {
      events = await api(`/rooms/${state.roomPin}/replay`);
      renderEventLog();
      const slider = $('#replay-slider');
      if (slider) {
        slider.max = Math.max(0, events.length - 1);
        slider.value = 0;
      }
    } catch (e) {
      console.error('Load replay events failed:', e);
    }
  }

  function renderEventLog() {
    const el = $('#replay-event-log');
    if (!el) return;
    if (!events || events.length === 0) {
      el.innerHTML = '<p class="muted">No events recorded yet. Events are logged automatically during play.</p>';
      return;
    }
    el.innerHTML = '';
    events.forEach((evt, idx) => {
      const div = document.createElement('div');
      div.className = 'replay-event';
      div.id = 'replay-evt-' + idx;
      const time = evt.timestamp ? new Date(evt.timestamp).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit',second:'2-digit'}) : '?';
      const { icon, text } = formatEvent(evt);
      div.innerHTML = `<span class="event-time">${time}</span><span class="event-icon">${icon}</span><span class="event-text">${text}</span>`;
      el.appendChild(div);
    });
  }

  function formatEvent(evt) {
    const d = evt.data || {};
    switch (evt.type) {
      case 'dice-roll':
        return {
          icon: '🎲',
          text: `<strong>${escapeHtml(d.userName || '?')}</strong> rolled ${escapeHtml(d.notation || '?')} → <strong>${d.total || '?'}</strong>${d.detail ? ' (' + escapeHtml(d.detail) + ')' : ''}`
        };
      case 'initiative-update':
        return { icon: '⚔️', text: `<strong>Initiative</strong> updated` };
      case 'chat-message':
        return { icon: '💬', text: `<strong>${escapeHtml(d.userName || '?')}</strong>: ${escapeHtml(d.message || '')}` };
      case 'token_move':
        return { icon: '🗺️', text: `<strong>${escapeHtml(d.userName || '?')}</strong> moved a token` };
      default:
        return { icon: '📝', text: escapeHtml(JSON.stringify(d).slice(0, 100)) };
    }
  }

  function startPlay() {
    if (events.length === 0) return;
    playing = true;
    show('#replay-pause-btn');
    hide('#replay-play-btn');
    const speed = parseInt($('#replay-speed')?.value) || 1000;
    const statusEl = $('#replay-status');
    if (currentIdx < 0) currentIdx = 0;

    playTimer = setInterval(() => {
      if (currentIdx >= events.length) {
        pausePlay();
        if (statusEl) statusEl.textContent = 'Replay complete';
        return;
      }
      highlightEvent(currentIdx);
      if (statusEl) statusEl.textContent = `Event ${currentIdx + 1} / ${events.length}`;
      const slider = $('#replay-slider');
      if (slider) slider.value = currentIdx;
      currentIdx++;
    }, speed);
  }

  function pausePlay() {
    playing = false;
    if (playTimer) { clearInterval(playTimer); playTimer = null; }
    hide('#replay-pause-btn');
    show('#replay-play-btn');
  }

  function highlightEvent(idx) {
    // Remove previous highlights
    $$('.replay-event.active').forEach(el => el.classList.remove('active'));
    const el = document.getElementById('replay-evt-' + idx);
    if (el) {
      el.classList.add('active');
      el.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }

  function onSliderChange() {
    const val = parseInt($('#replay-slider')?.value) || 0;
    currentIdx = val;
    highlightEvent(val);
    const statusEl = $('#replay-status');
    if (statusEl) statusEl.textContent = `Event ${val + 1} / ${events.length}`;
  }

  async function clearLog() {
    if (!confirm('Clear all replay events?')) return;
    try {
      await api(`/rooms/${state.roomPin}/replay`, { method: 'DELETE' });
      events = [];
      currentIdx = -1;
      renderEventLog();
      showToast('🗑️ Replay log cleared');
    } catch (e) {
      showToast('❌ ' + e.message, 'error');
    }
  }

  return { init, loadEvents };
})();

