const InGameChat = (() => {
  const PLAYER_COLORS = ['#ef4444','#3b82f6','#10b981','#f59e0b','#8b5cf6','#ec4899','#06b6d4','#f97316'];
  let _colorMap = {};
  let _unread = 0;
  let _currentTab = null;

  function getColor(name) {
    if (!_colorMap[name]) {
      const idx = Object.keys(_colorMap).length % PLAYER_COLORS.length;
      _colorMap[name] = PLAYER_COLORS[idx];
    }
    return _colorMap[name];
  }

  function init() {
    $('#chat-send-btn')?.addEventListener('click', sendMessage);
    $('#chat-input')?.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') { e.preventDefault(); sendMessage(); }
    });
  }

  function sendMessage() {
    if (state.isSpectator) return;
    const input = $('#chat-input');
    const text = input?.value.trim();
    if (!text) return;
    input.value = '';
    sendWS({
      type: 'chat_message',
      data: { sender: state.playerName, text, timestamp: Date.now(), isDM: state.isDM }
    });
  }

  function receiveMessage(data) {
    if (!data) return;
    const container = $('#chat-messages');
    if (!container) return;
    // Remove empty placeholder
    const empty = container.querySelector('.chat-empty');
    if (empty) empty.remove();

    const isSelf = data.sender === state.playerName;
    const isSystem = data.isSystem;
    const isDM = data.isDM;

    const msgEl = document.createElement('div');
    let cls = 'chat-msg ';
    if (isSystem) cls += 'chat-msg-system';
    else if (isSelf) cls += 'chat-msg-self';
    else if (isDM) cls += 'chat-msg-dm';
    else cls += 'chat-msg-player';
    msgEl.className = cls;

    const senderColor = isDM ? '#d4af37' : (isSystem ? '#9CA3AF' : getColor(data.sender));
    const timeStr = data.timestamp ? new Date(data.timestamp).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '';

    if (isSystem) {
      msgEl.innerHTML = `<span class="chat-msg-text">${escapeHtml(data.text)}</span>`;
    } else {
      msgEl.innerHTML = `
        <div class="chat-msg-header">
          <span class="chat-msg-sender" style="color:${senderColor}">${escapeHtml(data.sender)}${isDM ? ' 🏰' : ''}</span>
          <span class="chat-msg-time">${timeStr}</span>
        </div>
        <div class="chat-msg-text">${escapeHtml(data.text)}</div>
      `;
    }
    container.appendChild(msgEl);
    container.scrollTop = container.scrollHeight;

    // Unread badge logic
    const activeTab = document.querySelector('.tab-content.active');
    if (!activeTab || activeTab.id !== 'tab-chat') {
      _unread++;
      const badge = $('#chat-unread-badge');
      if (badge) { badge.textContent = _unread; show(badge); }
    }
  }

  async function loadHistory() {
    if (!state.roomPin || state.roomPin === 'SOLO') return;
    try {
      const messages = await api(`/rooms/${state.roomPin}/chat`);
      if (messages && messages.length) {
        messages.forEach(m => receiveMessage(m));
        _unread = 0;
        const badge = $('#chat-unread-badge');
        if (badge) hide(badge);
      }
    } catch (e) { /* endpoint may not exist yet */ }
  }

  function clearUnread() {
    _unread = 0;
    const badge = $('#chat-unread-badge');
    if (badge) hide(badge);
  }

  return { init, sendMessage, receiveMessage, loadHistory, clearUnread };
})();

// Clear chat unread when switching to chat tab
const _origSwitchTab = switchTab;
switchTab = function(tab) {
  _origSwitchTab(tab);
  if (tab === 'chat') InGameChat.clearUnread();
};

