function initSpectatorLogin() {
  $('#show-spectate-btn')?.addEventListener('click', () => {
    $$('.login-panel').forEach(p => p.classList.remove('active'));
    $('#spectate-panel').classList.add('active');
  });
  $('#back-from-spectate-btn')?.addEventListener('click', () => {
    $$('.login-panel').forEach(p => p.classList.remove('active'));
    $('#pin-login-panel').classList.add('active');
  });
  $('#spectate-enter-btn')?.addEventListener('click', enterAsSpectator);
  $('#spectate-pin')?.addEventListener('keydown', e => { if (e.key === 'Enter') enterAsSpectator(); });
}

async function enterAsSpectator() {
  const pin = ($('#spectate-pin')?.value || '').trim();
  if (!pin || pin.length !== 6) return showError('Enter a valid 6-digit room PIN');
  try {
    // Validate room exists
    await api(`/rooms/${pin}`);
    state.roomPin = pin;
    state.playerId = 'spectator-' + Date.now();
    state.playerName = 'Spectator';
    state.isDM = false;
    state.isSpectator = true;
    saveSession();
    enterApp();
  } catch (e) { showError('Room not found: ' + e.message); }
}

