const RulesLawyer = (() => {
  const CACHE_KEY = 'dnd-rules-cache';

  function init() {
    $('#rules-lawyer-btn')?.addEventListener('click', () => { show('#rules-lawyer-modal'); renderRecent(); });
    $('#rules-modal-close')?.addEventListener('click', () => hide('#rules-lawyer-modal'));
    $('#rules-lawyer-modal')?.addEventListener('click', (e) => { if (e.target.id === 'rules-lawyer-modal') hide('#rules-lawyer-modal'); });
    $('#rules-ask-btn')?.addEventListener('click', askQuestion);
    $('#rules-question-input')?.addEventListener('keydown', (e) => { if (e.key === 'Enter') { e.preventDefault(); askQuestion(); } });
    $$('.rules-quick-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        $('#rules-question-input').value = btn.dataset.q;
        askQuestion();
      });
    });
  }

  function getCache() {
    try { return JSON.parse(localStorage.getItem(CACHE_KEY)) || []; } catch { return []; }
  }
  function saveCache(items) {
    localStorage.setItem(CACHE_KEY, JSON.stringify(items.slice(0, 10)));
  }

  async function askQuestion() {
    const input = $('#rules-question-input');
    const question = input?.value.trim();
    if (!question) return;
    const btn = $('#rules-ask-btn');
    const card = $('#rules-answer-card');
    btn.disabled = true;
    btn.textContent = '⏳ Looking up...';
    card.textContent = '📜 Consulting the rulebooks...';
    card.className = 'rules-answer-card';
    show(card);

    // Check cache first
    const cached = getCache();
    const hit = cached.find(c => c.q.toLowerCase() === question.toLowerCase());
    if (hit) {
      card.textContent = hit.a;
      btn.disabled = false;
      btn.textContent = '📜 Ask the Rules Lawyer';
      return;
    }

    try {
      const result = await api('/rules/ask', { method:'POST', body:{ question } });
      const answer = result.answer || 'No answer available.';
      card.textContent = answer;
      // Save to cache
      cached.unshift({ q: question, a: answer, t: Date.now() });
      saveCache(cached);
      renderRecent();
    } catch (e) {
      card.textContent = '❌ ' + e.message;
      card.className = 'rules-answer-card ai-error';
    } finally {
      btn.disabled = false;
      btn.textContent = '📜 Ask the Rules Lawyer';
    }
  }

  function renderRecent() {
    const container = $('#rules-recent');
    if (!container) return;
    const cached = getCache();
    if (!cached.length) { container.innerHTML = ''; return; }
    container.innerHTML = '<h4>Recent Questions</h4>';
    cached.forEach(item => {
      const div = document.createElement('div');
      div.className = 'rules-recent-item';
      div.innerHTML = `<span class="rr-q">${escapeHtml(item.q)}</span>`;
      div.addEventListener('click', () => {
        $('#rules-question-input').value = item.q;
        $('#rules-answer-card').textContent = item.a;
        show('#rules-answer-card');
      });
      container.appendChild(div);
    });
  }

  return { init };
})();

