const QuestGenerator = (() => {
  function init() {
    $('#quest-gen-open-btn')?.addEventListener('click', () => show('#quest-gen-modal'));
    $('#quest-gen-close')?.addEventListener('click', () => hide('#quest-gen-modal'));
    $('#quest-gen-cancel')?.addEventListener('click', () => hide('#quest-gen-modal'));
    $('#quest-gen-modal')?.addEventListener('click', (e) => { if (e.target.id === 'quest-gen-modal') hide('#quest-gen-modal'); });
    $('#quest-gen-btn')?.addEventListener('click', generate);
  }

  async function generate() {
    const setting = $('#quest-setting')?.value.trim();
    if (!setting) return alert('Enter a setting/location description');
    const difficulty = $('#quest-difficulty')?.value || 'Medium';
    const partyLevel = parseInt($('#quest-party-level')?.value) || 3;
    const theme = $('#quest-theme')?.value || 'Mixed';
    const extras = $('#quest-extras')?.value.trim() || '';

    const btn = $('#quest-gen-btn');
    const status = $('#quest-gen-status');
    btn.disabled = true;
    btn.textContent = '⏳ Generating...';
    status.textContent = '🗺️ The quest master is crafting your adventure...';
    status.className = 'ai-status';
    show(status);

    try {
      const result = await api('/quests/generate', { method:'POST', body:{ setting, difficulty, partyLevel, theme, extras } });
      hide(status);
      renderQuestCard(result);
    } catch (e) {
      status.textContent = '❌ ' + e.message;
      status.className = 'ai-status ai-error';
    } finally {
      btn.disabled = false;
      btn.textContent = '🗺️ Generate Quest';
    }
  }

  function renderQuestCard(q) {
    const card = $('#quest-result-card');
    let html = `<h2>📜 ${escapeHtml(q.title || 'Untitled Quest')}</h2>`;
    if (q.hook) html += `<p><em>${escapeHtml(q.hook)}</em></p>`;
    if (q.objectives && q.objectives.length) {
      html += `<h3>🎯 Objectives</h3><ul>${q.objectives.map(o => `<li>${escapeHtml(o)}</li>`).join('')}</ul>`;
    }
    if (q.encounters && q.encounters.length) {
      html += `<h3>⚔️ Encounters</h3><ul>${q.encounters.map(e => `<li><strong>${escapeHtml(e.name)}</strong> (CR ${e.cr || '?'}) — ${escapeHtml(e.description || '')}</li>`).join('')}</ul>`;
    }
    if (q.npcs && q.npcs.length) {
      html += `<h3>👥 NPCs</h3><ul>${q.npcs.map(n => `<li><strong>${escapeHtml(n.name)}</strong> — ${escapeHtml(n.role || '')}. ${escapeHtml(n.motivation || '')}</li>`).join('')}</ul>`;
    }
    if (q.rewards && q.rewards.length) {
      html += `<h3>💰 Rewards</h3><ul>${q.rewards.map(r => `<li>${escapeHtml(r)}</li>`).join('')}</ul>`;
    }
    if (q.twists && q.twists.length) {
      html += `<h3>🔄 Twists</h3><ul>${q.twists.map(t => `<li>${escapeHtml(t)}</li>`).join('')}</ul>`;
    }
    if (q.estimatedSessions) html += `<p><strong>Estimated Sessions:</strong> ${q.estimatedSessions}</p>`;
    html += `<div class="quest-actions">
      <button class="btn-sm btn-gold" id="quest-save-wiki">📖 Save to Wiki</button>
      <button class="btn-sm btn-gold" id="quest-add-encounters">⚔️ Add Encounters</button>
      <button class="btn-sm" id="quest-copy-notes">📋 Copy to Notes</button>
    </div>`;
    card.innerHTML = html;
    show(card);

    // Save to wiki
    card.querySelector('#quest-save-wiki')?.addEventListener('click', async () => {
      try {
        let wikiContent = `# ${q.title || 'Quest'}\n\n*${q.hook || ''}*\n\n`;
        if (q.objectives) wikiContent += `## Objectives\n${q.objectives.map(o => `- ${o}`).join('\n')}\n\n`;
        if (q.npcs) wikiContent += `## NPCs\n${q.npcs.map(n => `- **${n.name}** — ${n.role || ''}. ${n.motivation || ''}`).join('\n')}\n\n`;
        if (q.rewards) wikiContent += `## Rewards\n${q.rewards.map(r => `- ${r}`).join('\n')}\n`;
        await api(`/rooms/${state.roomPin}/wiki`, { method:'POST', body:{ title: q.title || 'Generated Quest', category:'quest', content: wikiContent, tags:['quest','generated'], published:false } });
        showToast('📖 Quest saved to Wiki!');
      } catch (e) { showToast('❌ ' + e.message, 'error'); }
    });

    // Add encounters to encounter builder
    card.querySelector('#quest-add-encounters')?.addEventListener('click', () => {
      if (q.encounters && q.encounters.length) {
        q.encounters.forEach(enc => {
          state.initiative.combatants.push({
            id: Date.now().toString(36) + Math.random().toString(36).slice(2,6),
            name: enc.name || 'Enemy',
            initiative: Math.floor(Math.random()*20)+1,
            maxHP: parseInt(enc.hp) || 20,
            currentHP: parseInt(enc.hp) || 20,
            type:'monster', conditions:[], active:false
          });
        });
        sortInitiative();
        broadcastInitiative();
        showToast('⚔️ Encounters added to initiative!');
      }
    });

    // Copy to notes
    card.querySelector('#quest-copy-notes')?.addEventListener('click', () => {
      const notesEl = $('#session-notes');
      if (notesEl) {
        let txt = `\n\n--- QUEST: ${q.title || 'Generated'} ---\n${q.hook || ''}\n`;
        if (q.objectives) txt += `Objectives: ${q.objectives.join(', ')}\n`;
        notesEl.value += txt;
        showToast('📋 Copied to session notes!');
      }
    });
  }

  return { init };
})();

