  async function generate() {
    const difficulty = $('#trap-difficulty')?.value || 'Medium';
    const type = $('#trap-type')?.value || 'Trap';
    const theme = $('#trap-theme')?.value.trim() || '';

    const btn = $('#trap-gen-btn');
    const status = $('#trap-gen-status');
    btn.disabled = true;
    btn.textContent = '⏳ Generating...';
    status.textContent = '⚠️ Crafting a devious trap...';
    status.className = 'ai-status';
    show(status);

    try {
      const result = await api('/traps/generate', { method:'POST', body:{ difficulty, type, theme } });
      hide(status);
      renderTrapCard(result);
    } catch (e) {
      status.textContent = '❌ ' + e.message;
      status.className = 'ai-status ai-error';
    } finally {
      btn.disabled = false;
      btn.textContent = '⚠️ Generate';
    }
  }

  function renderTrapCard(t) {
    const card = $('#trap-result-card');
    let html = `<h2>⚠️ ${escapeHtml(t.name || 'Unknown Trap')}</h2>`;
    if (t.description) html += `<p>${escapeHtml(t.description)}</p>`;
    if (t.trigger) html += `<h3>🎯 Trigger</h3><p>${escapeHtml(t.trigger)}</p>`;
    if (t.effect) html += `<h3>💥 Effect</h3><p>${escapeHtml(t.effect)}</p>`;
    if (t.dc) html += `<p><strong>DC:</strong> ${t.dc}</p>`;
    if (t.damage) html += `<p><strong>Damage:</strong> ${escapeHtml(t.damage)}</p>`;
    if (t.solution) html += `<h3>🔓 Solution</h3><p>${escapeHtml(t.solution)}</p>`;
    if (t.hints && t.hints.length) {
      html += `<h3>💡 Hints</h3><ul>${t.hints.map(h => `<li>${escapeHtml(h)}</li>`).join('')}</ul>`;
