    html += `<div class="trap-actions"><button class="btn-sm btn-gold" id="trap-copy-notes">📋 Copy to Notes</button></div>`;
    card.innerHTML = html;
    show(card);

    card.querySelector('#trap-copy-notes')?.addEventListener('click', () => {
      const notesEl = $('#session-notes');
      if (notesEl) {
        let txt = `\n\n--- ${(t.name || 'TRAP').toUpperCase()} ---\n`;
        txt += `${t.description || ''}\nTrigger: ${t.trigger || '?'}\nEffect: ${t.effect || '?'}\nDC: ${t.dc || '?'}\nDamage: ${t.damage || 'N/A'}\nSolution: ${t.solution || '?'}\n`;
        if (t.hints) txt += `Hints: ${t.hints.join('; ')}\n`;
        if (t.dmNotes) txt += `DM Notes: ${t.dmNotes}\n`;
        notesEl.value += txt;
        showToast('📋 Copied to session notes!');
      }
    });
  }

  return { init };
})();

