async function validateAndEnter() {
  try {
    if (state.isSpectator) {
      // Validate room exists
      await api(`/rooms/${state.roomPin}`);
      enterApp();
    } else if (state.isDM) {
      // Validate DM PIN
      const data = await api('/auth/dm', { method:'POST', body:{ pin: state.roomPin } });
      state.playerName = data.dmName;
      state.playerId = data.dmId;
      state.managedPlayers = data.players || [];
      enterApp();
    } else if (state.playerPin) {
      // Validate Player PIN
      const data = await api('/auth/player', { method:'POST', body:{ pin: state.playerPin } });
      state.roomPin = data.roomPin;
      state.playerId = data.playerId;
      state.playerName = data.playerName;
      enterApp();
    } else {
      // No playerPin stored — can't validate, just try to enter
      enterApp();
    }
  } catch (e) {
    // Session invalid, clear and show login
    console.warn('Session validation failed:', e.message);
    clearSession();
  }
}

