const ThemeToggle = (() => {
  const STORAGE_KEY = 'dnd-theme';

  function init() {
    // Restore saved theme
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved === 'light') {
      document.documentElement.setAttribute('data-theme', 'light');
    }
    updateButton();

    $('#theme-toggle-btn')?.addEventListener('click', toggle);
  }

  function toggle() {
    const current = document.documentElement.getAttribute('data-theme');
    const next = current === 'light' ? 'dark' : 'light';
    document.documentElement.setAttribute('data-theme', next);
    localStorage.setItem(STORAGE_KEY, next);
    updateButton();
  }

  function updateButton() {
    const btn = $('#theme-toggle-btn');
    if (!btn) return;
    const isLight = document.documentElement.getAttribute('data-theme') === 'light';
    btn.textContent = isLight ? '☀️ Light' : '🌙 Dark';
    btn.title = isLight ? 'Switch to Dark Theme' : 'Switch to Light Theme';
  }

  return { init };
})();

// ============================================================
// RPG-STYLE COMBAT ARENA (DM Only)
// ============================================================

const Arena = (() => {
  // Monster icon mapping
  const MONSTER_ICONS = {
    beast: '🐺', undead: '💀', humanoid: '👤', dragon: '🐉',
    fiend: '😈', aberration: '👁️', giant: '🗿', monstrosity: '🐲',
    elemental: '🔥', ooze: '🟢', construct: '🤖', celestial: '👼',
    fey: '🧚', plant: '🌿', default: '👾'
  };

  const CLASS_ICONS = {
    Barbarian: '🪓', Bard: '🎵', Cleric: '✝️', Druid: '🌿',
    Fighter: '⚔️', Monk: '👊', Paladin: '🛡️', Ranger: '🏹',
    Rogue: '🗡️', Sorcerer: '✨', Warlock: '🔮', Wizard: '🧙'
  };

  // Basic spell list for combat
  const COMBAT_SPELLS = {
    Wizard: [
      { name: 'Fire Bolt', level: 0, damage: '1d10', type: 'fire', save: null, attack: true, range: 120 },
      { name: 'Magic Missile', level: 1, damage: '3d4+3', type: 'force', save: null, attack: false, autoHit: true },
      { name: 'Burning Hands', level: 1, damage: '3d6', type: 'fire', save: 'DEX', aoe: true },
      { name: 'Scorching Ray', level: 2, damage: '2d6', type: 'fire', save: null, attack: true, rays: 3 },
    ],
    Sorcerer: [
      { name: 'Fire Bolt', level: 0, damage: '1d10', type: 'fire', attack: true },
      { name: 'Chaos Bolt', level: 1, damage: '2d8+1d6', type: 'varies', attack: true },
      { name: 'Burning Hands', level: 1, damage: '3d6', type: 'fire', save: 'DEX', aoe: true },
    ],
    Cleric: [
      { name: 'Sacred Flame', level: 0, damage: '1d8', type: 'radiant', save: 'DEX' },
      { name: 'Guiding Bolt', level: 1, damage: '4d6', type: 'radiant', attack: true },
      { name: 'Cure Wounds', level: 1, damage: '1d8', type: 'healing', heal: true },
      { name: 'Inflict Wounds', level: 1, damage: '3d10', type: 'necrotic', attack: true, melee: true },
    ],
    Bard: [
      { name: 'Vicious Mockery', level: 0, damage: '1d4', type: 'psychic', save: 'WIS' },
      { name: 'Thunderwave', level: 1, damage: '2d8', type: 'thunder', save: 'CON', aoe: true },
      { name: 'Healing Word', level: 1, damage: '1d4', type: 'healing', heal: true },
    ],
    Druid: [
      { name: 'Produce Flame', level: 0, damage: '1d8', type: 'fire', attack: true },
      { name: 'Thunderwave', level: 1, damage: '2d8', type: 'thunder', save: 'CON', aoe: true },
      { name: 'Cure Wounds', level: 1, damage: '1d8', type: 'healing', heal: true },
    ],
    Warlock: [
      { name: 'Eldritch Blast', level: 0, damage: '1d10', type: 'force', attack: true },
      { name: 'Hex', level: 1, damage: '1d6', type: 'necrotic', bonus: true },
      { name: 'Hellish Rebuke', level: 1, damage: '2d10', type: 'fire', save: 'DEX' },
    ],
    Paladin: [
      { name: 'Divine Smite', level: 1, damage: '2d8', type: 'radiant', smite: true },
      { name: 'Cure Wounds', level: 1, damage: '1d8', type: 'healing', heal: true },
    ],
    Ranger: [
      { name: "Hunter's Mark", level: 1, damage: '1d6', type: 'force', bonus: true },
      { name: 'Cure Wounds', level: 1, damage: '1d8', type: 'healing', heal: true },
    ],
  };

  let arenaState = {
    phase: 'setup', // setup | combat | result
    party: [],  // { id, name, className, level, hp, maxHp, ac, str, dex, con, int, wis, cha, initiative, isDefending, isDead }
    monsters: [], // similar shape
    turnOrder: [], // combined & sorted
    currentTurn: 0,
    roundNumber: 1,
    combatLog: [],
    selectedAction: null,
    bestiaryCache: [],
    totalXpGained: 0,
  };

  function init() {
    $('#arena-monster-search')?.addEventListener('input', searchMonsters);
    $('#arena-start-btn')?.addEventListener('click', startBattle);
    $('#arena-back-setup-btn')?.addEventListener('click', backToSetup);
    $('#arena-new-battle-btn')?.addEventListener('click', backToSetup);
    $('#arena-target-cancel')?.addEventListener('click', () => { hide('#arena-target-select'); arenaState.selectedAction = null; });
    $('#arena-spell-cancel')?.addEventListener('click', () => { hide('#arena-spell-select'); arenaState.selectedAction = null; });

    $$('.arena-action-btn').forEach(btn => {
      btn.addEventListener('click', () => handleAction(btn.dataset.action));
    });
  }

  function activate() {
    loadPartyForArena();
  }

  async function loadPartyForArena() {
    if (!state.roomPin) return;
    try {
      const chars = await api(`/rooms/${state.roomPin}/characters`);
      const partyList = $('#arena-party-list');
      partyList.innerHTML = '';
      if (!chars.length) {
        partyList.innerHTML = '<p class="muted">No characters in room yet.</p>';
        return;
      }
      chars.forEach(c => {
        const cls = CLASSES.find(cl => cl.name === c.className);
        const hitDieMax = cls ? parseInt(cls.hitDie.replace('d', '')) : 8;
        const conMod = mod(c.abilityScores?.CON || 10);
        let maxHp = hitDieMax + conMod;
        if ((c.level || 1) > 1) maxHp += ((c.level || 1) - 1) * (Math.floor(hitDieMax / 2) + 1 + conMod);
        if (maxHp < 1) maxHp = 1;
        const ac = 10 + mod(c.abilityScores?.DEX || 10);
        const icon = CLASS_ICONS[c.className] || '⚔️';

        const card = document.createElement('div');
        card.className = 'arena-entity-card selected';
        card.dataset.charId = c.id;
        card.innerHTML = `
          <span class="entity-icon">${icon}</span>
          <div class="entity-info">
            <div class="entity-name">${escapeHtml(c.name)}</div>
            <div class="entity-meta">Lv.${c.level || 1} ${escapeHtml(c.className || '?')} ${escapeHtml(c.species || '')}</div>
          </div>
          <div class="entity-stats">
            <span>❤️${maxHp}</span>
            <span>🛡️${ac}</span>
          </div>
        `;
        card.addEventListener('click', () => card.classList.toggle('selected'));
        // Store data on the element
        card._charData = {
          id: c.id, name: c.name, className: c.className || 'Fighter', level: c.level || 1,
          hp: c.currentHP || maxHp, maxHp, ac,
          str: c.abilityScores?.STR || 10, dex: c.abilityScores?.DEX || 10,
          con: c.abilityScores?.CON || 10, int: c.abilityScores?.INT || 10,
          wis: c.abilityScores?.WIS || 10, cha: c.abilityScores?.CHA || 10,
          type: 'player', isDefending: false, isDead: false
        };
        partyList.appendChild(card);
      });
    } catch (e) { console.error('Load party for arena failed:', e); }
  }

  async function searchMonsters() {
    const q = ($('#arena-monster-search')?.value || '').toLowerCase().trim();
    const results = $('#arena-monster-results');
    if (!q || q.length < 2) { hide(results); return; }

    if (arenaState.bestiaryCache.length === 0) {
      try { arenaState.bestiaryCache = await api('/monsters'); } catch { return; }
    }

    const filtered = arenaState.bestiaryCache.filter(m => m.name.toLowerCase().includes(q)).slice(0, 10);
    if (!filtered.length) { hide(results); return; }

    results.innerHTML = '';
    filtered.forEach(m => {
      const item = document.createElement('div');
      item.className = 'arena-monster-result-item';
      item.innerHTML = `<span>${escapeHtml(m.name)}</span><span style="color:var(--gold)">CR ${m.cr}</span>`;
      item.addEventListener('click', () => {
        addMonsterToArena(m);
        hide(results);
        $('#arena-monster-search').value = '';
      });
      results.appendChild(item);
    });
    show(results);
  }

  function addMonsterToArena(m) {
    // Check if already added (increment qty)
    const existing = arenaState.monsters.find(x => x.templateName === m.name);
    if (existing) {
      existing.qty = (existing.qty || 1) + 1;
    } else {
      const typeKey = (m.type || 'default').toLowerCase();
      arenaState.monsters.push({
        templateName: m.name, name: m.name, type: m.type || 'monstrosity',
        icon: MONSTER_ICONS[typeKey] || MONSTER_ICONS.default,
        hp: m.hp || 10, maxHp: m.hp || 10, ac: m.ac || 10,
        str: m.str || 10, dex: m.dex || 10, con: m.con || 10,
        int: m.int || 10, wis: m.wis || 10, cha: m.cha || 10,
        cr: m.cr || '1', qty: 1, actions: m.actions || [],
        xp: crToXP(m.cr)
      });
    }
    renderMonsterSelection();
  }

  function crToXP(cr) {
    const map = {'0':10,'1/8':25,'1/4':50,'1/2':100,'1':200,'2':450,'3':700,'4':1100,'5':1800,'6':2300,'7':2900,'8':3900,'9':5000,'10':5900,'11':7200,'12':8400,'13':10000,'14':11500,'15':13000,'16':15000,'17':18000,'18':20000,'19':22000,'20':25000};
    return map[String(cr)] || 200;
  }

  function renderMonsterSelection() {
    const list = $('#arena-monster-selected');
    if (!arenaState.monsters.length) {
      list.innerHTML = '<p class="muted">No monsters selected.</p>';
      return;
    }
    list.innerHTML = '';
    arenaState.monsters.forEach((m, idx) => {
      const card = document.createElement('div');
      card.className = 'arena-entity-card';
      card.innerHTML = `
        <span class="entity-icon">${m.icon}</span>
        <div class="entity-info">
          <div class="entity-name">${escapeHtml(m.name)}</div>
          <div class="entity-meta">CR ${m.cr} | HP ${m.hp} | AC ${m.ac}</div>
        </div>
        <div class="entity-qty">
          <button data-idx="${idx}" data-dir="-1">−</button>
          <span>${m.qty}</span>
          <button data-idx="${idx}" data-dir="1">+</button>
        </div>
      `;
      card.querySelectorAll('.entity-qty button').forEach(btn => {
        btn.addEventListener('click', (e) => {
          e.stopPropagation();
          const i = parseInt(btn.dataset.idx);
          const dir = parseInt(btn.dataset.dir);
          arenaState.monsters[i].qty = Math.max(0, arenaState.monsters[i].qty + dir);
          if (arenaState.monsters[i].qty <= 0) arenaState.monsters.splice(i, 1);
          renderMonsterSelection();
        });
      });
      list.appendChild(card);
    });
  }

  function startBattle() {
    // Gather selected party
    const partyCards = $$('#arena-party-list .arena-entity-card.selected');
    if (!partyCards.length) { showToast('Select at least one party member!', 'error'); return; }
    if (!arenaState.monsters.length) { showToast('Add at least one monster!', 'error'); return; }

    arenaState.party = [];
    partyCards.forEach(card => {
      const d = card._charData;
      if (d) {
        const pb = profBonus(d.level);
        const primaryAbility = CLASSES.find(c => c.name === d.className)?.primary || 'STR';
        const abilityMod = mod(d[primaryAbility.toLowerCase()] || d.str);
        arenaState.party.push({
          ...d, id: d.id + '-' + Date.now(),
          initiative: rollDie(20) + mod(d.dex),
          attackMod: pb + abilityMod,
          damageDie: getDamageDie(d.className),
          damageMod: abilityMod,
          spellDC: 8 + pb + mod(getSpellAbilityScore(d)),
          spellAttackMod: pb + mod(getSpellAbilityScore(d)),
          pb,
          isDefending: false, isDead: false
        });
      }
    });

    // Expand monsters by qty
    arenaState.turnOrder = [];
    let monsterIdx = 1;
    arenaState.monsters.forEach(template => {
      for (let i = 0; i < template.qty; i++) {
        const dexMod = mod(template.dex);
        const monsterName = template.qty > 1 ? `${template.name} #${monsterIdx}` : template.name;
        arenaState.turnOrder.push({
          id: 'mon-' + Date.now() + '-' + monsterIdx,
          name: monsterName, type: 'monster', icon: template.icon,
          hp: template.maxHp, maxHp: template.maxHp, ac: template.ac,
          str: template.str, dex: template.dex, con: template.con,
          int: template.int, wis: template.wis, cha: template.cha,
          cr: template.cr, xp: template.xp,
          initiative: rollDie(20) + dexMod,
          attackMod: Math.max(2, mod(Math.max(template.str, template.dex)) + 2),
          damageDie: getMonsterDamageDie(template.cr),
          damageMod: mod(Math.max(template.str, template.dex)),
          isDefending: false, isDead: false, actions: template.actions || []
        });
        monsterIdx++;
      }
    });

    // Add party to turn order
    arenaState.party.forEach(p => arenaState.turnOrder.push(p));

    // Sort by initiative (highest first)
    arenaState.turnOrder.sort((a, b) => b.initiative - a.initiative);
    arenaState.currentTurn = 0;
    arenaState.roundNumber = 1;
    arenaState.combatLog = [];
    arenaState.phase = 'combat';
    arenaState.totalXpGained = 0;

    // Show combat UI
    hide('#arena-setup');
    show('#arena-combat');
    hide('#arena-result');
    show('#arena-back-setup-btn');

    addLog('⚔️ BATTLE BEGINS! Round 1', 'system');
    arenaState.turnOrder.forEach(c => addLog(`  ${c.name}: Initiative ${c.initiative}`, 'system'));

    renderBattlefield();
    processTurn();
  }

  function getDamageDie(className) {
    const map = { Barbarian:'1d12', Fighter:'1d10', Paladin:'1d10', Ranger:'1d8', Rogue:'1d8', Monk:'1d6', Bard:'1d8', Cleric:'1d8', Druid:'1d8', Sorcerer:'1d6', Warlock:'1d8', Wizard:'1d6' };
    return map[className] || '1d8';
  }

  function getMonsterDamageDie(cr) {
    const n = parseFloat(cr) || 0;
    if (n <= 0.5) return '1d6';
    if (n <= 2) return '1d8';
    if (n <= 5) return '2d6';
    if (n <= 10) return '2d8';
    if (n <= 15) return '2d10';
    return '2d12';
  }

  function getSpellAbilityScore(charData) {
    const cls = CLASSES.find(c => c.name === charData.className);
    if (!cls || !cls.spellAbility) return charData.int || 10;
    const ab = cls.spellAbility;
    return charData[ab.toLowerCase()] || 10;
  }

  function renderBattlefield() {
    const monstersEl = $('#arena-monsters-side');
    const partyEl = $('#arena-party-side');
    monstersEl.innerHTML = '';
    partyEl.innerHTML = '';

    arenaState.turnOrder.forEach(c => {
      const card = createCombatantCard(c);
      if (c.type === 'monster') {
        monstersEl.appendChild(card);
      } else {
        partyEl.appendChild(card);
      }
    });
  }

  function createCombatantCard(c) {
    const hpPct = Math.max(0, (c.hp / c.maxHp) * 100);
    const hpColor = hpPct > 50 ? '#10b981' : hpPct > 25 ? '#f59e0b' : '#ef4444';
    const isActive = arenaState.turnOrder[arenaState.currentTurn]?.id === c.id;
    const icon = c.type === 'monster' ? (c.icon || '👾') : (CLASS_ICONS[c.className] || '⚔️');

    const card = document.createElement('div');
    card.className = `arena-combatant ${c.type === 'monster' ? 'monster-type' : 'player-type'} ${isActive ? 'active-combatant' : ''} ${c.isDead ? 'dead' : ''} ${c.isDefending ? 'defending' : ''}`;
    card.id = 'arena-card-' + c.id;
    card.innerHTML = `
      <span class="combatant-init">${c.initiative}</span>
      <div class="combatant-icon">${icon}</div>
      <div class="combatant-name">${escapeHtml(c.name)}</div>
      <div class="combatant-class">${c.type === 'monster' ? 'CR ' + c.cr : 'Lv.' + c.level + ' ' + (c.className || '')}</div>
      <div class="combatant-hp-bar"><div class="combatant-hp-fill" style="width:${hpPct}%;background:${hpColor}"></div></div>
      <div class="combatant-hp-text">${Math.max(0, c.hp)}/${c.maxHp}</div>
      <div class="combatant-ac">AC ${c.ac}${c.isDefending ? ' (+2)' : ''}</div>
    `;
    return card;
  }

  function updateCombatantCard(c) {
    const el = document.getElementById('arena-card-' + c.id);
    if (!el) return;
    const hpPct = Math.max(0, (c.hp / c.maxHp) * 100);
    const hpColor = hpPct > 50 ? '#10b981' : hpPct > 25 ? '#f59e0b' : '#ef4444';
    const isActive = arenaState.turnOrder[arenaState.currentTurn]?.id === c.id;

    el.className = `arena-combatant ${c.type === 'monster' ? 'monster-type' : 'player-type'} ${isActive ? 'active-combatant' : ''} ${c.isDead ? 'dead' : ''} ${c.isDefending ? 'defending' : ''}`;
    el.querySelector('.combatant-hp-fill').style.width = hpPct + '%';
    el.querySelector('.combatant-hp-fill').style.background = hpColor;
    el.querySelector('.combatant-hp-text').textContent = `${Math.max(0, c.hp)}/${c.maxHp}`;
    el.querySelector('.combatant-ac').textContent = `AC ${c.ac}${c.isDefending ? ' (+2)' : ''}`;
  }

  function showFloatingNumber(targetId, text, type) {
    const el = document.getElementById('arena-card-' + targetId);
    if (!el) return;
    const floater = document.createElement('div');
    floater.className = `arena-float-number ${type}`;
    floater.textContent = text;
    floater.style.left = '50%';
    floater.style.top = '20%';
    floater.style.transform = 'translateX(-50%)';
    el.appendChild(floater);
    el.classList.add('arena-shake');
    if (type === 'damage' || type === 'crit') el.classList.add('arena-flash');
    setTimeout(() => { floater.remove(); el.classList.remove('arena-shake', 'arena-flash'); }, 1500);
  }

  function processTurn() {
    const current = arenaState.turnOrder[arenaState.currentTurn];
    if (!current || current.isDead) {
      advanceTurn();
      return;
    }

    // Update all cards to show active
    renderBattlefield();

    const turnNameEl = $('#arena-turn-name');
    turnNameEl.textContent = `${current.name}'s TURN (Round ${arenaState.roundNumber})`;

    if (current.type === 'monster') {
      // AI auto-action (after a short delay for dramatic effect)
      disableActions();
      setTimeout(() => monsterAI(current), 800);
    } else {
      // Player's turn — enable action buttons
      enableActions();
      const cls = CLASSES.find(c => c.name === current.className);
      // Show/hide spell button based on class
      const spellBtn = $$('.arena-action-btn[data-action="spell"]')[0];
      if (spellBtn) {
        spellBtn.style.display = (cls && cls.spellcaster) ? '' : 'none';
      }
    }
  }

  function enableActions() {
    $$('.arena-action-btn').forEach(btn => btn.disabled = false);
  }

  function disableActions() {
    $$('.arena-action-btn').forEach(btn => btn.disabled = true);
  }

  function handleAction(action) {
    const current = arenaState.turnOrder[arenaState.currentTurn];
    if (!current || current.isDead || current.type === 'monster') return;

    arenaState.selectedAction = action;

    switch (action) {
      case 'attack': {
        showTargetSelection(current, 'attack');
        break;
      }
      case 'spell': {
        showSpellSelection(current);
        break;
      }
      case 'defend': {
        current.isDefending = true;
        addLog(`🛡️ ${current.name} takes the Defend action! (AC +2 until next turn)`, 'defend');
        DiceSound.play();
        updateCombatantCard(current);
        setTimeout(() => advanceTurn(), 600);
        break;
      }
      case 'flee': {
        attemptFlee(current);
        break;
      }
    }
  }

  function showTargetSelection(attacker, actionType) {
    const targets = arenaState.turnOrder.filter(c => !c.isDead && c.type !== attacker.type);
    if (!targets.length) {
      addLog('No valid targets!', 'system');
      return;
    }

    const targetList = $('#arena-target-list');
    targetList.innerHTML = '';
    const prompt = $('#arena-target-prompt');
    prompt.textContent = actionType === 'attack' ? '⚔️ Select Target to Attack' : '🎯 Select Target';

    targets.forEach(t => {
      const btn = document.createElement('button');
      btn.className = 'arena-target-btn';
      const hpPct = Math.round((t.hp / t.maxHp) * 100);
      btn.innerHTML = `${t.icon || '👾'} ${escapeHtml(t.name)}<span class="target-hp">HP: ${t.hp}/${t.maxHp} (${hpPct}%) | AC ${t.ac}</span>`;
      btn.addEventListener('click', () => {
        hide('#arena-target-select');
        if (arenaState.selectedAction === 'attack') {
          resolveAttack(arenaState.turnOrder[arenaState.currentTurn], t);
        } else if (arenaState.selectedAction === 'spell-attack') {
          resolveSpellOnTarget(arenaState.turnOrder[arenaState.currentTurn], t, arenaState._pendingSpell);
        }
      });
      targetList.appendChild(btn);
    });
    show('#arena-target-select');
  }

  function showHealTargetSelection(caster, spell) {
    const targets = arenaState.turnOrder.filter(c => !c.isDead && c.type === caster.type && c.hp < c.maxHp);
    if (!targets.length) {
      addLog('No allies need healing!', 'system');
      return;
    }
    const targetList = $('#arena-target-list');
    targetList.innerHTML = '';
    $('#arena-target-prompt').textContent = '💚 Select Ally to Heal';
    targets.forEach(t => {
      const btn = document.createElement('button');
      btn.className = 'arena-target-btn';
      btn.innerHTML = `${CLASS_ICONS[t.className] || '⚔️'} ${escapeHtml(t.name)}<span class="target-hp">HP: ${t.hp}/${t.maxHp}</span>`;
      btn.addEventListener('click', () => {
        hide('#arena-target-select');
        resolveHeal(caster, t, spell);
      });
      targetList.appendChild(btn);
    });
    show('#arena-target-select');
  }

  function showSpellSelection(caster) {
    const cls = caster.className;
    const spells = COMBAT_SPELLS[cls] || COMBAT_SPELLS.Wizard;

    const spellList = $('#arena-spell-list');
    spellList.innerHTML = '';

    spells.forEach(spell => {
      const btn = document.createElement('button');
      btn.className = 'arena-spell-btn';
      const levelText = spell.level === 0 ? 'Cantrip' : `Lv.${spell.level}`;
      btn.innerHTML = `${spell.heal ? '💚' : '✨'} ${spell.name} (${levelText}) — ${spell.damage} ${spell.type}`;
      btn.addEventListener('click', () => {
        hide('#arena-spell-select');
        if (spell.heal) {
          showHealTargetSelection(caster, spell);
        } else if (spell.aoe) {
          resolveAOESpell(caster, spell);
        } else if (spell.autoHit) {
          // Like Magic Missile, select a target but auto-hit
          arenaState.selectedAction = 'spell-attack';
          arenaState._pendingSpell = spell;
          showTargetSelection(caster, 'spell');
        } else {
          arenaState.selectedAction = 'spell-attack';
          arenaState._pendingSpell = spell;
          showTargetSelection(caster, 'spell');
        }
      });
      spellList.appendChild(btn);
    });
    show('#arena-spell-select');
  }

  function resolveAttack(attacker, target) {
    disableActions();
    const d20 = rollDie(20);
    const effectiveAC = target.ac + (target.isDefending ? 2 : 0);
    const roll = d20 + attacker.attackMod;
    const isCrit = d20 === 20;
    const isFumble = d20 === 1;
    const isHit = isCrit || (!isFumble && roll >= effectiveAC);

    DiceSound.play();

    addLog(`⚔️ ${attacker.name} attacks ${target.name}!`, 'attack');
    addLog(`  Roll: ${d20} + ${attacker.attackMod} = ${roll} vs AC ${effectiveAC}`, isHit ? 'hit' : 'miss');

    if (isCrit) {
      addLog('  🌟 NATURAL 20 — CRITICAL HIT!', 'crit');
    } else if (isFumble) {
      addLog('  💀 NATURAL 1 — FUMBLE! Auto-miss!', 'miss');
    }

    if (isHit) {
      const parsed = parseDice(attacker.damageDie);
      let dmg = 0;
      if (parsed) {
        for (let i = 0; i < parsed.count * (isCrit ? 2 : 1); i++) dmg += rollDie(parsed.sides);
        dmg += attacker.damageMod;
      } else {
        dmg = rollDie(8) + attacker.damageMod;
      }
      dmg = Math.max(1, dmg);
      addLog(`  💥 Damage: ${dmg} ${isCrit ? '(CRIT!)' : ''}`, 'damage');
      applyDamage(target, dmg, isCrit);
    } else {
      showFloatingNumber(target.id, 'MISS', 'miss');
    }

    setTimeout(() => {
      if (!checkCombatEnd()) advanceTurn();
    }, 800);
  }

  function resolveSpellOnTarget(caster, target, spell) {
    disableActions();
    DiceSound.play();

    addLog(`✨ ${caster.name} casts ${spell.name} on ${target.name}!`, 'spell');

    if (spell.autoHit) {
      // Auto-hit like Magic Missile
      const parsed = parseDice(spell.damage);
      let dmg = 0;
      if (parsed) {
        for (let i = 0; i < parsed.count; i++) dmg += rollDie(parsed.sides);
        dmg += parsed.modifier;
      } else {
        dmg = rollDie(8) + 3;
      }
      dmg = Math.max(1, dmg);
      addLog(`  💫 ${spell.name} hits automatically for ${dmg} ${spell.type} damage!`, 'damage');
      applyDamage(target, dmg, false);
    } else if (spell.save) {
      // Saving throw spell
      const saveMod = mod(target[spell.save.toLowerCase()] || 10);
      const saveRoll = rollDie(20) + saveMod;
      const dc = caster.spellDC;
      addLog(`  ${target.name} rolls ${spell.save} save: ${saveRoll} vs DC ${dc}`, saveRoll >= dc ? 'miss' : 'hit');
      if (saveRoll < dc) {
        const parsed = parseDice(spell.damage);
        let dmg = 0;
        if (parsed) { for (let i = 0; i < parsed.count; i++) dmg += rollDie(parsed.sides); dmg += parsed.modifier; }
        else dmg = rollDie(8);
        dmg = Math.max(1, dmg);
        addLog(`  💥 ${dmg} ${spell.type} damage!`, 'damage');
        applyDamage(target, dmg, false);
      } else {
        addLog(`  ${target.name} saves!`, 'miss');
        showFloatingNumber(target.id, 'SAVED', 'miss');
      }
    } else if (spell.attack) {
      // Spell attack roll
      const d20 = rollDie(20);
      const effectiveAC = target.ac + (target.isDefending ? 2 : 0);
      const roll = d20 + caster.spellAttackMod;
      const isCrit = d20 === 20;
      const isHit = isCrit || (d20 !== 1 && roll >= effectiveAC);
      addLog(`  Spell attack: ${d20} + ${caster.spellAttackMod} = ${roll} vs AC ${effectiveAC} — ${isHit ? 'HIT!' : 'MISS'}`, isHit ? 'hit' : 'miss');
      if (isHit) {
        const parsed = parseDice(spell.damage);
        let dmg = 0;
        if (parsed) { for (let i = 0; i < parsed.count * (isCrit ? 2 : 1); i++) dmg += rollDie(parsed.sides); dmg += parsed.modifier; }
        else dmg = rollDie(10);
        dmg = Math.max(1, dmg);
        addLog(`  💥 ${dmg} ${spell.type} damage! ${isCrit ? '(CRIT!)' : ''}`, 'damage');
        applyDamage(target, dmg, isCrit);
      } else {
        showFloatingNumber(target.id, 'MISS', 'miss');
      }
    }

    setTimeout(() => {
      if (!checkCombatEnd()) advanceTurn();
    }, 800);
  }

  function resolveAOESpell(caster, spell) {
    disableActions();
    DiceSound.play();
    const targets = arenaState.turnOrder.filter(c => !c.isDead && c.type !== caster.type);
    addLog(`✨ ${caster.name} casts ${spell.name}! (AoE)`, 'spell');
    const dc = caster.spellDC;
    const parsed = parseDice(spell.damage);
    let baseDmg = 0;
    if (parsed) { for (let i = 0; i < parsed.count; i++) baseDmg += rollDie(parsed.sides); baseDmg += parsed.modifier; }
    else baseDmg = rollDie(8);
    baseDmg = Math.max(1, baseDmg);

    targets.forEach(t => {
      const saveMod = mod(t[spell.save ? spell.save.toLowerCase() : 'dex'] || 10);
      const saveRoll = rollDie(20) + saveMod;
      if (saveRoll >= dc) {
        const halfDmg = Math.floor(baseDmg / 2);
        addLog(`  ${t.name} saves (${saveRoll} vs DC ${dc}) — ${halfDmg} damage`, 'miss');
        applyDamage(t, halfDmg, false);
      } else {
        addLog(`  ${t.name} fails (${saveRoll} vs DC ${dc}) — ${baseDmg} damage!`, 'damage');
        applyDamage(t, baseDmg, false);
      }
    });

    setTimeout(() => {
      if (!checkCombatEnd()) advanceTurn();
    }, 1000);
  }

  function resolveHeal(caster, target, spell) {
    disableActions();
    DiceSound.play();
    const parsed = parseDice(spell.damage);
    let heal = 0;
    if (parsed) { for (let i = 0; i < parsed.count; i++) heal += rollDie(parsed.sides); heal += parsed.modifier; }
    else heal = rollDie(8);
    heal += mod(getSpellAbilityScore(caster));
    heal = Math.max(1, heal);

    const oldHp = target.hp;
    target.hp = Math.min(target.maxHp, target.hp + heal);
    const actualHeal = target.hp - oldHp;
    addLog(`💚 ${caster.name} casts ${spell.name} on ${target.name} for ${actualHeal} HP!`, 'heal');
    showFloatingNumber(target.id, '+' + actualHeal, 'heal');
    updateCombatantCard(target);

    setTimeout(() => advanceTurn(), 600);
  }

  function applyDamage(target, dmg, isCrit) {
    target.hp = Math.max(0, target.hp - dmg);
    showFloatingNumber(target.id, '-' + dmg, isCrit ? 'crit' : 'damage');
    updateCombatantCard(target);

    if (target.hp <= 0) {
      target.isDead = true;
      addLog(`💀 ${target.name} falls!`, 'death');
      if (target.type === 'monster') {
        arenaState.totalXpGained += (target.xp || 0);
      }
      setTimeout(() => updateCombatantCard(target), 300);
    }
  }

  function monsterAI(monster) {
    const aliveTargets = arenaState.turnOrder.filter(c => !c.isDead && c.type === 'player');
    if (!aliveTargets.length) { advanceTurn(); return; }

    // Pick a random target (slightly prefer low HP targets)
    const target = aliveTargets[Math.floor(Math.random() * aliveTargets.length)];
    resolveAttack(monster, target);
  }

  function attemptFlee(character) {
    disableActions();
    DiceSound.play();
    const d20 = rollDie(20);
    const fleeCheck = d20 + mod(character.dex);
    const dc = 12;
    addLog(`🏃 ${character.name} attempts to flee! Roll: ${d20} + ${mod(character.dex)} = ${fleeCheck} vs DC ${dc}`, 'flee');

    if (fleeCheck >= dc) {
      addLog(`  ${character.name} successfully flees!`, 'flee');
      character.isDead = true; // Remove from combat (fled)
      updateCombatantCard(character);
      setTimeout(() => {
        if (!checkCombatEnd()) advanceTurn();
      }, 600);
    } else {
      addLog(`  ${character.name} fails to escape!`, 'miss');
      setTimeout(() => advanceTurn(), 600);
    }
  }

  function advanceTurn() {
    // Clear defending status for the current combatant
    const current = arenaState.turnOrder[arenaState.currentTurn];
    if (current) current.isDefending = false;

    // Find next alive combatant
    let nextIdx = arenaState.currentTurn;
    let attempts = 0;
    do {
      nextIdx = (nextIdx + 1) % arenaState.turnOrder.length;
      attempts++;
      if (attempts > arenaState.turnOrder.length) break;

      // Check for new round
      if (nextIdx === 0) {
        arenaState.roundNumber++;
        addLog(`\n─── Round ${arenaState.roundNumber} ───`, 'system');
      }
    } while (arenaState.turnOrder[nextIdx].isDead);

    arenaState.currentTurn = nextIdx;

    if (!checkCombatEnd()) {
      processTurn();
    }
  }

  function checkCombatEnd() {
    const aliveMonsters = arenaState.turnOrder.filter(c => c.type === 'monster' && !c.isDead);
    const alivePlayers = arenaState.turnOrder.filter(c => c.type === 'player' && !c.isDead);

    if (aliveMonsters.length === 0) {
      showResult('victory');
      return true;
    }
    if (alivePlayers.length === 0) {
      showResult('defeat');
      return true;
    }
    return false;
  }

  function showResult(outcome) {
    arenaState.phase = 'result';
    hide('#arena-combat');
    show('#arena-result');

    const content = $('#arena-result-content');
    const totalRounds = arenaState.roundNumber;
    const monstersKilled = arenaState.turnOrder.filter(c => c.type === 'monster' && c.isDead).length;
    const playersDown = arenaState.turnOrder.filter(c => c.type === 'player' && c.isDead).length;
    const xp = arenaState.totalXpGained;
    const xpPerPlayer = arenaState.party.length > 0 ? Math.floor(xp / arenaState.party.length) : 0;

    if (outcome === 'victory') {
      // Generate loot
      const avgCR = arenaState.monsters.reduce((s, m) => s + (parseFloat(m.cr) || 1), 0) / arenaState.monsters.length;
      const loot = generateLoot(Math.round(avgCR), 'individual');

      let lootHtml = '';
      if (loot.currency.gold) lootHtml += `🟡 ${loot.currency.gold} GP `;
      if (loot.currency.silver) lootHtml += `⚪ ${loot.currency.silver} SP `;
      if (loot.currency.copper) lootHtml += `🟤 ${loot.currency.copper} CP `;
      if (loot.items.length) {
        lootHtml += '<br>' + loot.items.map(i => `${i.icon} <strong>${escapeHtml(i.name)}</strong> (${i.rarity})`).join('<br>');
      }

      content.innerHTML = `
        <div class="arena-result-victory">
          <h2>⚔️ VICTORY! ⚔️</h2>
          <div class="result-stats">
            <p>Rounds: <strong>${totalRounds}</strong></p>
            <p>Monsters Slain: <strong>${monstersKilled}</strong></p>
            <p>Party Members Down: <strong>${playersDown}</strong></p>
            <p>XP Gained: <strong>${xp}</strong> (${xpPerPlayer} per player)</p>
            ${lootHtml ? `<div class="loot-section"><h3 style="color:var(--gold)">🎁 Loot</h3><p>${lootHtml}</p></div>` : ''}
          </div>
        </div>
      `;
    } else {
      content.innerHTML = `
        <div class="arena-result-defeat">
          <h2>💀 DEFEAT 💀</h2>
          <div class="result-stats">
            <p>Rounds Survived: <strong>${totalRounds}</strong></p>
            <p>Monsters Remaining: <strong>${arenaState.turnOrder.filter(c => c.type === 'monster' && !c.isDead).length}</strong></p>
            <p>The party has fallen...</p>
          </div>
        </div>
      `;
    }
  }

  function backToSetup() {
    arenaState.phase = 'setup';
    arenaState.monsters = [];
    arenaState.party = [];
    arenaState.turnOrder = [];
    arenaState.combatLog = [];
    show('#arena-setup');
    hide('#arena-combat');
    hide('#arena-result');
    hide('#arena-back-setup-btn');
    renderMonsterSelection();
    loadPartyForArena();
  }

  function addLog(text, type) {
    type = type || 'system';
    arenaState.combatLog.push({ text, type });
    const logEl = $('#arena-combat-log');
    if (!logEl) return;
    const entry = document.createElement('div');
    entry.className = 'arena-log-entry log-' + type;
    entry.textContent = text;
    logEl.appendChild(entry);
    logEl.scrollTop = logEl.scrollHeight;
  }

  return { init, activate };
})();

// ============================================================
// FEATURE: PHB 2024 COMPENDIUM (5etools data, Indonesian translation support)
// ============================================================

const Compendium = (() => {
  let _currentCategory = 'spells';
  let _debounceTimer = null;
  let _lang = localStorage.getItem('dnd-compendium-lang') || 'id';
  let _translations = null;
  let _translationsLoaded = false;
  let _displayedCount = 0;
  let _currentData = [];

  const ITEMS_PER_PAGE = 50;

  // ---- i18n helpers ----
  function t(key, fallback) {
    if (_lang === 'en' || !_translations) return fallback || key;
    return _translations.ui?.[key] || fallback || key;
  }
  function tSpell(spellName, field) {
    if (_lang === 'en' || !_translations) return null;
    const key = spellName.toLowerCase().replace(/\s+/g, '-').replace(/'/g, '').replace(/[^\w-]/g, '');
    if (field === 'description') return _translations.spells?.[key] || null;
    if (field === 'higherLevels') return _translations.spell_higher_levels?.[key] || null;
    return null;
  }
  function tSpecies(name) {
    if (_lang === 'en' || !_translations) return null;
    const key = name.toLowerCase().replace(/\s+/g, '-');
    return _translations.species?.[key] || null;
  }
  function tCondition(name) {
    if (_lang === 'en' || !_translations) return null;
    const key = name.toLowerCase();
    return _translations.conditions?.[key] || null;
  }
  function tFeat(name) {
    if (_lang === 'en' || !_translations) return null;
    const key = name.toLowerCase().replace(/\s+/g, '-');
    return _translations.feats?.[key] || null;
  }
  function tMonster(name) {
    if (_lang === 'en' || !_translations) return null;
    const key = name.toLowerCase().replace(/\s+/g, '-');
    return _translations.monsters?.[key] || null;
  }
  function tBackground(name) {
    if (_lang === 'en' || !_translations) return null;
    const key = name.toLowerCase().replace(/\s+/g, '-');
    return _translations.backgrounds?.[key] || null;
  }
  function tEquipment(name) {
    if (_lang === 'en' || !_translations) return null;
    const key = name.toLowerCase().replace(/\s+/g, '-');
    return _translations.equipment?.[key] || null;
  }
  function tClassFeature(className, featureName) {
    if (_lang === 'en' || !_translations) return null;
    const key = className.toLowerCase() + '.' + featureName.toLowerCase().replace(/\s+/g, '-').replace(/'/g, '');
    return _translations.class_features?.[key] || null;
  }
  function tSubclassFeature(subclassName, featureName) {
    if (_lang === 'en' || !_translations) return null;
    const key = subclassName.toLowerCase() + '.' + featureName.toLowerCase().replace(/\s+/g, '-').replace(/'/g, '');
    return _translations.subclass_features?.[key] || null;
  }
  function tDesc(category, index) {
    if (_lang === 'en' || !_translations) return null;
    const catMap = { 'races': 'species', 'items': 'equipment' };
    const tCat = catMap[category] || category;
    return _translations[tCat]?.[index] || null;
  }
  function tSchool(schoolName) {
    if (_lang === 'en' || !_translations) return schoolName;
    return _translations.ui?.[(schoolName || '').toLowerCase()] || schoolName;
  }

  async function loadTranslations() {
    if (_translationsLoaded) return;
    try {
      _translations = await api('/srd/translations/id');
      _translationsLoaded = true;
    } catch (e) { console.warn('Failed to load translations:', e.message); }
  }

  function getLang() { return _lang; }
  function toggleLang() {
    _lang = _lang === 'id' ? 'en' : 'id';
    localStorage.setItem('dnd-compendium-lang', _lang);
    updateLangUI();
    updateAllLabels();
    fetchAndRender();
  }
  function updateLangUI() {
    const label = $('#comp-lang-label');
    const flag = $('#comp-lang-flag');
    if (label) label.textContent = _lang === 'id' ? 'ID' : 'EN';
    if (flag) flag.textContent = _lang === 'id' ? '🇮🇩' : '🇬🇧';
  }
  function updateAllLabels() {
    const isID = _lang === 'id';
    const title = $('#compendium-title');
    if (title) title.textContent = isID ? '📚 Kompendium PHB 2024' : '📚 PHB 2024 Compendium';

    const catLabels = {
      'spells':      { id: 'Mantra',       en: 'Spells' },
      'classes':     { id: 'Kelas',         en: 'Classes' },
      'races':       { id: 'Spesies',       en: 'Species' },
      'items':       { id: 'Peralatan',     en: 'Equipment' },
      'feats':       { id: 'Feat',          en: 'Feats' },
      'backgrounds': { id: 'Latar Belakang',en: 'Backgrounds' },
      'conditions':  { id: 'Kondisi',       en: 'Conditions' }
    };
    $$('.comp-cat-btn').forEach(btn => {
      const cat = btn.dataset.category;
      const span = btn.querySelector('[data-i18n]');
      if (span && catLabels[cat]) span.textContent = catLabels[cat][_lang] || catLabels[cat].en;
    });

    const searchInput = $('#compendium-search');
    if (searchInput) searchInput.placeholder = isID ? '🔍 Cari di kompendium...' : '🔍 Search the compendium...';
    buildFilters(_currentCategory);
  }

  function setCategory(cat) {
    _currentCategory = cat;
    $$('.comp-cat-btn').forEach(b => b.classList.toggle('active', b.dataset.category === cat));
    buildFilters(cat);
    fetchAndRender();
  }

  function buildFilters(cat) {
    const container = $('#compendium-filters');
    if (!container) return;
    container.innerHTML = '';
    const isID = _lang === 'id';

    if (cat === 'spells') {
      container.innerHTML = `
        <select id="comp-filter-level">
          <option value="">${isID ? 'Semua Level' : 'All Levels'}</option>
          <option value="0">Cantrip</option>
          ${[1,2,3,4,5,6,7,8,9].map(n => `<option value="${n}">Level ${n}</option>`).join('')}
        </select>
        <select id="comp-filter-school">
          <option value="">${isID ? 'Semua Aliran' : 'All Schools'}</option>
          <option value="abjuration">${isID ? 'Abjurasi' : 'Abjuration'}</option>
          <option value="conjuration">${isID ? 'Konjurasi' : 'Conjuration'}</option>
          <option value="divination">${isID ? 'Divinasi' : 'Divination'}</option>
          <option value="enchantment">${isID ? 'Pesona' : 'Enchantment'}</option>
          <option value="evocation">${isID ? 'Evokasi' : 'Evocation'}</option>
          <option value="illusion">${isID ? 'Ilusi' : 'Illusion'}</option>
          <option value="necromancy">${isID ? 'Nekromansi' : 'Necromancy'}</option>
          <option value="transmutation">${isID ? 'Transmutasi' : 'Transmutation'}</option>
        </select>
        <select id="comp-filter-class">
          <option value="">${isID ? 'Semua Kelas' : 'All Classes'}</option>
          <option value="Barbarian">Barbarian</option><option value="Bard">Bard</option>
          <option value="Cleric">Cleric</option><option value="Druid">Druid</option>
          <option value="Fighter">Fighter</option><option value="Monk">Monk</option>
          <option value="Paladin">Paladin</option><option value="Ranger">Ranger</option>
          <option value="Rogue">Rogue</option><option value="Sorcerer">Sorcerer</option>
          <option value="Warlock">Warlock</option><option value="Wizard">Wizard</option>
        </select>`;
    } else if (cat === 'items') {
      container.innerHTML = `
        <select id="comp-filter-itemtype">
          <option value="">${isID ? 'Semua Tipe' : 'All Types'}</option>
          <option value="Melee Weapon">${isID ? 'Senjata Jarak Dekat' : 'Melee Weapons'}</option>
          <option value="Ranged Weapon">${isID ? 'Senjata Jarak Jauh' : 'Ranged Weapons'}</option>
          <option value="Heavy Armor">${isID ? 'Armor Berat' : 'Heavy Armor'}</option>
          <option value="Medium Armor">${isID ? 'Armor Sedang' : 'Medium Armor'}</option>
          <option value="Light Armor">${isID ? 'Armor Ringan' : 'Light Armor'}</option>
          <option value="Shield">${isID ? 'Perisai' : 'Shield'}</option>
          <option value="Adventuring Gear">${isID ? 'Perlengkapan' : 'Adventuring Gear'}</option>
          <option value="Artisan Tool">${isID ? 'Alat Pengrajin' : "Artisan's Tools"}</option>
          <option value="Instrument">${isID ? 'Instrumen' : 'Instruments'}</option>
          <option value="Ammunition">${isID ? 'Amunisi' : 'Ammunition'}</option>
          <option value="Spellcasting Focus">${isID ? 'Fokus Mantra' : 'Spellcasting Focus'}</option>
        </select>`;
    } else if (cat === 'feats') {
      container.innerHTML = `
        <select id="comp-filter-featcat">
          <option value="">${isID ? 'Semua Kategori' : 'All Categories'}</option>
          <option value="General">General</option>
          <option value="Origin">Origin</option>
          <option value="Fighting Style">Fighting Style</option>
          <option value="Epic Boon">Epic Boon</option>
        </select>`;
    }

    container.querySelectorAll('select').forEach(sel => {
      sel.addEventListener('change', () => fetchAndRender());
    });
  }

  function buildQueryString() {
    const params = new URLSearchParams();
    const search = $('#compendium-search')?.value?.trim();
    if (search) params.set('search', search);

    if (_currentCategory === 'spells') {
      const lvl = $('#comp-filter-level')?.value;
      const sch = $('#comp-filter-school')?.value;
      const cls = $('#comp-filter-class')?.value;
      if (lvl !== undefined && lvl !== '') params.set('level', lvl);
      if (sch) params.set('school', sch);
      if (cls) params.set('className', cls);
    } else if (_currentCategory === 'items') {
      const itemType = $('#comp-filter-itemtype')?.value;
      if (itemType) params.set('type', itemType);
    }
    return params.toString();
  }

  async function fetchAndRender() {
    const container = $('#compendium-results');
    const countEl = $('#compendium-results-count');
    if (!container) return;

    const isID = _lang === 'id';
    container.innerHTML = `<div class="compendium-loading">${isID ? 'Memuat...' : 'Loading...'}</div>`;

    try {
      const qs = buildQueryString();
      let data = await api(`/srd/${_currentCategory}?${qs}`);

      // Client-side filter for feats category
      if (_currentCategory === 'feats') {
        const featCat = $('#comp-filter-featcat')?.value;
        if (featCat) data = data.filter(f => (f.category || '').toLowerCase() === featCat.toLowerCase());
      }

      _currentData = data;
      _displayedCount = 0;

      if (countEl) {
        const word = isID ? 'hasil' : (data.length !== 1 ? 'results' : 'result');
        countEl.textContent = `${data.length} ${word}`;
      }

      if (data.length === 0) {
        const msg = isID ? 'Tidak ada hasil ditemukan.' : 'No results found.';
        container.innerHTML = `<div class="compendium-empty"><div class="empty-icon">📜</div><p>${msg}</p></div>`;
        return;
      }

      container.innerHTML = '';
      loadMoreItems(container);
    } catch (err) {
      const msg = isID ? `Gagal memuat: ${err.message}` : `Failed to load: ${err.message}`;
      container.innerHTML = `<div class="compendium-empty"><div class="empty-icon">⚠️</div><p>${msg}</p></div>`;
    }
  }

  function loadMoreItems(container) {
    if (!container) container = $('#compendium-results');
    if (!container) return;

    // Remove existing load-more button
    const existing = container.querySelector('.comp-load-more');
    if (existing) existing.remove();

    const end = Math.min(_displayedCount + ITEMS_PER_PAGE, _currentData.length);
    for (let i = _displayedCount; i < end; i++) {
      const card = renderCard(_currentCategory, _currentData[i]);
      container.appendChild(card);
    }
    _displayedCount = end;

    if (_displayedCount < _currentData.length) {
      const isID = _lang === 'id';
      const btn = document.createElement('button');
      btn.className = 'comp-load-more';
      btn.textContent = isID
        ? `Muat ${Math.min(ITEMS_PER_PAGE, _currentData.length - _displayedCount)} lagi (${_displayedCount}/${_currentData.length})`
        : `Load ${Math.min(ITEMS_PER_PAGE, _currentData.length - _displayedCount)} more (${_displayedCount}/${_currentData.length})`;
      btn.addEventListener('click', () => loadMoreItems(container));
      container.appendChild(btn);
    }
  }

  // ---- Card Rendering ----
  function renderCard(category, item) {
    const card = document.createElement('div');
    card.className = 'comp-card';
    card.addEventListener('click', () => showDetail(category, item));

    if (category === 'spells') {
      const lvlText = item.level === 0 ? 'Cantrip' : `Lvl ${item.level}`;
      const school = _lang === 'id' ? tSchool(item.school) : item.school;
      const classes = (item.classes || []).join(', ');
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
          <span class="comp-card-badge">${lvlText}</span>
        </div>
        <div class="comp-card-meta">${escapeHtml(school)}${item.concentration ? ' · ⟐' : ''}${item.ritual ? ' · ®' : ''} · ${escapeHtml(classes || 'Various')}</div>
        <div class="comp-card-desc">${escapeHtml((item.description || '').slice(0, 120))}…</div>`;

    } else if (category === 'classes') {
      const scCount = (item.subclasses || []).length;
      const ftCount = (item.features || []).length;
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
          <span class="comp-card-badge">${item.hitDice || ''}</span>
        </div>
        <div class="comp-card-meta">Saves: ${(item.profSaves || []).join(', ')} · ${scCount} subclasses</div>
        <div class="comp-card-desc">${ftCount} features · ${item.casterProgression ? 'Spellcaster' : 'Non-caster'}</div>`;

    } else if (category === 'races') {
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
          <span class="comp-card-badge">Speed ${item.speed || 30}</span>
        </div>
        <div class="comp-card-meta">Size: ${item.size || 'Medium'}${item.darkvision ? ` · Darkvision ${item.darkvision} ft.` : ''}</div>
        <div class="comp-card-desc">${escapeHtml((item.entries || '').slice(0, 120))}…</div>`;

    } else if (category === 'items') {
      const costStr = item.value ? `${(item.value / 100).toFixed(item.value % 100 === 0 ? 0 : 2)} gp` : '';
      const weightStr = item.weight ? `${item.weight} lb` : '';
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
          <span class="comp-card-badge">${escapeHtml(costStr)}</span>
        </div>
        <div class="comp-card-meta">${escapeHtml(item.type || '')}${weightStr ? ` · ${weightStr}` : ''}${item.dmg1 ? ` · ${item.dmg1} ${item.dmgType}` : ''}</div>
        <div class="comp-card-desc">${escapeHtml((item.entries || '').slice(0, 100))}</div>`;

    } else if (category === 'feats') {
      const prereqs = (item.prerequisites || []).join(', ');
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
          <span class="comp-card-badge">${escapeHtml(item.category || 'General')}</span>
        </div>
        ${prereqs ? `<div class="comp-card-meta">Prerequisites: ${escapeHtml(prereqs)}</div>` : ''}
        <div class="comp-card-desc">${escapeHtml((item.entries || '').slice(0, 120))}…</div>`;

    } else if (category === 'backgrounds') {
      const skills = (item.skillProficiencies || []).join(', ');
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
        </div>
        <div class="comp-card-meta">${skills ? `Skills: ${escapeHtml(skills)}` : ''}</div>
        <div class="comp-card-desc">${escapeHtml((item.entries || '').slice(0, 120))}…</div>`;

    } else if (category === 'conditions') {
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name)}</div>
          <span class="comp-card-badge">${escapeHtml(item.type || 'condition')}</span>
        </div>

        <div class="comp-card-desc">${escapeHtml((item.entries || '').slice(0, 160))}</div>`;

    } else {
      card.innerHTML = `
        <div class="comp-card-header">
          <div class="comp-card-name">${escapeHtml(item.name || 'Unknown')}</div>
        </div>
        <div class="comp-card-desc">${escapeHtml((item.entries || item.description || '').toString().slice(0, 120))}</div>`;
    }
    return card;
  }

  // ---- Detail Rendering ----
  function showDetail(category, item) {
    const overlay = $('#compendium-detail-overlay');
    const content = $('#compendium-detail-content');
    if (!overlay || !content) return;

    let html = '';
    if (category === 'spells') html = renderSpellDetail(item);
    else if (category === 'classes') html = renderClassDetail(item);
    else if (category === 'races') html = renderRaceDetail(item);
    else if (category === 'items') html = renderItemDetail(item);
    else if (category === 'feats') html = renderFeatDetail(item);
    else if (category === 'backgrounds') html = renderBackgroundDetail(item);
    else if (category === 'conditions') html = renderConditionDetail(item);
    else html = renderGenericDetail(item);

    content.innerHTML = html;

    // Wire up collapsible features
    content.querySelectorAll('.class-feature-item').forEach(el => {
      el.addEventListener('click', () => el.classList.toggle('expanded'));
    });
    content.querySelectorAll('.subclass-group-header').forEach(el => {
      el.addEventListener('click', () => el.parentElement.classList.toggle('expanded'));
    });

    overlay.classList.remove('hidden');
  }

  function mod(score) {
    const m = Math.floor(((score || 10) - 10) / 2);
    return m >= 0 ? `+${m}` : `${m}`;
  }

  function formatDesc(text) {
    if (!text) return '';
    let html = escapeHtml(text);

    // Detect known sub-heading patterns and bold them
    // Lines that are short (< 40 chars), no period, followed by a newline + longer text
    html = html.replace(/^([A-Z][A-Za-z '\-]{2,38})$/gm, '<strong class="feature-subheading">$1</strong>');

    // Bullet points: lines starting with • or -
    html = html.replace(/^[•\-] (.+)$/gm, '<li>$1</li>');
    // Wrap consecutive <li> in <ul>
    html = html.replace(/((?:<li>.+<\/li>\n?)+)/g, '<ul class="feature-list">$1</ul>');

    // Double newlines = paragraph break
    html = html.replace(/\n\n/g, '</p><p>');
    // Single newline = line break (but not inside ul)
    html = html.replace(/\n/g, '<br>');

    return html;
  }

  function renderSpellDetail(s) {
    const isID = _lang === 'id';
    const school = isID ? tSchool(s.school) : s.school;
    const lvlText = s.level === 0 ? 'Cantrip' : `${isID ? 'Level' : 'Level'} ${s.level}`;
    const classes = (s.classes || []).join(', ');

    let badges = '';
    if (s.concentration) badges += `<span class="spell-concentration-badge">${isID ? 'Konsentrasi' : 'Concentration'}</span>`;
    if (s.ritual) badges += `<span class="spell-ritual-badge">Ritual</span>`;

    return `
      <div class="comp-detail-title">${escapeHtml(s.name)}${badges}</div>
      <div class="comp-detail-subtitle">${lvlText} ${escapeHtml(school)}</div>
      <dl class="spell-detail-props">
        <dt>${isID ? 'Waktu Rapal' : 'Casting Time'}</dt><dd>${escapeHtml(s.castingTime || '—')}</dd>
        <dt>${isID ? 'Jangkauan' : 'Range'}</dt><dd>${escapeHtml(s.range || '—')}</dd>
        <dt>${isID ? 'Komponen' : 'Components'}</dt><dd>${escapeHtml(s.components || '—')}${s.materialDetail ? ` <em>(${escapeHtml(s.materialDetail)})</em>` : ''}</dd>
        <dt>${isID ? 'Durasi' : 'Duration'}</dt><dd>${escapeHtml(s.duration || '—')}</dd>
      </dl>
      <div class="comp-detail-section">
        <h3>${isID ? 'Deskripsi' : 'Description'}</h3>
        <div class="comp-desc-text"><p>${formatDesc(tSpell(s.name, 'description') || s.description)}</p></div>
      </div>
      ${s.higherLevels ? `
        <div class="comp-detail-section">
          <h3>${isID ? 'Pada Level Lebih Tinggi' : 'At Higher Levels'}</h3>
          <div class="comp-desc-text"><p>${formatDesc(tSpell(s.name, 'higherLevels') || s.higherLevels)}</p></div>
        </div>` : ''}
      ${classes ? `<div class="comp-detail-tags">${classes.split(', ').map(c => `<span class="comp-detail-tag">${escapeHtml(c)}</span>`).join('')}</div>` : ''}
    `;
  }

  function renderClassDetail(c) {
    const isID = _lang === 'id';

    // Proficiencies section
    let profHtml = `<div class="comp-detail-section"><h3>${isID ? 'Profisiensi' : 'Proficiencies'}</h3>`;
    if (c.profArmor?.length) profHtml += `<p><strong>${isID ? 'Armor' : 'Armor'}:</strong> ${escapeHtml(c.profArmor.join(', '))}</p>`;
    if (c.profWeapons?.length) profHtml += `<p><strong>${isID ? 'Senjata' : 'Weapons'}:</strong> ${escapeHtml(c.profWeapons.join(', '))}</p>`;
    if (c.profTools?.length) profHtml += `<p><strong>${isID ? 'Alat' : 'Tools'}:</strong> ${escapeHtml(c.profTools.join(', '))}</p>`;
    if (c.profSaves?.length) profHtml += `<p><strong>Saving Throws:</strong> ${escapeHtml(c.profSaves.join(', '))}</p>`;
    if (c.profSkills?.length) profHtml += `<p><strong>${isID ? 'Skill (pilih 2)' : 'Skills (choose 2)'}:</strong> ${escapeHtml(c.profSkills.join(', '))}</p>`;
    profHtml += '</div>';

    // Features by level
    let featHtml = `<div class="comp-detail-section"><h3>${isID ? 'Fitur per Level' : 'Features by Level'}</h3><div class="class-features-list">`;
    const features = c.features || [];
    let currentLevel = -1;
    features.forEach(f => {
      if (f.level !== currentLevel) {
        currentLevel = f.level;
      }
      featHtml += `
        <div class="class-feature-item">
          <div class="feature-header">
            <span class="feature-name">${escapeHtml(f.name)}</span>
            <span class="feature-level">Lvl ${f.level}</span>
          </div>
          <div class="feature-body">${formatDesc(tClassFeature(c.name, f.name) || f.entries)}</div>
        </div>`;
    });
    featHtml += '</div></div>';

    // Subclasses
    let scHtml = '';
    if (c.subclasses && c.subclasses.length > 0) {
      scHtml = `<div class="comp-detail-section"><h3>${isID ? 'Subkelas' : 'Subclasses'} (${c.subclasses.length})</h3>`;
      c.subclasses.forEach(sc => {
        const scFeats = (sc.features || []);
        scHtml += `
          <div class="subclass-group">
            <div class="subclass-group-header">
              <span>${escapeHtml(sc.name)}</span>
              <span style="font-size:0.8rem;color:var(--text-dim)">${scFeats.length} ${isID ? 'fitur' : 'features'} ▾</span>
            </div>
            <div class="subclass-group-body">
              <div class="class-features-list">`;
        scFeats.forEach(f => {
          scHtml += `
                <div class="class-feature-item">
                  <div class="feature-header">
                    <span class="feature-name">${escapeHtml(f.name)}</span>
                    <span class="feature-level">Lvl ${f.level}</span>
                  </div>
                  <div class="feature-body">${formatDesc(tSubclassFeature(sc.name, f.name) || f.entries)}</div>
                </div>`;
        });
        scHtml += '</div></div></div>';
      });
      scHtml += '</div>';
    }

    return `
      <div class="comp-detail-title">${escapeHtml(c.name)}</div>
      <div class="comp-detail-subtitle">${isID ? 'Hit Dice' : 'Hit Dice'}: ${c.hitDice || '?'} · Saving Throws: ${(c.profSaves || []).join(', ')}${c.spellcastingAbility ? ` · ${isID ? 'Sihir' : 'Spellcasting'}: ${c.spellcastingAbility}` : ''}</div>
      ${profHtml}
      ${featHtml}
      ${scHtml}
    `;
  }

  function renderRaceDetail(r) {
    const isID = _lang === 'id';
    return `
      <div class="comp-detail-title">${escapeHtml(r.name)}</div>
      <div class="comp-detail-subtitle">${isID ? 'Kecepatan' : 'Speed'}: ${r.speed || 30} ft · ${isID ? 'Ukuran' : 'Size'}: ${r.size || 'Medium'}${r.darkvision ? ` · Darkvision ${r.darkvision} ft.` : ''}</div>
      ${r.abilityBonuses?.length ? `<div class="comp-detail-section"><h3>${isID ? 'Skor Kemampuan' : 'Ability Scores'}</h3><p>${escapeHtml(r.abilityBonuses.join(', '))}</p></div>` : ''}
      <div class="comp-detail-section">
        <h3>${isID ? 'Sifat' : 'Traits'}</h3>
        <div class="comp-desc-text"><p>${formatDesc(tSpecies(r.name) || r.entries)}</p></div>
      </div>
      ${r.traitTags?.length ? `<div class="comp-detail-tags">${r.traitTags.map(t => `<span class="comp-detail-tag">${escapeHtml(t)}</span>`).join('')}</div>` : ''}
      ${r.subraces?.length ? `<div class="comp-detail-section"><h3>${isID ? 'Subspesies' : 'Subspecies'}</h3>${r.subraces.map(sr => `<p><strong>${escapeHtml(sr.name)}</strong>${sr.entries ? ': ' + escapeHtml(sr.entries.slice(0, 200)) : ''}</p>`).join('')}</div>` : ''}
    `;
  }

  function renderItemDetail(item) {
    const isID = _lang === 'id';
    const costStr = item.value ? `${(item.value / 100).toFixed(item.value % 100 === 0 ? 0 : 2)} gp` : '—';
    const weightStr = item.weight ? `${item.weight} lb` : '—';

    let propsHtml = '';
    if (item.dmg1) propsHtml += `<p><strong>Damage:</strong> ${escapeHtml(item.dmg1)} ${escapeHtml(item.dmgType)}</p>`;
    if (item.ac) propsHtml += `<p><strong>AC:</strong> ${item.ac}</p>`;
    if (item.range) propsHtml += `<p><strong>${isID ? 'Jangkauan' : 'Range'}:</strong> ${escapeHtml(item.range)}</p>`;
    if (item.weaponCategory) propsHtml += `<p><strong>Category:</strong> ${escapeHtml(item.weaponCategory)}</p>`;
    if (item.property?.length) {
      propsHtml += `<p><strong>${isID ? 'Properti' : 'Properties'}:</strong> ${item.property.map(p => `<span class="item-prop-badge">${escapeHtml(typeof p === 'string' ? p : (p.name || JSON.stringify(p)))}</span>`).join(' ')}</p>`;
    }
    if (item.reqAttune) propsHtml += `<p><strong>Attunement:</strong> ${item.reqAttuneText || 'Required'}</p>`;

    return `
      <div class="comp-detail-title">${escapeHtml(item.name)}</div>
      <div class="comp-detail-subtitle">${escapeHtml(item.type || '')} · ${isID ? 'Harga' : 'Cost'}: ${costStr} · ${isID ? 'Berat' : 'Weight'}: ${weightStr}${item.rarity !== 'none' ? ` · ${escapeHtml(item.rarity)}` : ''}</div>
      ${propsHtml ? `<div class="comp-detail-section">${propsHtml}</div>` : ''}
      ${item.entries ? `<div class="comp-detail-section"><h3>${isID ? 'Deskripsi' : 'Description'}</h3><div class="comp-desc-text"><p>${formatDesc(tEquipment(item.name) || item.entries)}</p></div></div>` : ''}
    `;
  }

  function renderFeatDetail(f) {
    const isID = _lang === 'id';
    const prereqs = (f.prerequisites || []).join(', ');
    return `
      <div class="comp-detail-title">${escapeHtml(f.name)}</div>
      <div class="comp-detail-subtitle">${escapeHtml(f.category || 'General')} Feat${prereqs ? ` · ${isID ? 'Prasyarat' : 'Prerequisites'}: ${escapeHtml(prereqs)}` : ''}</div>
      <div class="comp-detail-section">
        <h3>${isID ? 'Deskripsi' : 'Description'}</h3>
        <div class="comp-desc-text"><p>${formatDesc(tFeat(f.name) || f.entries)}</p></div>
      </div>
    `;
  }

  function renderBackgroundDetail(b) {
    const isID = _lang === 'id';
    const skills = (b.skillProficiencies || []).join(', ');
    const tools = (b.toolProficiencies || []).join(', ');
    return `
      <div class="comp-detail-title">${escapeHtml(b.name)}</div>
      <div class="comp-detail-subtitle">${isID ? 'Latar Belakang PHB 2024' : 'PHB 2024 Background'}</div>
      ${skills ? `<div class="comp-detail-section"><p><strong>${isID ? 'Keahlian' : 'Skill Proficiencies'}:</strong> ${escapeHtml(skills)}</p></div>` : ''}
      ${tools ? `<div class="comp-detail-section"><p><strong>${isID ? 'Alat' : 'Tool Proficiencies'}:</strong> ${escapeHtml(tools)}</p></div>` : ''}
      <div class="comp-detail-section">
        <h3>${isID ? 'Deskripsi' : 'Description'}</h3>
        <div class="comp-desc-text"><p>${formatDesc(tBackground(b.name) || b.entries)}</p></div>
      </div>
    `;
  }

  function renderConditionDetail(c) {
    const isID = _lang === 'id';
    return `
      <div class="comp-detail-title">${escapeHtml(c.name)}</div>
      <div class="comp-detail-subtitle">${escapeHtml(c.type || 'Condition')}</div>
      <div class="comp-detail-section">
        <div class="comp-desc-text"><p>${formatDesc(tCondition(c.name) || c.entries)}</p></div>
      </div>
    `;
  }

  function renderGenericDetail(item) {
    return `
      <div class="comp-detail-title">${escapeHtml(item.name || 'Unknown')}</div>
      <div class="comp-detail-section">
        <div class="comp-desc-text"><p>${formatDesc(item.entries || item.description || '')}</p></div>
      </div>
    `;
  }

  // ---- Init / Activate ----
  async function init() {
    await loadTranslations();
    updateLangUI();
    updateAllLabels();

    $$('.comp-cat-btn').forEach(btn => {
      btn.addEventListener('click', () => setCategory(btn.dataset.category));
    });

    $('#compendium-search')?.addEventListener('input', () => {
      clearTimeout(_debounceTimer);
      _debounceTimer = setTimeout(fetchAndRender, 300);
    });

    $('#comp-lang-btn')?.addEventListener('click', toggleLang);

    $('#compendium-detail-close')?.addEventListener('click', () => {
      $('#compendium-detail-overlay')?.classList.add('hidden');
    });
    $('#compendium-detail-overlay')?.addEventListener('click', (e) => {
      if (e.target === e.currentTarget) e.currentTarget.classList.add('hidden');
    });
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') $('#compendium-detail-overlay')?.classList.add('hidden');
    });

    buildFilters('spells');
  }

  function activate() {
    if (!$('#compendium-results')?.children.length || $('#compendium-results')?.querySelector('.compendium-loading')) {
      fetchAndRender();
    }
  }

  return { init, activate };
})();
// ---- Add tab title for Compendium ----
TAB_TITLES['compendium'] = 'PHB 2024 Compendium';

// ---- Add tab title for Arena ----
TAB_TITLES['arena'] = 'Battle Arena';

// ---- Patch init to include new modules ----
const _origInit = init;
init = function() {
  _origInit();
  ThemeToggle.init();
  Compendium.init();
  Arena.init();
};

// ---- Patch enterApp to show Compendium + Arena tabs ----
const _origEnterApp = enterApp;
enterApp = function() {
  _origEnterApp();
  // Compendium is always visible for all roles
  show('#nav-compendium-btn');
  // Show arena for DM
  if (state.isDM) {
    show('#nav-arena-btn');
  } else {
    hide('#nav-arena-btn');
  }
};

// ---- Patch switchTab to activate Arena + Compendium ----
// (merged with chat clearUnread patch above)
const _origSwitchTab2 = switchTab;
switchTab = function(tab) {
  _origSwitchTab2(tab);
  if (tab === 'arena') Arena.activate();
  if (tab === 'compendium') Compendium.activate();
};

// Start
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

})();

/* === D&D 2024 App — Apex Dark + Amber Fantasy Theme === */

:root {
  --bg-base: #0d121b;
  --bg-surface: #0f141f;
  --bg-card: #0f1521;
  --bg-hover: #151c2a;
  --bg-input: #0a0f18;
  --gold: #d4a73a;
  --gold-dim: #b8922e;
  --gold-bright: #fbbf24;
  --red: #EF4444;
  --red-dim: #B91C1C;
  --green: #10B981;
  --green-dim: #059669;
  --blue: #3B82F6;
  --purple: #8B5CF6;
  --text: #c9d1d9;
  --text-dim: #8b949e;
  --text-muted: #6e7681;
  --border: rgba(255,255,255,.08);
  --border-gold: rgba(212, 167, 58, 0.3);
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --radius: 8px;
  --radius-lg: 12px;
  --mobile-header-h: 50px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  background: var(--bg-base);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
  padding-left: 56px;
}

body::before {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background-image: linear-gradient(rgba(255,255,255,.024) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,.024) 1px, transparent 1px);
  background-size: 48px 48px;
}

::selection { background: rgba(212,167,58,.25); color: #fff; }

.cinzel { font-family: 'Cinzel', serif; }

/* === Scrollbar === */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: var(--bg-base); }
::-webkit-scrollbar-thumb { background: rgba(212,167,58,.3); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: rgba(212,167,58,.5); }

/* === Screens === */
.screen { display: none; }
.screen.active { display: flex; }

/* === LOGIN === */
#login-screen {
  min-height: 100vh;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at center, #0f141f 0%, #0d121b 70%);
}

.login-container {
  background: var(--bg-card);
  border: 1px solid var(--border-gold);
